window.KJV1769_STRONG_BOOKS["Judg"] = {"osis":"Judg","book":"사사기","verses":{"1:1":{"text":"Now after the death of Joshua it came to pass, that the children of Israel asked the LORD, saying, Who shall go up for us against the Canaanites first, to fight against them?","words":[["H0310","Now after",0,9],["H4194","the death",10,19],["H3091","of Joshua",20,29],["H1121","it came to pass, that the children",30,64],["H3478","of Israel",65,74],["H7592","asked",75,80],["H3068","the LORD",81,89],["H0559","saying",91,97],["H5927","Who shall go up",99,114],["H3669","for us against the Canaanites",115,144],["H8462","first",145,150],["H3898","to fight",152,160]]},"1:2":{"text":"And the LORD said, Judah shall go up: behold, I have delivered the land into his hand.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H3063","Judah",19,24],["H5927","shall go up",25,36],["H5414","behold, I have delivered",38,62],["H0776","the land",63,71],["H3027","into his hand",72,85]]},"1:3":{"text":"And Judah said unto Simeon his brother, Come up with me into my lot, that we may fight against the Canaanites; and I likewise will go with thee into thy lot. So Simeon went with him.","words":[["H3063","And Judah",0,9],["H0559","said",10,14],["H8095","unto Simeon",15,26],["H0251","his brother",27,38],["H5927","Come up",40,47],["H1486","with me into my lot",48,67],["H3898","that we may fight",69,86],["H3669","against the Canaanites",87,109],["H1980","and I likewise will go",111,133],["H1486","with thee into thy lot",134,156],["H8095","So Simeon",158,167],["H3212","went",168,172]]},"1:4":{"text":"And Judah went up; and the LORD delivered the Canaanites and the Perizzites into their hand: and they slew of them in Bezek ten thousand men.","words":[["H3063","And Judah",0,9],["H5927","went up",10,17],["H3068","and the LORD",19,31],["H5414","delivered",32,41],["H3669","the Canaanites",42,56],["H6522","and the Perizzites",57,75],["H3027","into their hand",76,91],["H5221","and they slew",93,106],["H0966","of them in Bezek",107,123],["H6235","ten",124,127],["H0505","thousand",128,136],["H0376","men",137,140]]},"1:5":{"text":"And they found Adonibezek in Bezek: and they fought against him, and they slew the Canaanites and the Perizzites.","words":[["H4672","And they found",0,14],["H0137","Adonibezek",15,25],["H0966","in Bezek",26,34],["H3898","and they fought",36,51],["H5221","against him, and they slew",52,78],["H3669","the Canaanites",79,93],["H6522","and the Perizzites",94,112]]},"1:6":{"text":"But Adonibezek fled; and they pursued after him, and caught him, and cut off his thumbs and his great toes.","words":[["H0137","But Adonibezek",0,14],["H5127","fled",15,19],["H7291","and they pursued",21,37],["H0310","after",38,43],["H0270","him, and caught",44,59],["H7112","him, and cut off",60,76],["H0931","his thumbs",77,87],["H3027","his thumbs",77,87],["H7272","and his great toes",88,106]]},"1:7":{"text":"And Adonibezek said, Threescore and ten kings, having their thumbs and their great toes cut off, gathered their meat under my table: as I have done, so God hath requited me. And they brought him to Jerusalem, and there he died.","words":[["H0137","And Adonibezek",0,14],["H0559","said",15,19],["H7657","Threescore and ten",21,39],["H4428","kings",40,45],["H0931","having their thumbs",47,66],["H3027","having their thumbs",47,66],["H7272","and their great toes",67,87],["H7112","cut off",88,95],["H3950","gathered",97,105],["H7979","their meat under my table",106,131],["H6213","as I have done",133,147],["H0430","so God",149,155],["H7999","hath requited",156,169],["H0935","me. And they brought",170,190],["H3389","him to Jerusalem",191,207],["H4191","and there he died",209,226]]},"1:8":{"text":"Now the children of Judah had fought against Jerusalem, and had taken it, and smitten it with the edge of the sword, and set the city on fire.","words":[["H1121","Now the children",0,16],["H3063","of Judah",17,25],["H3898","had fought",26,36],["H3389","against Jerusalem",37,54],["H3920","and had taken",56,69],["H5221","it, and smitten",70,85],["H6310","it with the edge",86,102],["H2719","of the sword",103,115],["H7971","and set",117,124],["H5892","the city",125,133],["H0784","on fire",134,141]]},"1:9":{"text":"And afterward the children of Judah went down to fight against the Canaanites, that dwelt in the mountain, and in the south, and in the valley.","words":[["H0310","And afterward",0,13],["H1121","the children",14,26],["H3063","of Judah",27,35],["H3381","went down",36,45],["H3898","to fight",46,54],["H3669","against the Canaanites",55,77],["H3427","that dwelt",79,89],["H2022","in the mountain",90,105],["H5045","and in the south",107,123],["H8219","and in the valley",125,142]]},"1:10":{"text":"And Judah went against the Canaanites that dwelt in Hebron: (now the name of Hebron before was Kirjatharba:) and they slew Sheshai, and Ahiman, and Talmai.","words":[["H3063","And Judah",0,9],["H3212","went",10,14],["H3669","against the Canaanites",15,37],["H3427","that dwelt",38,48],["H2275","in Hebron",49,58],["H8034","(now the name",60,73],["H2275","of Hebron",74,83],["H6440","before",84,90],["H7153","was Kirjatharba",91,106],["H5221",") and they slew",107,122],["H8344","Sheshai",123,130],["H0289","and Ahiman",132,142],["H8526","and Talmai",144,154]]},"1:11":{"text":"And from thence he went against the inhabitants of Debir: and the name of Debir before was Kirjathsepher:","words":[["H3212","And from thence he went",0,23],["H3427","against the inhabitants",24,47],["H1688","of Debir",48,56],["H8034","and the name",58,70],["H1688","of Debir",71,79],["H6440","before",80,86],["H7158","was Kirjathsepher",87,104]]},"1:12":{"text":"And Caleb said, He that smiteth Kirjathsepher, and taketh it, to him will I give Achsah my daughter to wife.","words":[["H3612","And Caleb",0,9],["H0559","said",10,14],["H5221","He that smiteth",16,31],["H7158","Kirjathsepher",32,45],["H3920","and taketh",47,57],["H5414","it, to him will I give",58,80],["H5915","Achsah",81,87],["H1323","my daughter",88,99],["H0802","to wife",100,107]]},"1:13":{"text":"And Othniel the son of Kenaz, Caleb's younger brother, took it: and he gave him Achsah his daughter to wife.","words":[["H6274","And Othniel",0,11],["H1121","the son",12,19],["H7073","of Kenaz",20,28],["H3612","Caleb's",30,37],["H6996","younger",38,45],["H0251","brother",46,53],["H3920","took",55,59],["H5414","it: and he gave",60,75],["H5915","him Achsah",76,86],["H1323","his daughter",87,99],["H0802","to wife",100,107]]},"1:14":{"text":"And it came to pass, when she came to him, that she moved him to ask of her father a field: and she lighted from off her ass; and Caleb said unto her, What wilt thou?","words":[["H0935","And it came to pass, when she came",0,34],["H5496","to him, that she moved",35,57],["H7592","him to ask",58,68],["H0001","of her father",69,82],["H7704","a field",83,90],["H6795","and she lighted",92,107],["H2543","from off her ass",108,124],["H3612","and Caleb",126,135],["H0559","said",136,140]]},"1:15":{"text":"And she said unto him, Give me a blessing: for thou hast given me a south land; give me also springs of water. And Caleb gave her the upper springs and the nether springs.","words":[["H0559","And she said",0,12],["H3051","unto him, Give",13,27],["H1293","me a blessing",28,41],["H5414","for thou hast given",43,62],["H5045","me a south",63,73],["H0776","land",74,78],["H5414","give",80,84],["H1543","me also springs",85,100],["H4325","of water",101,109],["H3612","And Caleb",111,120],["H5414","gave",121,125],["H5942","her the upper",126,139],["H1543","springs",140,147],["H8482","and the nether",148,162],["H1543","springs",163,170]]},"1:16":{"text":"And the children of the Kenite, Moses' father in law, went up out of the city of palm trees with the children of Judah into the wilderness of Judah, which lieth in the south of Arad; and they went and dwelt among the people.","words":[["H1121","And the children",0,16],["H7017","of the Kenite",17,30],["H4872","Moses'",32,38],["H2859","father in law",39,52],["H5927","went up",54,61],["H5892","out of the city",62,77],["H8558","of palm trees",78,91],["H5899","of palm trees",78,91],["H1121","with the children",92,109],["H3063","of Judah",110,118],["H4057","into the wilderness",119,138],["H3063","of Judah",139,147],["H5045","which lieth in the south",149,173],["H6166","of Arad",174,181],["H3212","and they went",183,196],["H3427","and dwelt",197,206],["H0854","among",207,212],["H5971","the people",213,223]]},"1:17":{"text":"And Judah went with Simeon his brother, and they slew the Canaanites that inhabited Zephath, and utterly destroyed it. And the name of the city was called Hormah.","words":[["H3063","And Judah",0,9],["H3212","went",10,14],["H8095","with Simeon",15,26],["H0251","his brother",27,38],["H5221","and they slew",40,53],["H3669","the Canaanites",54,68],["H3427","that inhabited",69,83],["H6857","Zephath",84,91],["H2763","and utterly destroyed",93,114],["H8034","it. And the name",115,131],["H5892","of the city",132,143],["H7121","was called",144,154],["H2767","Hormah",155,161]]},"1:18":{"text":"Also Judah took Gaza with the coast thereof, and Askelon with the coast thereof, and Ekron with the coast thereof.","words":[["H3063","Also Judah",0,10],["H3920","took",11,15],["H5804","Gaza",16,20],["H1366","with the coast",21,35],["H0831","thereof, and Askelon",36,56],["H1366","with the coast",57,71],["H6138","thereof, and Ekron",72,90],["H1366","with the coast",91,105]]},"1:19":{"text":"And the LORD was with Judah; and he drave out the inhabitants of the mountain; but could not drive out the inhabitants of the valley, because they had chariots of iron.","words":[["H3068","And the LORD",0,12],["H3063","was with Judah",13,27],["H3423","and he drave out",29,45],["H2022","the inhabitants of the mountain",46,77],["H3808","but could not",79,92],["H3423","drive out",93,102],["H3427","the inhabitants",103,118],["H6010","of the valley",119,132],["H7393","because they had chariots",134,159],["H1270","of iron",160,167]]},"1:20":{"text":"And they gave Hebron unto Caleb, as Moses said: and he expelled thence the three sons of Anak.","words":[["H5414","And they gave",0,13],["H2275","Hebron",14,20],["H3612","unto Caleb",21,31],["H4872","as Moses",33,41],["H1696","said",42,46],["H3423","and he expelled",48,63],["H7969","thence the three",64,80],["H1121","sons",81,85],["H6061","of Anak",86,93]]},"1:21":{"text":"And the children of Benjamin did not drive out the Jebusites that inhabited Jerusalem; but the Jebusites dwell with the children of Benjamin in Jerusalem unto this day.","words":[["H1121","And the children",0,16],["H1144","of Benjamin",17,28],["H3423","did not drive out",29,46],["H2983","the Jebusites",47,60],["H3427","that inhabited",61,75],["H3389","Jerusalem",76,85],["H2983","but the Jebusites",87,104],["H3427","dwell",105,110],["H1121","with the children",111,128],["H1144","of Benjamin",129,140],["H3389","in Jerusalem",141,153],["H3117","unto this day",154,167]]},"1:22":{"text":"And the house of Joseph, they also went up against Bethel: and the LORD was with them.","words":[["H1004","And the house",0,13],["H3130","of Joseph",14,23],["H5927","they also went up",25,42],["H1008","against Bethel",43,57],["H3068","and the LORD",59,71]]},"1:23":{"text":"And the house of Joseph sent to descry Bethel. (Now the name of the city before was Luz.)","words":[["H1004","And the house",0,13],["H3130","of Joseph",14,23],["H8446","sent to descry",24,38],["H1008","Bethel",39,45],["H8034","(Now the name",47,60],["H5892","of the city",61,72],["H6440","before",73,79],["H3870","was Luz",80,87]]},"1:24":{"text":"And the spies saw a man come forth out of the city, and they said unto him, Shew us, we pray thee, the entrance into the city, and we will shew thee mercy.","words":[["H8104","And the spies",0,13],["H7200","saw",14,17],["H0376","a man",18,23],["H3318","come forth",24,34],["H5892","out of the city",35,50],["H0559","and they said",52,65],["H7200","unto him, Shew",66,80],["H3996","us, we pray thee, the entrance",81,111],["H5892","into the city",112,125],["H6213","and we will shew",127,143],["H2617","thee mercy",144,154]]},"1:25":{"text":"And when he shewed them the entrance into the city, they smote the city with the edge of the sword; but they let go the man and all his family.","words":[["H7200","And when he shewed",0,18],["H3996","them the entrance",19,36],["H5892","into the city",37,50],["H5221","they smote",52,62],["H5892","the city",63,71],["H6310","with the edge",72,85],["H2719","of the sword",86,98],["H7971","but they let go",100,115],["H0376","the man",116,123],["H4940","and all his family",124,142]]},"1:26":{"text":"And the man went into the land of the Hittites, and built a city, and called the name thereof Luz: which is the name thereof unto this day.","words":[["H0376","And the man",0,11],["H3212","went",12,16],["H0776","into the land",17,30],["H2850","of the Hittites",31,46],["H1129","and built",48,57],["H5892","a city",58,64],["H7121","and called",66,76],["H8034","the name",77,85],["H3870","thereof Luz",86,97],["H8034","which is the name",99,116],["H3117","thereof unto this day",117,138]]},"1:27":{"text":"Neither did Manasseh drive out the inhabitants of Bethshean and her towns, nor Taanach and her towns, nor the inhabitants of Dor and her towns, nor the inhabitants of Ibleam and her towns, nor the inhabitants of Megiddo and her towns: but the Canaanites would dwell in that land.","words":[["H4519","Neither did Manasseh",0,20],["H3423","drive out",21,30],["H1052","the inhabitants of Bethshean",31,59],["H1323","and her towns",60,73],["H8590","nor Taanach",75,86],["H1323","and her towns",87,100],["H3427","nor the inhabitants",102,121],["H1756","of Dor",122,128],["H1323","and her towns",129,142],["H3427","nor the inhabitants",144,163],["H2991","of Ibleam",164,173],["H1323","and her towns",174,187],["H3427","nor the inhabitants",189,208],["H4023","of Megiddo",209,219],["H1323","and her towns",220,233],["H3669","but the Canaanites",235,253],["H2974","would",254,259],["H3427","dwell",260,265],["H0776","in that land",266,278]]},"1:28":{"text":"And it came to pass, when Israel was strong, that they put the Canaanites to tribute, and did not utterly drive them out.","words":[["H3478","And it came to pass, when Israel",0,32],["H2388","was strong",33,43],["H7760","that they put",45,58],["H3669","the Canaanites",59,73],["H4522","to tribute",74,84],["H3423","and did not utterly",86,105],["H3423","drive them out",106,120]]},"1:29":{"text":"Neither did Ephraim drive out the Canaanites that dwelt in Gezer; but the Canaanites dwelt in Gezer among them.","words":[["H0669","Neither did Ephraim",0,19],["H3423","drive out",20,29],["H3669","the Canaanites",30,44],["H3427","that dwelt",45,55],["H1507","in Gezer",56,64],["H3669","but the Canaanites",66,84],["H3427","dwelt",85,90],["H1507","in Gezer",91,99],["H7130","among",100,105]]},"1:30":{"text":"Neither did Zebulun drive out the inhabitants of Kitron, nor the inhabitants of Nahalol; but the Canaanites dwelt among them, and became tributaries.","words":[["H2074","Neither did Zebulun",0,19],["H3423","drive out",20,29],["H3427","the inhabitants",30,45],["H7003","of Kitron",46,55],["H3427","nor the inhabitants",57,76],["H5096","of Nahalol",77,87],["H3669","but the Canaanites",89,107],["H3427","dwelt",108,113],["H7130","among",114,119],["H4522","them, and became tributaries",120,148]]},"1:31":{"text":"Neither did Asher drive out the inhabitants of Accho, nor the inhabitants of Zidon, nor of Ahlab, nor of Achzib, nor of Helbah, nor of Aphik, nor of Rehob:","words":[["H0836","Neither did Asher",0,17],["H3423","drive out",18,27],["H3427","the inhabitants",28,43],["H5910","of Accho",44,52],["H3427","nor the inhabitants",54,73],["H6721","of Zidon",74,82],["H0303","nor of Ahlab",84,96],["H0392","nor of Achzib",98,111],["H2462","nor of Helbah",113,126],["H0663","nor of Aphik",128,140],["H7340","nor of Rehob",142,154]]},"1:32":{"text":"But the Asherites dwelt among the Canaanites, the inhabitants of the land: for they did not drive them out.","words":[["H0843","But the Asherites",0,17],["H3427","dwelt",18,23],["H7130","among",24,29],["H3669","the Canaanites",30,44],["H3427","the inhabitants",46,61],["H0776","of the land",62,73],["H3423","for they did not drive them out",75,106]]},"1:33":{"text":"Neither did Naphtali drive out the inhabitants of Bethshemesh, nor the inhabitants of Bethanath; but he dwelt among the Canaanites, the inhabitants of the land: nevertheless the inhabitants of Bethshemesh and of Bethanath became tributaries unto them.","words":[["H5321","Neither did Naphtali",0,20],["H3423","drive out",21,30],["H3427","the inhabitants",31,46],["H1053","of Bethshemesh",47,61],["H3427","nor the inhabitants",63,82],["H1043","of Bethanath",83,95],["H3427","but he dwelt",97,109],["H7130","among",110,115],["H3669","the Canaanites",116,130],["H3427","the inhabitants",132,147],["H0776","of the land",148,159],["H3427","nevertheless the inhabitants",161,189],["H1053","of Bethshemesh",190,204],["H1043","and of Bethanath",205,221],["H4522","became tributaries",222,240]]},"1:34":{"text":"And the Amorites forced the children of Dan into the mountain: for they would not suffer them to come down to the valley:","words":[["H0567","And the Amorites",0,16],["H3905","forced",17,23],["H1121","the children",24,36],["H1835","of Dan",37,43],["H2022","into the mountain",44,61],["H5414","for they would not suffer",63,88],["H3381","them to come down",89,106],["H6010","to the valley",107,120]]},"1:35":{"text":"But the Amorites would dwell in mount Heres in Aijalon, and in Shaalbim: yet the hand of the house of Joseph prevailed, so that they became tributaries.","words":[["H0567","But the Amorites",0,16],["H2974","would",17,22],["H3427","dwell",23,28],["H2022","in mount",29,37],["H2776","Heres",38,43],["H0357","in Aijalon",44,54],["H8169","and in Shaalbim",56,71],["H3027","yet the hand",73,85],["H1004","of the house",86,98],["H3130","of Joseph",99,108],["H3513","prevailed",109,118],["H4522","so that they became tributaries",120,151]]},"1:36":{"text":"And the coast of the Amorites was from the going up to Akrabbim, from the rock, and upward.","words":[["H1366","And the coast",0,13],["H0567","of the Amorites",14,29],["H4608","was from the going up",30,51],["H4610","to Akrabbim",52,63],["H5553","from the rock",65,78],["H4605","and upward",80,90]]},"2:1":{"text":"And an angel of the LORD came up from Gilgal to Bochim, and said, I made you to go up out of Egypt, and have brought you unto the land which I sware unto your fathers; and I said, I will never break my covenant with you.","words":[["H4397","And an angel",0,12],["H3068","of the LORD",13,24],["H5927","came up",25,32],["H1537","from Gilgal",33,44],["H1066","to Bochim",45,54],["H0559","and said",56,64],["H5927","I made you to go up",66,85],["H4714","out of Egypt",86,98],["H0935","and have brought",100,116],["H0776","you unto the land",117,134],["H7650","which I sware",135,148],["H0001","unto your fathers",149,166],["H0559","and I said",168,178],["H5769","I will never",180,192],["H6565","break",193,198],["H1285","my covenant",199,210]]},"2:2":{"text":"And ye shall make no league with the inhabitants of this land; ye shall throw down their altars: but ye have not obeyed my voice: why have ye done this?","words":[["H3772","And ye shall make",0,17],["H1285","no league",18,27],["H3427","with the inhabitants",28,48],["H0776","of this land",49,61],["H5422","ye shall throw down",63,82],["H4196","their altars",83,95],["H8085","but ye have not obeyed",97,119],["H6963","my voice",120,128],["H6213","why have ye done",130,146]]},"2:3":{"text":"Wherefore I also said, I will not drive them out from before you; but they shall be as thorns in your sides, and their gods shall be a snare unto you.","words":[["H0559","Wherefore I also said",0,21],["H1644","I will not drive them out",23,48],["H6440","from before",49,60],["H6654","you; but they shall be as thorns in your sides",61,107],["H0430","and their gods",109,123],["H4170","shall be a snare",124,140]]},"2:4":{"text":"And it came to pass, when the angel of the LORD spake these words unto all the children of Israel, that the people lifted up their voice, and wept.","words":[["H4397","And it came to pass, when the angel",0,35],["H3068","of the LORD",36,47],["H1696","spake",48,53],["H1697","these words",54,65],["H1121","unto all the children",66,87],["H3478","of Israel",88,97],["H5971","that the people",99,114],["H5375","lifted up",115,124],["H6963","their voice",125,136],["H1058","and wept",138,146]]},"2:5":{"text":"And they called the name of that place Bochim: and they sacrificed there unto the LORD.","words":[["H7121","And they called",0,15],["H8034","the name",16,24],["H4725","of that place",25,38],["H1066","Bochim",39,45],["H2076","and they sacrificed",47,66],["H3068","there unto the LORD",67,86]]},"2:6":{"text":"And when Joshua had let the people go, the children of Israel went every man unto his inheritance to possess the land.","words":[["H3091","And when Joshua",0,15],["H5971","had let the people",16,34],["H7971","go",35,37],["H1121","the children",39,51],["H3478","of Israel",52,61],["H3212","went",62,66],["H0376","every man",67,76],["H5159","unto his inheritance",77,97],["H3423","to possess",98,108],["H0776","the land",109,117]]},"2:7":{"text":"And the people served the LORD all the days of Joshua, and all the days of the elders that outlived Joshua, who had seen all the great works of the LORD, that he did for Israel.","words":[["H5971","And the people",0,14],["H5647","served",15,21],["H3068","the LORD",22,30],["H3117","all the days",31,43],["H3091","of Joshua",44,53],["H3117","and all the days",55,71],["H2205","of the elders",72,85],["H0748","that outlived",86,99],["H3117","that outlived",86,99],["H0310","that outlived",86,99],["H3091","Joshua",100,106],["H7200","who had seen",108,120],["H1419","all the great",121,134],["H4639","works",135,140],["H3068","of the LORD",141,152],["H6213","that he did",154,165],["H3478","for Israel",166,176]]},"2:8":{"text":"And Joshua the son of Nun, the servant of the LORD, died, being an hundred and ten years old.","words":[["H3091","And Joshua",0,10],["H1121","the son",11,18],["H5126","of Nun",19,25],["H5650","the servant",27,38],["H3068","of the LORD",39,50],["H4191","died",52,56],["H3967","being an hundred",58,74],["H6235","and ten",75,82],["H8141","years",83,88],["H1121","old",89,92]]},"2:9":{"text":"And they buried him in the border of his inheritance in Timnathheres, in the mount of Ephraim, on the north side of the hill Gaash.","words":[["H6912","And they buried",0,15],["H1366","him in the border",16,33],["H5159","of his inheritance",34,52],["H8556","in Timnathheres",53,68],["H2022","in the mount",70,82],["H0669","of Ephraim",83,93],["H6828","on the north side",95,112],["H2022","of the hill",113,124],["H1608","Gaash",125,130]]},"2:10":{"text":"And also all that generation were gathered unto their fathers: and there arose another generation after them, which knew not the LORD, nor yet the works which he had done for Israel.","words":[["H1755","And also all that generation",0,28],["H0622","were gathered",29,42],["H0001","unto their fathers",43,61],["H6965","and there arose",63,78],["H0312","another",79,86],["H1755","generation",87,97],["H0310","after",98,103],["H3045","them, which knew",104,120],["H3068","not the LORD",121,133],["H4639","nor yet the works",135,152],["H6213","which he had done",153,170],["H3478","for Israel",171,181]]},"2:11":{"text":"And the children of Israel did evil in the sight of the LORD, and served Baalim:","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6213","did",27,30],["H7451","evil",31,35],["H5869","in the sight",36,48],["H3068","of the LORD",49,60],["H5647","and served",62,72],["H1168","Baalim",73,79]]},"2:12":{"text":"And they forsook the LORD God of their fathers, which brought them out of the land of Egypt, and followed other gods, of the gods of the people that were round about them, and bowed themselves unto them, and provoked the LORD to anger.","words":[["H5800","And they forsook",0,16],["H3068","the LORD",17,25],["H0430","God",26,29],["H0001","of their fathers",30,46],["H3318","which brought them out",48,70],["H0776","of the land",71,82],["H4714","of Egypt",83,91],["H3212","and followed",93,105],["H0310","and followed",93,105],["H0312","other",106,111],["H0430","gods",112,116],["H0430","of the gods",118,129],["H5971","of the people",130,143],["H5439","that were round about",144,165],["H7812","them, and bowed",166,181],["H3068","themselves unto them, and provoked the LORD",182,225],["H3707","to anger",226,234]]},"2:13":{"text":"And they forsook the LORD, and served Baal and Ashtaroth.","words":[["H5800","And they forsook",0,16],["H3068","the LORD",17,25],["H5647","and served",27,37],["H1168","Baal",38,42],["H6252","and Ashtaroth",43,56]]},"2:14":{"text":"And the anger of the LORD was hot against Israel, and he delivered them into the hands of spoilers that spoiled them, and he sold them into the hands of their enemies round about, so that they could not any longer stand before their enemies.","words":[["H0639","And the anger",0,13],["H3068","of the LORD",14,25],["H2734","was hot",26,33],["H3478","against Israel",34,48],["H5414","and he delivered",50,66],["H3027","them into the hands",67,86],["H8154","of spoilers",87,98],["H8155","that spoiled",99,111],["H4376","them, and he sold",112,129],["H3027","them into the hands",130,149],["H0341","of their enemies",150,166],["H5439","round about",167,178],["H3201","so that they could",180,198],["H5750","not any longer",199,213],["H5975","stand",214,219],["H6440","before",220,226],["H0341","their enemies",227,240]]},"2:15":{"text":"Whithersoever they went out, the hand of the LORD was against them for evil, as the LORD had said, and as the LORD had sworn unto them: and they were greatly distressed.","words":[["H3318","Whithersoever they went out",0,27],["H3027","the hand",29,37],["H3068","of the LORD",38,49],["H7451","was against them for evil",50,75],["H3068","as the LORD",77,88],["H1696","had said",89,97],["H3068","and as the LORD",99,114],["H7650","had sworn",115,124],["H3966","unto them: and they were greatly",125,157],["H3334","distressed",158,168]]},"2:16":{"text":"Nevertheless the LORD raised up judges, which delivered them out of the hand of those that spoiled them.","words":[["H3068","Nevertheless the LORD",0,21],["H6965","raised up",22,31],["H8199","judges",32,38],["H3467","which delivered",40,55],["H3027","them out of the hand",56,76],["H8154","of those that spoiled",77,98]]},"2:17":{"text":"And yet they would not hearken unto their judges, but they went a whoring after other gods, and bowed themselves unto them: they turned quickly out of the way which their fathers walked in, obeying the commandments of the LORD; but they did not so.","words":[["H8085","And yet they would not hearken",0,30],["H8199","unto their judges",31,48],["H2181","but they went a whoring",50,73],["H0310","after",74,79],["H0312","other",80,85],["H0430","gods",86,90],["H7812","and bowed",92,101],["H5493","themselves unto them: they turned",102,135],["H4118","quickly",136,143],["H1870","out of the way",144,158],["H0001","which their fathers",159,178],["H1980","walked in",179,188],["H8085","obeying",190,197],["H4687","the commandments",198,214],["H3068","of the LORD",215,226],["H6213","but they did",228,240]]},"2:18":{"text":"And when the LORD raised them up judges, then the LORD was with the judge, and delivered them out of the hand of their enemies all the days of the judge: for it repented the LORD because of their groanings by reason of them that oppressed them and vexed them.","words":[["H3068","And when the LORD",0,17],["H6965","raised",18,24],["H8199","them up judges",25,39],["H3068","then the LORD",41,54],["H8199","was with the judge",55,73],["H3467","and delivered",75,88],["H3027","them out of the hand",89,109],["H0341","of their enemies",110,126],["H3117","all the days",127,139],["H8199","of the judge",140,152],["H5162","for it repented",154,169],["H3068","the LORD",170,178],["H6440","because",179,186],["H5009","of their groanings",187,205],["H3905","by reason of them that oppressed",206,238],["H1766","them and vexed",239,253]]},"2:19":{"text":"And it came to pass, when the judge was dead, that they returned, and corrupted themselves more than their fathers, in following other gods to serve them, and to bow down unto them; they ceased not from their own doings, nor from their stubborn way.","words":[["H8199","And it came to pass, when the judge",0,35],["H4194","was dead",36,44],["H7725","that they returned",46,64],["H7843","and corrupted",66,79],["H0001","themselves more than their fathers",80,114],["H3212","in following",116,128],["H0310","in following",116,128],["H0312","other",129,134],["H0430","gods",135,139],["H5647","to serve",140,148],["H7812","them, and to bow down",149,170],["H5307","unto them; they ceased",171,193],["H4611","not from their own doings",194,219],["H7186","nor from their stubborn",221,244],["H1870","way",245,248]]},"2:20":{"text":"And the anger of the LORD was hot against Israel; and he said, Because that this people hath transgressed my covenant which I commanded their fathers, and have not hearkened unto my voice;","words":[["H0639","And the anger",0,13],["H3068","of the LORD",14,25],["H2734","was hot",26,33],["H3478","against Israel",34,48],["H0559","and he said",50,61],["H1471","Because that this people",63,87],["H5674","hath transgressed",88,105],["H1285","my covenant",106,117],["H6680","which I commanded",118,135],["H0001","their fathers",136,149],["H8085","and have not hearkened",151,173],["H6963","unto my voice",174,187]]},"2:21":{"text":"I also will not henceforth drive out any from before them of the nations which Joshua left when he died:","words":[["H3254","I also will not henceforth",0,26],["H3423","drive out",27,36],["H0376","any",37,40],["H6440","from before",41,52],["H1471","them of the nations",53,72],["H3091","which Joshua",73,85],["H5800","left",86,90],["H4191","when he died",91,103]]},"2:22":{"text":"That through them I may prove Israel, whether they will keep the way of the LORD to walk therein, as their fathers did keep it, or not.","words":[["H5254","That through them I may prove",0,29],["H3478","Israel",30,36],["H8104","whether they will keep",38,60],["H1870","the way",61,68],["H3068","of the LORD",69,80],["H3212","to walk",81,88],["H0001","therein, as their fathers",89,114],["H8104","did keep",115,123]]},"2:23":{"text":"Therefore the LORD left those nations, without driving them out hastily; neither delivered he them into the hand of Joshua.","words":[["H3068","Therefore the LORD",0,18],["H3240","left",19,23],["H1471","those nations",24,37],["H1115","without",39,46],["H3423","driving them out",47,63],["H4118","hastily",64,71],["H5414","neither delivered",73,90],["H3027","he them into the hand",91,112],["H3091","of Joshua",113,122]]},"3:1":{"text":"Now these are the nations which the LORD left, to prove Israel by them, even as many of Israel as had not known all the wars of Canaan;","words":[["H1471","Now these are the nations",0,25],["H3068","which the LORD",26,40],["H3240","left",41,45],["H5254","to prove",47,55],["H3478","Israel",56,62],["H3045","by them, even as many of Israel as had not known",63,111],["H4421","all the wars",112,124],["H3667","of Canaan",125,134]]},"3:2":{"text":"Only that the generations of the children of Israel might know, to teach them war, at the least such as before knew nothing thereof;","words":[["H7535","Only that",0,9],["H1755","the generations",10,25],["H1121","of the children",26,41],["H3478","of Israel",42,51],["H3045","might know",52,62],["H3925","to teach",64,72],["H4421","them war",73,81],["H6440","at the least such as before",83,110],["H3045","knew",111,115]]},"3:3":{"text":"Namely, five lords of the Philistines, and all the Canaanites, and the Sidonians, and the Hivites that dwelt in mount Lebanon, from mount Baalhermon unto the entering in of Hamath.","words":[["H2568","Namely, five",0,12],["H5633","lords",13,18],["H6430","of the Philistines",19,37],["H3669","and all the Canaanites",39,61],["H6722","and the Sidonians",63,80],["H2340","and the Hivites",82,97],["H3427","that dwelt",98,108],["H2022","in mount",109,117],["H3844","Lebanon",118,125],["H2022","from mount",127,137],["H1179","Baalhermon",138,148],["H0935","unto the entering in",149,169],["H2574","of Hamath",170,179]]},"3:4":{"text":"And they were to prove Israel by them, to know whether they would hearken unto the commandments of the LORD, which he commanded their fathers by the hand of Moses.","words":[["H5254","And they were to prove",0,22],["H3478","Israel",23,29],["H3045","by them, to know",30,46],["H8085","whether they would hearken",47,73],["H4687","unto the commandments",74,95],["H3068","of the LORD",96,107],["H6680","which he commanded",109,127],["H0001","their fathers",128,141],["H3027","by the hand",142,153],["H4872","of Moses",154,162]]},"3:5":{"text":"And the children of Israel dwelt among the Canaanites, Hittites, and Amorites, and Perizzites, and Hivites, and Jebusites:","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H3427","dwelt",27,32],["H7130","among",33,38],["H3669","the Canaanites",39,53],["H2850","Hittites",55,63],["H0567","and Amorites",65,77],["H6522","and Perizzites",79,93],["H2340","and Hivites",95,106],["H2983","and Jebusites",108,121]]},"3:6":{"text":"And they took their daughters to be their wives, and gave their daughters to their sons, and served their gods.","words":[["H3947","And they took",0,13],["H1323","their daughters",14,29],["H0802","to be their wives",30,47],["H5414","and gave",49,57],["H1323","their daughters",58,73],["H1121","to their sons",74,87],["H5647","and served",89,99],["H0430","their gods",100,110]]},"3:7":{"text":"And the children of Israel did evil in the sight of the LORD, and forgat the LORD their God, and served Baalim and the groves.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6213","did",27,30],["H7451","evil",31,35],["H5869","in the sight",36,48],["H3068","of the LORD",49,60],["H7911","and forgat",62,72],["H3068","the LORD",73,81],["H0430","their God",82,91],["H5647","and served",93,103],["H1168","Baalim",104,110],["H0842","and the groves",111,125]]},"3:8":{"text":"Therefore the anger of the LORD was hot against Israel, and he sold them into the hand of Chushanrishathaim king of Mesopotamia: and the children of Israel served Chushanrishathaim eight years.","words":[["H0639","Therefore the anger",0,19],["H3068","of the LORD",20,31],["H2734","was hot",32,39],["H3478","against Israel",40,54],["H4376","and he sold",56,67],["H3027","them into the hand",68,86],["H3573","of Chushanrishathaim",87,107],["H4428","king",108,112],["H0763","of Mesopotamia",113,127],["H1121","and the children",129,145],["H3478","of Israel",146,155],["H5647","served",156,162],["H3573","Chushanrishathaim",163,180],["H8083","eight",181,186],["H8141","years",187,192]]},"3:9":{"text":"And when the children of Israel cried unto the LORD, the LORD raised up a deliverer to the children of Israel, who delivered them, even Othniel the son of Kenaz, Caleb's younger brother.","words":[["H1121","And when the children",0,21],["H3478","of Israel",22,31],["H2199","cried",32,37],["H3068","unto the LORD",38,51],["H3068","the LORD",53,61],["H6965","raised up",62,71],["H3467","a deliverer",72,83],["H1121","to the children",84,99],["H3478","of Israel",100,109],["H3467","who delivered",111,124],["H6274","them, even Othniel",125,143],["H1121","the son",144,151],["H7073","of Kenaz",152,160],["H3612","Caleb's",162,169],["H6996","younger",170,177],["H0251","brother",178,185]]},"3:10":{"text":"And the Spirit of the LORD came upon him, and he judged Israel, and went out to war: and the LORD delivered Chushanrishathaim king of Mesopotamia into his hand; and his hand prevailed against Chushanrishathaim.","words":[["H7307","And the Spirit",0,14],["H3068","of the LORD",15,26],["H8199","came upon him, and he judged",27,55],["H3478","Israel",56,62],["H3318","and went out",64,76],["H4421","to war",77,83],["H3068","and the LORD",85,97],["H5414","delivered",98,107],["H3573","Chushanrishathaim",108,125],["H4428","king",126,130],["H0763","of Mesopotamia",131,145],["H3027","into his hand",146,159],["H3027","and his hand",161,173],["H5810","prevailed",174,183],["H3573","against Chushanrishathaim",184,209]]},"3:11":{"text":"And the land had rest forty years. And Othniel the son of Kenaz died.","words":[["H0776","And the land",0,12],["H8252","had rest",13,21],["H0705","forty",22,27],["H8141","years",28,33],["H6274","And Othniel",35,46],["H1121","the son",47,54],["H7073","of Kenaz",55,63],["H4191","died",64,68]]},"3:12":{"text":"And the children of Israel did evil again in the sight of the LORD: and the LORD strengthened Eglon the king of Moab against Israel, because they had done evil in the sight of the LORD.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6213","did",27,30],["H7451","evil",31,35],["H3254","again",36,41],["H5869","in the sight",42,54],["H3068","of the LORD",55,66],["H3068","and the LORD",68,80],["H2388","strengthened",81,93],["H5700","Eglon",94,99],["H4428","the king",100,108],["H4124","of Moab",109,116],["H3478","against Israel",117,131],["H6213","because they had done",133,154],["H7451","evil",155,159],["H5869","in the sight",160,172],["H3068","of the LORD",173,184]]},"3:13":{"text":"And he gathered unto him the children of Ammon and Amalek, and went and smote Israel, and possessed the city of palm trees.","words":[["H0622","And he gathered",0,15],["H1121","unto him the children",16,37],["H5983","of Ammon",38,46],["H6002","and Amalek",47,57],["H3212","and went",59,67],["H5221","and smote",68,77],["H3478","Israel",78,84],["H3423","and possessed",86,99],["H5892","the city",100,108],["H8558","of palm trees",109,122],["H5899","of palm trees",109,122]]},"3:14":{"text":"So the children of Israel served Eglon the king of Moab eighteen years.","words":[["H1121","So the children",0,15],["H3478","of Israel",16,25],["H5647","served",26,32],["H5700","Eglon",33,38],["H4428","the king",39,47],["H4124","of Moab",48,55],["H8083","eighteen",56,64],["H6240","eighteen",56,64],["H8141","years",65,70]]},"3:15":{"text":"But when the children of Israel cried unto the LORD, the LORD raised them up a deliverer, Ehud the son of Gera, a Benjamite, a man lefthanded: and by him the children of Israel sent a present unto Eglon the king of Moab.","words":[["H1121","But when the children",0,21],["H3478","of Israel",22,31],["H2199","cried",32,37],["H3068","unto the LORD",38,51],["H3068","the LORD",53,61],["H6965","raised them up",62,76],["H3467","a deliverer",77,88],["H0164","Ehud",90,94],["H1121","the son",95,102],["H1617","of Gera",103,110],["H1145","a Benjamite",112,123],["H0376","a man",125,130],["H0334","lefthanded",131,141],["H3225","lefthanded",131,141],["H3027","and by him",143,153],["H1121","the children",154,166],["H3478","of Israel",167,176],["H7971","sent",177,181],["H4503","a present",182,191],["H5700","unto Eglon",192,202],["H4428","the king",203,211],["H4124","of Moab",212,219]]},"3:16":{"text":"But Ehud made him a dagger which had two edges, of a cubit length; and he did gird it under his raiment upon his right thigh.","words":[["H0164","But Ehud",0,8],["H6213","made",9,13],["H2719","him a dagger",14,26],["H8147","which had two",27,40],["H6366","edges",41,46],["H1574","of a cubit",48,58],["H0753","length",59,65],["H2296","and he did gird",67,82],["H4055","it under his raiment",83,103],["H3225","upon his right",104,118],["H3409","thigh",119,124]]},"3:17":{"text":"And he brought the present unto Eglon king of Moab: and Eglon was a very fat man.","words":[["H7126","And he brought",0,14],["H4503","the present",15,26],["H5700","unto Eglon",27,37],["H4428","king",38,42],["H4124","of Moab",43,50],["H5700","and Eglon",52,61],["H3966","was a very",62,72],["H1277","fat",73,76],["H0376","man",77,80]]},"3:18":{"text":"And when he had made an end to offer the present, he sent away the people that bare the present.","words":[["H3615","And when he had made an end",0,27],["H7126","to offer",28,36],["H4503","the present",37,48],["H7971","he sent away",50,62],["H5971","the people",63,73],["H5375","that bare",74,83],["H4503","the present",84,95]]},"3:19":{"text":"But he himself turned again from the quarries that were by Gilgal, and said, I have a secret errand unto thee, O king: who said, Keep silence. And all that stood by him went out from him.","words":[["H7725","But he himself turned again",0,27],["H6456","from the quarries",28,45],["H1537","that were by Gilgal",46,65],["H0559","and said",67,75],["H5643","I have a secret",77,92],["H1697","errand",93,99],["H4428","unto thee, O king",100,117],["H0559","who said",119,127],["H2013","Keep silence",129,141],["H5975","And all that stood",143,161],["H3318","by him went out",162,177]]},"3:20":{"text":"And Ehud came unto him; and he was sitting in a summer parlour, which he had for himself alone. And Ehud said, I have a message from God unto thee. And he arose out of his seat.","words":[["H0164","And Ehud",0,8],["H0935","came",9,13],["H3427","unto him; and he was sitting",14,42],["H4747","in a summer",43,54],["H5944","parlour",55,62],["H0164","which he had for himself alone. And Ehud",64,104],["H0559","said",105,109],["H1697","I have a message",111,127],["H0430","from God",128,136],["H6965","unto thee. And he arose",137,160],["H3678","out of his seat",161,176]]},"3:21":{"text":"And Ehud put forth his left hand, and took the dagger from his right thigh, and thrust it into his belly:","words":[["H0164","And Ehud",0,8],["H7971","put forth",9,18],["H8040","his left",19,27],["H3027","hand",28,32],["H3947","and took",34,42],["H2719","the dagger",43,53],["H3225","from his right",54,68],["H3409","thigh",69,74],["H8628","and thrust",76,86],["H0990","it into his belly",87,104]]},"3:22":{"text":"And the haft also went in after the blade; and the fat closed upon the blade, so that he could not draw the dagger out of his belly; and the dirt came out.","words":[["H5325","And the haft",0,12],["H0935","also went in",13,25],["H0310","after",26,31],["H3851","the blade",32,41],["H2459","and the fat",43,54],["H5462","closed",55,61],["H1157","upon",62,66],["H3851","the blade",67,76],["H8025","so that he could not draw",78,103],["H2719","the dagger",104,114],["H0990","out of his belly",115,131],["H6574","and the dirt",133,145],["H3318","came out",146,154]]},"3:23":{"text":"Then Ehud went forth through the porch, and shut the doors of the parlour upon him, and locked them.","words":[["H0164","Then Ehud",0,9],["H3318","went forth",10,20],["H4528","through the porch",21,38],["H5462","and shut",40,48],["H1817","the doors",49,58],["H5944","of the parlour",59,73],["H5274","upon him, and locked",74,94]]},"3:24":{"text":"When he was gone out, his servants came; and when they saw that, behold, the doors of the parlour were locked, they said, Surely he covereth his feet in his summer chamber.","words":[["H3318","When he was gone out",0,20],["H5650","his servants",22,34],["H0935","came",35,39],["H7200","and when they saw",41,58],["H1817","that, behold, the doors",59,82],["H5944","of the parlour",83,97],["H5274","were locked",98,109],["H0559","they said",111,120],["H5526","Surely he covereth",122,140],["H7272","his feet",141,149],["H4747","in his summer",150,163],["H2315","chamber",164,171]]},"3:25":{"text":"And they tarried till they were ashamed: and, behold, he opened not the doors of the parlour; therefore they took a key, and opened them: and, behold, their lord was fallen down dead on the earth.","words":[["H2342","And they tarried",0,16],["H0954","till they were ashamed",17,39],["H6605","and, behold, he opened",41,63],["H1817","not the doors",64,77],["H5944","of the parlour",78,92],["H3947","therefore they took",94,113],["H4668","a key",114,119],["H6605","and opened",121,131],["H0113","them: and, behold, their lord",132,161],["H5307","was fallen down",162,177],["H4191","dead",178,182],["H0776","on the earth",183,195]]},"3:26":{"text":"And Ehud escaped while they tarried, and passed beyond the quarries, and escaped unto Seirath.","words":[["H0164","And Ehud",0,8],["H4422","escaped",9,16],["H4102","while they tarried",17,35],["H5674","and passed beyond",37,54],["H6456","the quarries",55,67],["H4422","and escaped",69,80],["H8167","unto Seirath",81,93]]},"3:27":{"text":"And it came to pass, when he was come, that he blew a trumpet in the mountain of Ephraim, and the children of Israel went down with him from the mount, and he before them.","words":[["H0935","And it came to pass, when he was come",0,37],["H8628","that he blew",39,51],["H7782","a trumpet",52,61],["H2022","in the mountain",62,77],["H0669","of Ephraim",78,88],["H1121","and the children",90,106],["H3478","of Israel",107,116],["H3381","went down",117,126],["H2022","with him from the mount",127,150],["H6440","and he before",152,165]]},"3:28":{"text":"And he said unto them, Follow after me: for the LORD hath delivered your enemies the Moabites into your hand. And they went down after him, and took the fords of Jordan toward Moab, and suffered not a man to pass over.","words":[["H0559","And he said",0,11],["H7291","unto them, Follow",12,29],["H0310","after",30,35],["H3068","me: for the LORD",36,52],["H5414","hath delivered",53,67],["H0341","your enemies",68,80],["H4124","the Moabites",81,93],["H3027","into your hand",94,108],["H3381","And they went down",110,128],["H0310","after",129,134],["H3920","him, and took",135,148],["H4569","the fords",149,158],["H3383","of Jordan",159,168],["H4124","toward Moab",169,180],["H5414","and suffered",182,194],["H0376","not a man",195,204],["H5674","to pass over",205,217]]},"3:29":{"text":"And they slew of Moab at that time about ten thousand men, all lusty, and all men of valour; and there escaped not a man.","words":[["H5221","And they slew",0,13],["H4124","of Moab",14,21],["H6256","at that time",22,34],["H6235","about ten",35,44],["H0505","thousand",45,53],["H0376","men",54,57],["H8082","all lusty",59,68],["H0376","and all men",70,81],["H2428","of valour",82,91],["H4422","and there escaped",93,110],["H0376","not a man",111,120]]},"3:30":{"text":"So Moab was subdued that day under the hand of Israel. And the land had rest fourscore years.","words":[["H4124","So Moab",0,7],["H3665","was subdued",8,19],["H3117","that day",20,28],["H3027","under the hand",29,43],["H3478","of Israel",44,53],["H0776","And the land",55,67],["H8252","had rest",68,76],["H8084","fourscore",77,86],["H8141","years",87,92]]},"3:31":{"text":"And after him was Shamgar the son of Anath, which slew of the Philistines six hundred men with an ox goad: and he also delivered Israel.","words":[["H0310","And after",0,9],["H8044","him was Shamgar",10,25],["H1121","the son",26,33],["H6067","of Anath",34,42],["H5221","which slew",44,54],["H6430","of the Philistines",55,73],["H8337","six",74,77],["H3967","hundred",78,85],["H0376","men",86,89],["H1241","with an ox",90,100],["H4451","goad",101,105],["H3467","and he also delivered",107,128],["H3478","Israel",129,135]]},"4:1":{"text":"And the children of Israel again did evil in the sight of the LORD, when Ehud was dead.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H3254","again",27,32],["H6213","did",33,36],["H7451","evil",37,41],["H5869","in the sight",42,54],["H3068","of the LORD",55,66],["H0164","when Ehud",68,77],["H4191","was dead",78,86]]},"4:2":{"text":"And the LORD sold them into the hand of Jabin king of Canaan, that reigned in Hazor; the captain of whose host was Sisera, which dwelt in Harosheth of the Gentiles.","words":[["H3068","And the LORD",0,12],["H4376","sold",13,17],["H3027","them into the hand",18,36],["H2985","of Jabin",37,45],["H4428","king",46,50],["H3667","of Canaan",51,60],["H4427","that reigned",62,74],["H2674","in Hazor",75,83],["H8269","the captain",85,96],["H6635","of whose host",97,110],["H5516","was Sisera",111,121],["H3427","which dwelt",123,134],["H2800","in Harosheth",135,147],["H1471","of the Gentiles",148,163]]},"4:3":{"text":"And the children of Israel cried unto the LORD: for he had nine hundred chariots of iron; and twenty years he mightily oppressed the children of Israel.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6817","cried",27,32],["H3068","unto the LORD",33,46],["H8672","for he had nine",48,63],["H3967","hundred",64,71],["H7393","chariots",72,80],["H1270","of iron",81,88],["H6242","and twenty",90,100],["H8141","years",101,106],["H2394","he mightily",107,118],["H3905","oppressed",119,128],["H1121","the children",129,141],["H3478","of Israel",142,151]]},"4:4":{"text":"And Deborah, a prophetess, the wife of Lapidoth, she judged Israel at that time.","words":[["H1683","And Deborah",0,11],["H5031","a prophetess",13,25],["H0802","the wife",27,35],["H3941","of Lapidoth",36,47],["H8199","she judged",49,59],["H3478","Israel",60,66],["H6256","at that time",67,79]]},"4:5":{"text":"And she dwelt under the palm tree of Deborah between Ramah and Bethel in mount Ephraim: and the children of Israel came up to her for judgment.","words":[["H3427","And she dwelt",0,13],["H8560","under the palm tree",14,33],["H1683","of Deborah",34,44],["H7414","between Ramah",45,58],["H1008","and Bethel",59,69],["H2022","in mount",70,78],["H0669","Ephraim",79,86],["H1121","and the children",88,104],["H3478","of Israel",105,114],["H5927","came up",115,122],["H4941","to her for judgment",123,142]]},"4:6":{"text":"And she sent and called Barak the son of Abinoam out of Kedeshnaphtali, and said unto him, Hath not the LORD God of Israel commanded, saying, Go and draw toward mount Tabor, and take with thee ten thousand men of the children of Naphtali and of the children of Zebulun?","words":[["H7971","And she sent",0,12],["H7121","and called",13,23],["H1301","Barak",24,29],["H1121","the son",30,37],["H0042","of Abinoam",38,48],["H6943","out of Kedeshnaphtali",49,70],["H0559","and said",72,80],["H3068","unto him, Hath not the LORD",81,108],["H0430","God",109,112],["H3478","of Israel",113,122],["H6680","commanded",123,132],["H3212","saying, Go",134,144],["H4900","and draw",145,153],["H2022","toward mount",154,166],["H8396","Tabor",167,172],["H3947","and take",174,182],["H6235","with thee ten",183,196],["H0505","thousand",197,205],["H0376","men",206,209],["H1121","of the children",210,225],["H5321","of Naphtali",226,237],["H1121","and of the children",238,257],["H2074","of Zebulun",258,268]]},"4:7":{"text":"And I will draw unto thee to the river Kishon Sisera, the captain of Jabin's army, with his chariots and his multitude; and I will deliver him into thine hand.","words":[["H4900","And I will draw",0,15],["H5158","unto thee to the river",16,38],["H7028","Kishon",39,45],["H5516","Sisera",46,52],["H8269","the captain",54,65],["H2985","of Jabin's",66,76],["H6635","army",77,81],["H7393","with his chariots",83,100],["H1995","and his multitude",101,118],["H5414","and I will deliver",120,138],["H3027","him into thine hand",139,158]]},"4:8":{"text":"And Barak said unto her, If thou wilt go with me, then I will go: but if thou wilt not go with me, then I will not go.","words":[["H1301","And Barak",0,9],["H0559","said",10,14],["H3212","unto her, If thou wilt go",15,40],["H1980","with me, then I will go",41,64],["H3212","but if thou wilt not go",66,89],["H3212","with me, then I will not go",90,117]]},"4:9":{"text":"And she said, I will surely go with thee: notwithstanding the journey that thou takest shall not be for thine honour; for the LORD shall sell Sisera into the hand of a woman. And Deborah arose, and went with Barak to Kedesh.","words":[["H0559","And she said",0,12],["H1980","I will surely",14,27],["H3212","go",28,30],["H0657","with thee: notwithstanding",31,57],["H1870","the journey",58,69],["H1980","that thou takest",70,86],["H8597","shall not be for thine honour",87,116],["H3068","for the LORD",118,130],["H4376","shall sell",131,141],["H5516","Sisera",142,148],["H3027","into the hand",149,162],["H0802","of a woman",163,173],["H1683","And Deborah",175,186],["H6965","arose",187,192],["H3212","and went",194,202],["H1301","with Barak",203,213],["H6943","to Kedesh",214,223]]},"4:10":{"text":"And Barak called Zebulun and Naphtali to Kedesh; and he went up with ten thousand men at his feet: and Deborah went up with him.","words":[["H1301","And Barak",0,9],["H2199","called",10,16],["H2074","Zebulun",17,24],["H5321","and Naphtali",25,37],["H6943","to Kedesh",38,47],["H5927","and he went up",49,63],["H6235","with ten",64,72],["H0505","thousand",73,81],["H0376","men",82,85],["H7272","at his feet",86,97],["H1683","and Deborah",99,110],["H5927","went up",111,118]]},"4:11":{"text":"Now Heber the Kenite, which was of the children of Hobab the father in law of Moses, had severed himself from the Kenites, and pitched his tent unto the plain of Zaanaim, which is by Kedesh.","words":[["H2268","Now Heber",0,9],["H7017","the Kenite",10,20],["H1121","which was of the children",22,47],["H2246","of Hobab",48,56],["H2859","the father in law",57,74],["H4872","of Moses",75,83],["H6504","had severed",85,96],["H7017","himself from the Kenites",97,121],["H5186","and pitched",123,134],["H0168","his tent",135,143],["H0436","unto the plain",144,158],["H6815","of Zaanaim",159,169],["H6943","which is by Kedesh",171,189]]},"4:12":{"text":"And they shewed Sisera that Barak the son of Abinoam was gone up to mount Tabor.","words":[["H5046","And they shewed",0,15],["H5516","Sisera",16,22],["H1301","that Barak",23,33],["H1121","the son",34,41],["H0042","of Abinoam",42,52],["H5927","was gone up",53,64],["H2022","to mount",65,73],["H8396","Tabor",74,79]]},"4:13":{"text":"And Sisera gathered together all his chariots, even nine hundred chariots of iron, and all the people that were with him, from Harosheth of the Gentiles unto the river of Kishon.","words":[["H5516","And Sisera",0,10],["H2199","gathered together",11,28],["H7393","all his chariots",29,45],["H8672","even nine",47,56],["H3967","hundred",57,64],["H7393","chariots",65,73],["H1270","of iron",74,81],["H5971","and all the people",83,101],["H2800","that were with him, from Harosheth",102,136],["H1471","of the Gentiles",137,152],["H5158","unto the river",153,167],["H7028","of Kishon",168,177]]},"4:14":{"text":"And Deborah said unto Barak, Up; for this is the day in which the LORD hath delivered Sisera into thine hand: is not the LORD gone out before thee? So Barak went down from mount Tabor, and ten thousand men after him.","words":[["H1683","And Deborah",0,11],["H0559","said",12,16],["H1301","unto Barak",17,27],["H6965","Up",29,31],["H3117","for this is the day",33,52],["H3068","in which the LORD",53,70],["H5414","hath delivered",71,85],["H5516","Sisera",86,92],["H3027","into thine hand",93,108],["H3068","is not the LORD",110,125],["H3318","gone out",126,134],["H6440","before",135,141],["H1301","thee? So Barak",142,156],["H3381","went down",157,166],["H2022","from mount",167,177],["H8396","Tabor",178,183],["H6235","and ten",185,192],["H0505","thousand",193,201],["H0376","men",202,205],["H0310","after",206,211]]},"4:15":{"text":"And the LORD discomfited Sisera, and all his chariots, and all his host, with the edge of the sword before Barak; so that Sisera lighted down off his chariot, and fled away on his feet.","words":[["H3068","And the LORD",0,12],["H2000","discomfited",13,24],["H5516","Sisera",25,31],["H7393","and all his chariots",33,53],["H4264","and all his host",55,71],["H6310","with the edge",73,86],["H2719","of the sword",87,99],["H6440","before",100,106],["H1301","Barak",107,112],["H5516","so that Sisera",114,128],["H3381","lighted down",129,141],["H4818","off his chariot",142,157],["H5127","and fled away",159,172],["H7272","on his feet",173,184]]},"4:16":{"text":"But Barak pursued after the chariots, and after the host, unto Harosheth of the Gentiles: and all the host of Sisera fell upon the edge of the sword; and there was not a man left.","words":[["H1301","But Barak",0,9],["H7291","pursued",10,17],["H0310","after",18,23],["H7393","the chariots",24,36],["H4264","and after the host",38,56],["H2800","unto Harosheth",58,72],["H1471","of the Gentiles",73,88],["H4264","and all the host",90,106],["H5516","of Sisera",107,116],["H5307","fell",117,121],["H6310","upon the edge",122,135],["H2719","of the sword",136,148],["H0259","and there was not a man",150,173],["H7604","left",174,178]]},"4:17":{"text":"Howbeit Sisera fled away on his feet to the tent of Jael the wife of Heber the Kenite: for there was peace between Jabin the king of Hazor and the house of Heber the Kenite.","words":[["H5516","Howbeit Sisera",0,14],["H5127","fled away",15,24],["H7272","on his feet",25,36],["H0168","to the tent",37,48],["H3278","of Jael",49,56],["H0802","the wife",57,65],["H2268","of Heber",66,74],["H7017","the Kenite",75,85],["H7965","for there was peace",87,106],["H2985","between Jabin",107,120],["H4428","the king",121,129],["H2674","of Hazor",130,138],["H1004","and the house",139,152],["H2268","of Heber",153,161],["H7017","the Kenite",162,172]]},"4:18":{"text":"And Jael went out to meet Sisera, and said unto him, Turn in, my lord, turn in to me; fear not. And when he had turned in unto her into the tent, she covered him with a mantle.","words":[["H3278","And Jael",0,8],["H3318","went out",9,17],["H7125","to meet",18,25],["H5516","Sisera",26,32],["H0559","and said",34,42],["H5493","unto him, Turn in",43,60],["H0113","my lord",62,69],["H5493","turn in",71,78],["H3372","to me; fear",79,90],["H5493","not. And when he had turned in",91,121],["H0168","unto her into the tent",122,144],["H3680","she covered",146,157],["H8063","him with a mantle",158,175]]},"4:19":{"text":"And he said unto her, Give me, I pray thee, a little water to drink; for I am thirsty. And she opened a bottle of milk, and gave him drink, and covered him.","words":[["H0559","And he said",0,11],["H4592","unto her, Give me, I pray thee, a little",12,52],["H4325","water",53,58],["H8248","to drink",59,67],["H6770","for I am thirsty",69,85],["H6605","And she opened",87,101],["H4997","a bottle",102,110],["H2461","of milk",111,118],["H8248","and gave him drink",120,138],["H3680","and covered",140,151]]},"4:20":{"text":"Again he said unto her, Stand in the door of the tent, and it shall be, when any man doth come and enquire of thee, and say, Is there any man here? that thou shalt say, No.","words":[["H0559","Again he said",0,13],["H5975","unto her, Stand in",14,32],["H6607","the door",33,41],["H0168","of the tent",42,53],["H0376","and it shall be, when any man",55,84],["H0935","doth come",85,94],["H7592","and enquire",95,106],["H0559","of thee, and say",107,123],["H3426","Is there",125,133],["H0376","any man",134,141],["H3426","here",142,146],["H0559","that thou shalt say",148,167]]},"4:21":{"text":"Then Jael Heber's wife took a nail of the tent, and took an hammer in her hand, and went softly unto him, and smote the nail into his temples, and fastened it into the ground: for he was fast asleep and weary. So he died.","words":[["H3278","Then Jael",0,9],["H2268","Heber's",10,17],["H0802","wife",18,22],["H3947","took",23,27],["H3489","a nail",28,34],["H0168","of the tent",35,46],["H7760","and took",48,56],["H4718","an hammer",57,66],["H3027","in her hand",67,78],["H0935","and went",80,88],["H3814","softly",89,95],["H8628","unto him, and smote",96,115],["H3489","the nail",116,124],["H7541","into his temples",125,141],["H6795","and fastened",143,155],["H0776","it into the ground",156,174],["H7290","for he was fast asleep",176,198],["H5774","and weary",199,208],["H4191","So he died",210,220]]},"4:22":{"text":"And, behold, as Barak pursued Sisera, Jael came out to meet him, and said unto him, Come, and I will shew thee the man whom thou seekest. And when he came into her tent, behold, Sisera lay dead, and the nail was in his temples.","words":[["H1301","And, behold, as Barak",0,21],["H7291","pursued",22,29],["H5516","Sisera",30,36],["H3278","Jael",38,42],["H3318","came out",43,51],["H7125","to meet",52,59],["H0559","him, and said",60,73],["H3212","unto him, Come",74,88],["H7200","and I will shew",90,105],["H0376","thee the man",106,118],["H1245","whom thou seekest",119,136],["H0935","And when he came",138,154],["H5516","into her tent, behold, Sisera",155,184],["H5307","lay",185,188],["H4191","dead",189,193],["H3489","and the nail",195,207],["H7541","was in his temples",208,226]]},"4:23":{"text":"So God subdued on that day Jabin the king of Canaan before the children of Israel.","words":[["H0430","So God",0,6],["H3665","subdued",7,14],["H3117","on that day",15,26],["H2985","Jabin",27,32],["H4428","the king",33,41],["H3667","of Canaan",42,51],["H6440","before",52,58],["H1121","the children",59,71],["H3478","of Israel",72,81]]},"4:24":{"text":"And the hand of the children of Israel prospered, and prevailed against Jabin the king of Canaan, until they had destroyed Jabin king of Canaan.","words":[["H3027","And the hand",0,12],["H1121","of the children",13,28],["H3478","of Israel",29,38],["H3212","prospered",39,48],["H1980","prospered",39,48],["H7186","and prevailed",50,63],["H2985","against Jabin",64,77],["H4428","the king",78,86],["H3667","of Canaan",87,96],["H3772","until they had destroyed",98,122],["H2985","Jabin",123,128],["H4428","king",129,133],["H3667","of Canaan",134,143]]},"5:1":{"text":"Then sang Deborah and Barak the son of Abinoam on that day, saying,","words":[["H7891","Then sang",0,9],["H1683","Deborah",10,17],["H1301","and Barak",18,27],["H1121","the son",28,35],["H0042","of Abinoam",36,46],["H3117","on that day",47,58],["H0559","saying",60,66]]},"5:2":{"text":"Praise ye the LORD for the avenging of Israel, when the people willingly offered themselves.","words":[["H1288","Praise",0,6],["H3068","ye the LORD",7,18],["H6544","for the avenging",19,35],["H6546","for the avenging",19,35],["H3478","of Israel",36,45],["H5971","when the people",47,62],["H5068","willingly offered",63,80]]},"5:3":{"text":"Hear, O ye kings; give ear, O ye princes; I, even I, will sing unto the LORD; I will sing praise to the LORD God of Israel.","words":[["H8085","Hear",0,4],["H4428","O ye kings",6,16],["H0238","give ear",18,26],["H7336","O ye princes",28,40],["H7891","I, even I, will sing",42,62],["H3068","unto the LORD",63,76],["H2167","I will sing",78,89],["H3068","praise to the LORD",90,108],["H0430","God",109,112],["H3478","of Israel",113,122]]},"5:4":{"text":"LORD, when thou wentest out of Seir, when thou marchedst out of the field of Edom, the earth trembled, and the heavens dropped, the clouds also dropped water.","words":[["H3068","LORD",0,4],["H3318","when thou wentest out",6,27],["H8165","of Seir",28,35],["H6805","when thou marchedst out",37,60],["H7704","of the field",61,73],["H0123","of Edom",74,81],["H0776","the earth",83,92],["H7493","trembled",93,101],["H8064","and the heavens",103,118],["H5197","dropped",119,126],["H5645","the clouds",128,138],["H5197","also dropped",139,151],["H4325","water",152,157]]},"5:5":{"text":"The mountains melted from before the LORD, even that Sinai from before the LORD God of Israel.","words":[["H2022","The mountains",0,13],["H5140","melted",14,20],["H6440","from before",21,32],["H3068","the LORD",33,41],["H5514","even that Sinai",43,58],["H6440","from before",59,70],["H3068","the LORD",71,79],["H0430","God",80,83],["H3478","of Israel",84,93]]},"5:6":{"text":"In the days of Shamgar the son of Anath, in the days of Jael, the highways were unoccupied, and the travellers walked through byways.","words":[["H3117","In the days",0,11],["H8044","of Shamgar",12,22],["H1121","the son",23,30],["H6067","of Anath",31,39],["H3117","in the days",41,52],["H3278","of Jael",53,60],["H0734","the highways",62,74],["H2308","were unoccupied",75,90],["H1980","and the travellers",92,110],["H3212","walked",111,117],["H6128","through byways",118,132],["H5410","through byways",118,132]]},"5:7":{"text":"The inhabitants of the villages ceased, they ceased in Israel, until that I Deborah arose, that I arose a mother in Israel.","words":[["H6520","The inhabitants of the villages",0,31],["H2308","ceased",32,38],["H2308","they ceased",40,51],["H3478","in Israel",52,61],["H1683","until that I Deborah",63,83],["H6965","arose",84,89],["H6965","that I arose",91,103],["H0517","a mother",104,112],["H3478","in Israel",113,122]]},"5:8":{"text":"They chose new gods; then was war in the gates: was there a shield or spear seen among forty thousand in Israel?","words":[["H0977","They chose",0,10],["H2319","new",11,14],["H0430","gods",15,19],["H3901","then was war",21,33],["H8179","in the gates",34,46],["H4043","was there a shield",48,66],["H7420","or spear",67,75],["H7200","seen",76,80],["H0705","among forty",81,92],["H0505","thousand",93,101],["H3478","in Israel",102,111]]},"5:9":{"text":"My heart is toward the governors of Israel, that offered themselves willingly among the people. Bless ye the LORD.","words":[["H3820","My heart",0,8],["H2710","is toward the governors",9,32],["H3478","of Israel",33,42],["H5068","that offered themselves willingly",44,77],["H5971","among the people",78,94],["H1288","Bless",96,101],["H3068","ye the LORD",102,113]]},"5:10":{"text":"Speak, ye that ride on white asses, ye that sit in judgment, and walk by the way.","words":[["H7878","Speak",0,5],["H7392","ye that ride",7,19],["H6715","on white",20,28],["H0860","asses",29,34],["H3427","ye that sit",36,47],["H4055","in judgment",48,59],["H1980","and walk",61,69],["H1870","by the way",70,80]]},"5:11":{"text":"They that are delivered from the noise of archers in the places of drawing water, there shall they rehearse the righteous acts of the LORD, even the righteous acts toward the inhabitants of his villages in Israel: then shall the people of the LORD go down to the gates.","words":[["H6963","They that are delivered from the noise",0,38],["H2686","of archers",39,49],["H4857","in the places of drawing water",50,80],["H8567","there shall they rehearse",82,107],["H6666","the righteous acts",108,126],["H3068","of the LORD",127,138],["H6666","even the righteous acts",140,163],["H6520","toward the inhabitants of his villages",164,202],["H3478","in Israel",203,212],["H5971","then shall the people",214,235],["H3068","of the LORD",236,247],["H3381","go down",248,255],["H8179","to the gates",256,268]]},"5:12":{"text":"Awake, awake, Deborah: awake, awake, utter a song: arise, Barak, and lead thy captivity captive, thou son of Abinoam.","words":[["H5782","Awake",0,5],["H5782","awake",7,12],["H1683","Deborah",14,21],["H5782","awake",23,28],["H5782","awake",30,35],["H1696","utter",37,42],["H7892","a song",43,49],["H6965","arise",51,56],["H1301","Barak",58,63],["H7628","and lead thy captivity",65,87],["H7617","captive",88,95],["H1121","thou son",97,105],["H0042","of Abinoam",106,116]]},"5:13":{"text":"Then he made him that remaineth have dominion over the nobles among the people: the LORD made me have dominion over the mighty.","words":[["H8300","Then he made him that remaineth",0,31],["H7287","have dominion",32,45],["H0117","over the nobles",46,61],["H5971","among the people",62,78],["H3068","the LORD",80,88],["H7287","made me have dominion",89,110],["H1368","over the mighty",111,126]]},"5:14":{"text":"Out of Ephraim was there a root of them against Amalek; after thee, Benjamin, among thy people; out of Machir came down governors, and out of Zebulun they that handle the pen of the writer.","words":[["H0669","Out of Ephraim",0,14],["H8328","was there a root",15,31],["H6002","of them against Amalek",32,54],["H0310","after",56,61],["H1144","thee, Benjamin",62,76],["H5971","among thy people",78,94],["H4353","out of Machir",96,109],["H3381","came down",110,119],["H2710","governors",120,129],["H2074","and out of Zebulun",131,149],["H4900","they that handle",150,166],["H7626","the pen",167,174],["H5608","of the writer",175,188]]},"5:15":{"text":"And the princes of Issachar were with Deborah; even Issachar, and also Barak: he was sent on foot into the valley. For the divisions of Reuben there were great thoughts of heart.","words":[["H8269","And the princes",0,15],["H3485","of Issachar",16,27],["H1683","were with Deborah",28,45],["H3485","even Issachar",47,60],["H1301","and also Barak",62,76],["H7971","he was sent",78,89],["H7272","on foot",90,97],["H6010","into the valley",98,113],["H6390","For the divisions",115,132],["H7205","of Reuben",133,142],["H1419","there were great",143,159],["H2711","thoughts",160,168],["H3820","of heart",169,177]]},"5:16":{"text":"Why abodest thou among the sheepfolds, to hear the bleatings of the flocks? For the divisions of Reuben there were great searchings of heart.","words":[["H3427","Why abodest",0,11],["H0996","thou among",12,22],["H4942","the sheepfolds",23,37],["H8085","to hear",39,46],["H8292","the bleatings",47,60],["H5739","of the flocks",61,74],["H6390","For the divisions",76,93],["H7205","of Reuben",94,103],["H1419","there were great",104,120],["H2714","searchings",121,131],["H3820","of heart",132,140]]},"5:17":{"text":"Gilead abode beyond Jordan: and why did Dan remain in ships? Asher continued on the sea shore, and abode in his breaches.","words":[["H1568","Gilead",0,6],["H7931","abode",7,12],["H5676","beyond",13,19],["H3383","Jordan",20,26],["H1835","and why did Dan",28,43],["H1481","remain",44,50],["H0591","in ships",51,59],["H0836","Asher",61,66],["H3427","continued",67,76],["H3220","on the sea",77,87],["H2348","shore",88,93],["H7931","and abode",95,104],["H4664","in his breaches",105,120]]},"5:18":{"text":"Zebulun and Naphtali were a people that jeoparded their lives unto the death in the high places of the field.","words":[["H2074","Zebulun",0,7],["H5321","and Naphtali",8,20],["H5971","were a people",21,34],["H2778","that jeoparded",35,49],["H5315","their lives",50,61],["H4191","unto the death",62,76],["H4791","in the high places",77,95],["H7704","of the field",96,108]]},"5:19":{"text":"The kings came and fought, then fought the kings of Canaan in Taanach by the waters of Megiddo; they took no gain of money.","words":[["H4428","The kings",0,9],["H0935","came",10,14],["H3898","and fought",15,25],["H3898","then fought",27,38],["H4428","the kings",39,48],["H3667","of Canaan",49,58],["H8590","in Taanach",59,69],["H4325","by the waters",70,83],["H4023","of Megiddo",84,94],["H3947","they took",96,105],["H1215","no gain",106,113],["H3701","of money",114,122]]},"5:20":{"text":"They fought from heaven; the stars in their courses fought against Sisera.","words":[["H3898","They fought",0,11],["H8064","from heaven",12,23],["H3556","the stars",25,34],["H4546","in their courses",35,51],["H3898","fought",52,58],["H5516","against Sisera",59,73]]},"5:21":{"text":"The river of Kishon swept them away, that ancient river, the river Kishon. O my soul, thou hast trodden down strength.","words":[["H5158","The river",0,9],["H7028","of Kishon",10,19],["H1640","swept them away",20,35],["H6917","that ancient",37,49],["H5158","river",50,55],["H5158","the river",57,66],["H7028","Kishon",67,73],["H5315","O my soul",75,84],["H1869","thou hast trodden down",86,108],["H5797","strength",109,117]]},"5:22":{"text":"Then were the horsehoofs broken by the means of the pransings, the pransings of their mighty ones.","words":[["H6119","Then were the horsehoofs",0,24],["H5483","Then were the horsehoofs",0,24],["H1986","broken",25,31],["H1726","by the means of the pransings",32,61],["H1726","the pransings",63,76],["H0047","of their mighty ones",77,97]]},"5:23":{"text":"Curse ye Meroz, said the angel of the LORD, curse ye bitterly the inhabitants thereof; because they came not to the help of the LORD, to the help of the LORD against the mighty.","words":[["H0779","Curse",0,5],["H4789","ye Meroz",6,14],["H0559","said",16,20],["H4397","the angel",21,30],["H3068","of the LORD",31,42],["H0779","curse",44,49],["H0779","ye bitterly",50,61],["H3427","the inhabitants",62,77],["H0935","thereof; because they came",78,104],["H5833","not to the help",105,120],["H3068","of the LORD",121,132],["H5833","to the help",134,145],["H3068","of the LORD",146,157],["H1368","against the mighty",158,176]]},"5:24":{"text":"Blessed above women shall Jael the wife of Heber the Kenite be, blessed shall she be above women in the tent.","words":[["H1288","Blessed",0,7],["H0802","above women",8,19],["H3278","shall Jael",20,30],["H0802","the wife",31,39],["H2268","of Heber",40,48],["H7017","the Kenite",49,59],["H1288","be, blessed",60,71],["H0802","shall she be above women",72,96],["H0168","in the tent",97,108]]},"5:25":{"text":"He asked water, and she gave him milk; she brought forth butter in a lordly dish.","words":[["H7592","He asked",0,8],["H4325","water",9,14],["H5414","and she gave",16,28],["H2461","him milk",29,37],["H7126","she brought forth",39,56],["H2529","butter",57,63],["H0117","in a lordly",64,75],["H5602","dish",76,80]]},"5:26":{"text":"She put her hand to the nail, and her right hand to the workmen's hammer; and with the hammer she smote Sisera, she smote off his head, when she had pierced and stricken through his temples.","words":[["H7971","She put",0,7],["H3027","her hand",8,16],["H3489","to the nail",17,28],["H3225","and her right hand",30,48],["H6001","to the workmen's",49,65],["H1989","hammer",66,72],["H1986","and with the hammer she smote",74,103],["H5516","Sisera",104,110],["H4277","she smote off",112,125],["H7218","his head",126,134],["H4272","when she had pierced",136,156],["H2498","and stricken through",157,177],["H7541","his temples",178,189]]},"5:27":{"text":"At her feet he bowed, he fell, he lay down: at her feet he bowed, he fell: where he bowed, there he fell down dead.","words":[["H7272","At her feet",0,11],["H3766","he bowed",12,20],["H5307","he fell",22,29],["H7901","he lay down",31,42],["H7272","at her feet",44,55],["H3766","he bowed",56,64],["H5307","he fell",66,73],["H0834","where",75,80],["H3766","he bowed",81,89],["H5307","there he fell down",91,109],["H7703","dead",110,114]]},"5:28":{"text":"The mother of Sisera looked out at a window, and cried through the lattice, Why is his chariot so long in coming? why tarry the wheels of his chariots?","words":[["H0517","The mother",0,10],["H5516","of Sisera",11,20],["H8259","looked",21,27],["H2474","out at a window",28,43],["H2980","and cried",45,54],["H0822","through the lattice",55,74],["H7393","Why is his chariot",76,94],["H0954","so long",95,102],["H0935","in coming",103,112],["H0309","why tarry",114,123],["H6471","the wheels",124,134],["H4818","of his chariots",135,150]]},"5:29":{"text":"Her wise ladies answered her, yea, she returned answer to herself,","words":[["H2450","Her wise",0,8],["H8282","ladies",9,15],["H6030","answered",16,24],["H7725","her, yea, she returned",25,47],["H0561","answer",48,54]]},"5:30":{"text":"Have they not sped? have they not divided the prey; to every man a damsel or two; to Sisera a prey of divers colours, a prey of divers colours of needlework, of divers colours of needlework on both sides, meet for the necks of them that take the spoil?","words":[["H4672","Have they not sped",0,18],["H2505","have they not divided",20,41],["H7998","the prey",42,50],["H7218","to every",52,60],["H1397","man",61,64],["H7356","a damsel",65,73],["H7361","or two",74,80],["H5516","to Sisera",82,91],["H7998","a prey",92,98],["H6648","of divers colours",99,116],["H7998","a prey",118,124],["H6648","of divers colours",125,142],["H7553","of needlework",143,156],["H6648","of divers colours",158,175],["H7553","of needlework on both sides",176,203],["H6677","meet for the necks",205,223],["H7998","of them that take the spoil",224,251]]},"5:31":{"text":"So let all thine enemies perish, O LORD: but let them that love him be as the sun when he goeth forth in his might. And the land had rest forty years.","words":[["H0341","So let all thine enemies",0,24],["H0006","perish",25,31],["H3068","O LORD",33,39],["H0157","but let them that love",41,63],["H8121","him be as the sun",64,81],["H3318","when he goeth forth",82,101],["H1369","in his might",102,114],["H0776","And the land",116,128],["H8252","had rest",129,137],["H0705","forty",138,143],["H8141","years",144,149]]},"6:1":{"text":"And the children of Israel did evil in the sight of the LORD: and the LORD delivered them into the hand of Midian seven years.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6213","did",27,30],["H7451","evil",31,35],["H5869","in the sight",36,48],["H3068","of the LORD",49,60],["H3068","and the LORD",62,74],["H5414","delivered",75,84],["H3027","them into the hand",85,103],["H4080","of Midian",104,113],["H7651","seven",114,119],["H8141","years",120,125]]},"6:2":{"text":"And the hand of Midian prevailed against Israel: and because of the Midianites the children of Israel made them the dens which are in the mountains, and caves, and strong holds.","words":[["H3027","And the hand",0,12],["H4080","of Midian",13,22],["H5810","prevailed",23,32],["H3478","against Israel",33,47],["H6440","and because",49,60],["H4080","of the Midianites",61,78],["H1121","the children",79,91],["H3478","of Israel",92,101],["H6213","made",102,106],["H4492","them the dens",107,120],["H2022","which are in the mountains",121,147],["H4631","and caves",149,158],["H4679","and strong holds",160,176]]},"6:3":{"text":"And so it was, when Israel had sown, that the Midianites came up, and the Amalekites, and the children of the east, even they came up against them;","words":[["H3478","And so it was, when Israel",0,26],["H2232","had sown",27,35],["H4080","that the Midianites",37,56],["H5927","came up",57,64],["H6002","and the Amalekites",66,84],["H1121","and the children",86,102],["H6924","of the east",103,114],["H5927","even they came up",116,133]]},"6:4":{"text":"And they encamped against them, and destroyed the increase of the earth, till thou come unto Gaza, and left no sustenance for Israel, neither sheep, nor ox, nor ass.","words":[["H2583","And they encamped",0,17],["H7843","against them, and destroyed",18,45],["H2981","the increase",46,58],["H0776","of the earth",59,71],["H0935","till thou come",73,87],["H5804","unto Gaza",88,97],["H7604","and left",99,107],["H4241","no sustenance",108,121],["H3478","for Israel",122,132],["H7716","neither sheep",134,147],["H7794","nor ox",149,155],["H2543","nor ass",157,164]]},"6:5":{"text":"For they came up with their cattle and their tents, and they came as grasshoppers for multitude; for both they and their camels were without number: and they entered into the land to destroy it.","words":[["H5927","For they came up",0,16],["H4735","with their cattle",17,34],["H0168","and their tents",35,50],["H0935","and they came",52,65],["H0935","and they came",52,65],["H1767","as",66,68],["H0697","grasshoppers",69,81],["H7230","for multitude",82,95],["H1581","for both they and their camels",97,127],["H4557","were without number",128,147],["H0935","and they entered",149,165],["H0776","into the land",166,179],["H7843","to destroy",180,190]]},"6:6":{"text":"And Israel was greatly impoverished because of the Midianites; and the children of Israel cried unto the LORD.","words":[["H3478","And Israel",0,10],["H3966","was greatly",11,22],["H1809","impoverished",23,35],["H6440","because",36,43],["H4080","of the Midianites",44,61],["H1121","and the children",63,79],["H3478","of Israel",80,89],["H2199","cried",90,95],["H3068","unto the LORD",96,109]]},"6:7":{"text":"And it came to pass, when the children of Israel cried unto the LORD because of the Midianites,","words":[["H1121","And it came to pass, when the children",0,38],["H3478","of Israel",39,48],["H2199","cried",49,54],["H3068","unto the LORD",55,68],["H0182","because",69,76],["H4080","of the Midianites",77,94]]},"6:8":{"text":"That the LORD sent a prophet unto the children of Israel, which said unto them, Thus saith the LORD God of Israel, I brought you up from Egypt, and brought you forth out of the house of bondage;","words":[["H3068","That the LORD",0,13],["H7971","sent",14,18],["H0376","a prophet",19,28],["H5030","a prophet",19,28],["H1121","unto the children",29,46],["H3478","of Israel",47,56],["H0559","which said",58,68],["H0559","unto them, Thus saith",69,90],["H3068","the LORD",91,99],["H0430","God",100,103],["H3478","of Israel",104,113],["H5927","I brought you up",115,131],["H4714","from Egypt",132,142],["H3318","and brought you forth",144,165],["H1004","out of the house",166,182],["H5650","of bondage",183,193]]},"6:9":{"text":"And I delivered you out of the hand of the Egyptians, and out of the hand of all that oppressed you, and drave them out from before you, and gave you their land;","words":[["H5337","And I delivered",0,15],["H3027","you out of the hand",16,35],["H4714","of the Egyptians",36,52],["H3027","and out of the hand",54,73],["H3905","of all that oppressed",74,95],["H1644","you, and drave them out",96,119],["H6440","from before",120,131],["H5414","you, and gave",132,145],["H0776","you their land",146,160]]},"6:10":{"text":"And I said unto you, I am the LORD your God; fear not the gods of the Amorites, in whose land ye dwell: but ye have not obeyed my voice.","words":[["H0559","And I said",0,10],["H3068","unto you, I am the LORD",11,34],["H0430","your God",35,43],["H3372","fear",45,49],["H0430","not the gods",50,62],["H0567","of the Amorites",63,78],["H0776","in whose land",80,93],["H3427","ye dwell",94,102],["H8085","but ye have not obeyed",104,126],["H6963","my voice",127,135]]},"6:11":{"text":"And there came an angel of the LORD, and sat under an oak which was in Ophrah, that pertained unto Joash the Abiezrite: and his son Gideon threshed wheat by the winepress, to hide it from the Midianites.","words":[["H0935","And there came",0,14],["H4397","an angel",15,23],["H3068","of the LORD",24,35],["H3427","and sat",37,44],["H0424","under an oak",45,57],["H6084","which was in Ophrah",58,77],["H3101","that pertained unto Joash",79,104],["H0033","the Abiezrite",105,118],["H1121","and his son",120,131],["H1439","Gideon",132,138],["H2251","threshed",139,147],["H2406","wheat",148,153],["H1660","by the winepress",154,170],["H5127","to hide",172,179],["H6440","it from",180,187],["H4080","the Midianites",188,202]]},"6:12":{"text":"And the angel of the LORD appeared unto him, and said unto him, The LORD is with thee, thou mighty man of valour.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H7200","appeared",26,34],["H0559","unto him, and said",35,53],["H3068","unto him, The LORD",54,72],["H1368","is with thee, thou mighty",73,98],["H2428","man of valour",99,112]]},"6:13":{"text":"And Gideon said unto him, Oh my Lord, if the LORD be with us, why then is all this befallen us? and where be all his miracles which our fathers told us of, saying, Did not the LORD bring us up from Egypt? but now the LORD hath forsaken us, and delivered us into the hands of the Midianites.","words":[["H1439","And Gideon",0,10],["H0559","said",11,15],["H0994","unto him, Oh",16,28],["H0113","my Lord",29,36],["H3426","if",38,40],["H3068","the LORD",41,49],["H4672","be with us, why then is all this befallen",50,91],["H6381","us? and where be all his miracles",92,125],["H0001","which our fathers",126,143],["H5608","told",144,148],["H0559","us of, saying",149,162],["H3068","Did not the LORD",164,180],["H5927","bring us up",181,192],["H4714","from Egypt",193,203],["H3068","but now the LORD",205,221],["H5203","hath forsaken",222,235],["H5414","us, and delivered",236,253],["H3709","us into the hands",254,271],["H4080","of the Midianites",272,289]]},"6:14":{"text":"And the LORD looked upon him, and said, Go in this thy might, and thou shalt save Israel from the hand of the Midianites: have not I sent thee?","words":[["H3068","And the LORD",0,12],["H6437","looked",13,19],["H0559","upon him, and said",20,38],["H3212","Go",40,42],["H3581","in this thy might",43,60],["H3467","and thou shalt save",62,81],["H3478","Israel",82,88],["H3709","from the hand",89,102],["H4080","of the Midianites",103,120],["H7971","have not I sent",122,137]]},"6:15":{"text":"And he said unto him, Oh my Lord, wherewith shall I save Israel? behold, my family is poor in Manasseh, and I am the least in my father's house.","words":[["H0559","And he said",0,11],["H0994","unto him, Oh",12,24],["H0136","my Lord",25,32],["H4100","wherewith",34,43],["H3467","shall I save",44,56],["H3478","Israel",57,63],["H0504","behold, my family",65,82],["H0505","behold, my family",65,82],["H1800","is poor",83,90],["H4519","in Manasseh",91,102],["H6810","and I am the least",104,122],["H0001","in my father's",123,137],["H1004","house",138,143]]},"6:16":{"text":"And the LORD said unto him, Surely I will be with thee, and thou shalt smite the Midianites as one man.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H5221","unto him, Surely I will be with thee, and thou shalt smite",18,76],["H4080","the Midianites",77,91],["H0259","as one",92,98],["H0376","man",99,102]]},"6:17":{"text":"And he said unto him, If now I have found grace in thy sight, then shew me a sign that thou talkest with me.","words":[["H0559","And he said",0,11],["H4672","unto him, If now I have found",12,41],["H2580","grace",42,47],["H5869","in thy sight",48,60],["H6213","then shew",62,71],["H0226","me a sign",72,81],["H1696","that thou talkest",82,99]]},"6:18":{"text":"Depart not hence, I pray thee, until I come unto thee, and bring forth my present, and set it before thee. And he said, I will tarry until thou come again.","words":[["H4185","Depart",0,6],["H0935","not hence, I pray thee, until I come",7,43],["H3318","unto thee, and bring forth",44,70],["H4503","my present",71,81],["H3240","and set",83,90],["H6440","it before",91,100],["H0559","thee. And he said",101,118],["H3427","I will tarry",120,132],["H7725","until thou come again",133,154]]},"6:19":{"text":"And Gideon went in, and made ready a kid, and unleavened cakes of an ephah of flour: the flesh he put in a basket, and he put the broth in a pot, and brought it out unto him under the oak, and presented it.","words":[["H1439","And Gideon",0,10],["H0935","went in",11,18],["H6213","and made ready",20,34],["H5795","a kid",35,40],["H1423","a kid",35,40],["H4682","and unleavened cakes",42,62],["H0374","of an ephah",63,74],["H7058","of flour",75,83],["H1320","the flesh",85,94],["H7760","he put",95,101],["H5536","in a basket",102,113],["H7760","and he put",115,125],["H4839","the broth",126,135],["H6517","in a pot",136,144],["H3318","and brought it out",146,164],["H0424","unto him under the oak",165,187],["H5066","and presented",189,202]]},"6:20":{"text":"And the angel of God said unto him, Take the flesh and the unleavened cakes, and lay them upon this rock, and pour out the broth. And he did so.","words":[["H4397","And the angel",0,13],["H0430","of God",14,20],["H0559","said",21,25],["H3947","unto him, Take",26,40],["H1320","the flesh",41,50],["H4682","and the unleavened cakes",51,75],["H3240","and lay",77,84],["H1975","them upon this",85,99],["H5553","rock",100,104],["H8210","and pour out",106,118],["H4839","the broth",119,128],["H6213","And he did",130,140]]},"6:21":{"text":"Then the angel of the LORD put forth the end of the staff that was in his hand, and touched the flesh and the unleavened cakes; and there rose up fire out of the rock, and consumed the flesh and the unleavened cakes. Then the angel of the LORD departed out of his sight.","words":[["H4397","Then the angel",0,14],["H3068","of the LORD",15,26],["H7971","put forth",27,36],["H7097","the end",37,44],["H4938","of the staff",45,57],["H3027","that was in his hand",58,78],["H5060","and touched",80,91],["H1320","the flesh",92,101],["H4682","and the unleavened cakes",102,126],["H5927","and there rose up",128,145],["H0784","fire",146,150],["H6697","out of the rock",151,166],["H0398","and consumed",168,180],["H1320","the flesh",181,190],["H4682","and the unleavened cakes",191,215],["H4397","Then the angel",217,231],["H3068","of the LORD",232,243],["H1980","departed",244,252],["H5869","out of his sight",253,269]]},"6:22":{"text":"And when Gideon perceived that he was an angel of the LORD, Gideon said, Alas, O Lord GOD! for because I have seen an angel of the LORD face to face.","words":[["H1439","And when Gideon",0,15],["H7200","perceived",16,25],["H4397","that he was an angel",26,46],["H3068","of the LORD",47,58],["H1439","Gideon",60,66],["H0559","said",67,71],["H0162","Alas",73,77],["H0136","O Lord",79,85],["H3069","GOD",86,89],["H3651","for because",91,102],["H7200","I have seen",103,114],["H4397","an angel",115,123],["H3068","of the LORD",124,135],["H6440","face",136,140],["H6440","to face",141,148]]},"6:23":{"text":"And the LORD said unto him, Peace be unto thee; fear not: thou shalt not die.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H7965","unto him, Peace",18,33],["H3372","be unto thee; fear",34,52],["H4191","not: thou shalt not die",53,76]]},"6:24":{"text":"Then Gideon built an altar there unto the LORD, and called it Jehovahshalom: unto this day it is yet in Ophrah of the Abiezrites.","words":[["H1439","Then Gideon",0,11],["H1129","built",12,17],["H4196","an altar",18,26],["H3068","there unto the LORD",27,46],["H7121","and called",48,58],["H3073","it Jehovahshalom",59,75],["H3117","unto this day",77,90],["H6084","it is yet in Ophrah",91,110],["H0033","of the Abiezrites",111,128]]},"6:25":{"text":"And it came to pass the same night, that the LORD said unto him, Take thy father's young bullock, even the second bullock of seven years old, and throw down the altar of Baal that thy father hath, and cut down the grove that is by it:","words":[["H3915","And it came to pass the same night",0,34],["H3068","that the LORD",36,49],["H0559","said",50,54],["H3947","unto him, Take",55,69],["H0001","thy father's",70,82],["H6499","young",83,88],["H7794","bullock",89,96],["H8145","even the second",98,113],["H6499","bullock",114,121],["H7651","of seven",122,130],["H8141","years old",131,140],["H2040","and throw down",142,156],["H4196","the altar",157,166],["H1168","of Baal",167,174],["H0001","that thy father",175,190],["H3772","hath, and cut down",191,209],["H0842","the grove",210,219]]},"6:26":{"text":"And build an altar unto the LORD thy God upon the top of this rock, in the ordered place, and take the second bullock, and offer a burnt sacrifice with the wood of the grove which thou shalt cut down.","words":[["H1129","And build",0,9],["H4196","an altar",10,18],["H3068","unto the LORD",19,32],["H0430","thy God",33,40],["H7218","upon the top",41,53],["H4581","of this rock",54,66],["H4634","in the ordered place",68,88],["H3947","and take",90,98],["H8145","the second",99,109],["H6499","bullock",110,117],["H5927","and offer",119,128],["H5930","a burnt sacrifice",129,146],["H6086","with the wood",147,160],["H0842","of the grove",161,173],["H3772","which thou shalt cut down",174,199]]},"6:27":{"text":"Then Gideon took ten men of his servants, and did as the LORD had said unto him: and so it was, because he feared his father's household, and the men of the city, that he could not do it by day, that he did it by night.","words":[["H1439","Then Gideon",0,11],["H3947","took",12,16],["H6235","ten",17,20],["H0582","men",21,24],["H5650","of his servants",25,40],["H6213","and did",42,49],["H3068","as the LORD",50,61],["H1696","had said",62,70],["H3372","unto him: and so it was, because he feared",71,113],["H0001","his father's",114,126],["H1004","household",127,136],["H0582","and the men",138,149],["H5892","of the city",150,161],["H6213","that he could not do",163,183],["H3119","it by day",184,193],["H6213","that he did",195,206],["H3915","it by night",207,218]]},"6:28":{"text":"And when the men of the city arose early in the morning, behold, the altar of Baal was cast down, and the grove was cut down that was by it, and the second bullock was offered upon the altar that was built.","words":[["H0582","And when the men",0,16],["H5892","of the city",17,28],["H7925","arose early",29,40],["H1242","in the morning",41,55],["H4196","behold, the altar",57,74],["H1168","of Baal",75,82],["H5422","was cast down",83,96],["H0842","and the grove",98,111],["H3772","was cut down",112,124],["H8145","that was by it, and the second",125,155],["H6499","bullock",156,163],["H5927","was offered",164,175],["H4196","upon the altar",176,190],["H1129","that was built",191,205]]},"6:29":{"text":"And they said one to another, Who hath done this thing? And when they enquired and asked, they said, Gideon the son of Joash hath done this thing.","words":[["H0559","And they said",0,13],["H0376","one",14,17],["H7453","to another",18,28],["H6213","Who hath done",30,43],["H1697","this thing",44,54],["H1875","And when they enquired",56,78],["H1245","and asked",79,88],["H0559","they said",90,99],["H1439","Gideon",101,107],["H1121","the son",108,115],["H3101","of Joash",116,124],["H6213","hath done",125,134],["H1697","this thing",135,145]]},"6:30":{"text":"Then the men of the city said unto Joash, Bring out thy son, that he may die: because he hath cast down the altar of Baal, and because he hath cut down the grove that was by it.","words":[["H0582","Then the men",0,12],["H5892","of the city",13,24],["H0559","said",25,29],["H3101","unto Joash",30,40],["H3318","Bring out",42,51],["H1121","thy son",52,59],["H4191","that he may die",61,76],["H5422","because he hath cast down",78,103],["H4196","the altar",104,113],["H1168","of Baal",114,121],["H3772","and because he hath cut down",123,151],["H0842","the grove",152,161]]},"6:31":{"text":"And Joash said unto all that stood against him, Will ye plead for Baal? will ye save him? he that will plead for him, let him be put to death whilst it is yet morning: if he be a god, let him plead for himself, because one hath cast down his altar.","words":[["H3101","And Joash",0,9],["H0559","said",10,14],["H5975","unto all that stood",15,34],["H7378","against him, Will ye plead",35,61],["H1168","for Baal",62,70],["H3467","will ye save",72,84],["H7378","him? he that will plead",85,108],["H4191","for him, let him be put to death",109,141],["H1242","whilst it is yet morning",142,166],["H0430","if he be a god",168,182],["H7378","let him plead",184,197],["H5422","for himself, because one hath cast down",198,237],["H4196","his altar",238,247]]},"6:32":{"text":"Therefore on that day he called him Jerubbaal, saying, Let Baal plead against him, because he hath thrown down his altar.","words":[["H3117","Therefore on that day",0,21],["H7121","he called",22,31],["H3378","him Jerubbaal",32,45],["H0559","saying",47,53],["H1168","Let Baal",55,63],["H7378","plead",64,69],["H5422","against him, because he hath thrown down",70,110],["H4196","his altar",111,120]]},"6:33":{"text":"Then all the Midianites and the Amalekites and the children of the east were gathered together, and went over, and pitched in the valley of Jezreel.","words":[["H4080","Then all the Midianites",0,23],["H6002","and the Amalekites",24,42],["H1121","and the children",43,59],["H6924","of the east",60,71],["H0622","were gathered",72,85],["H3162","together",86,94],["H5674","and went over",96,109],["H2583","and pitched",111,122],["H6010","in the valley",123,136],["H3157","of Jezreel",137,147]]},"6:34":{"text":"But the Spirit of the LORD came upon Gideon, and he blew a trumpet; and Abiezer was gathered after him.","words":[["H7307","But the Spirit",0,14],["H3068","of the LORD",15,26],["H3847","came",27,31],["H1439","upon Gideon",32,43],["H8628","and he blew",45,56],["H7782","a trumpet",57,66],["H0044","and Abiezer",68,79],["H2199","was gathered",80,92],["H0310","after",93,98]]},"6:35":{"text":"And he sent messengers throughout all Manasseh; who also was gathered after him: and he sent messengers unto Asher, and unto Zebulun, and unto Naphtali; and they came up to meet them.","words":[["H7971","And he sent",0,11],["H4397","messengers",12,22],["H4519","throughout all Manasseh",23,46],["H2199","who also was gathered",48,69],["H0310","after",70,75],["H7971","him: and he sent",76,92],["H4397","messengers",93,103],["H0836","unto Asher",104,114],["H2074","and unto Zebulun",116,132],["H5321","and unto Naphtali",134,151],["H5927","and they came up",153,169],["H7125","to meet",170,177]]},"6:36":{"text":"And Gideon said unto God, If thou wilt save Israel by mine hand, as thou hast said,","words":[["H1439","And Gideon",0,10],["H0559","said",11,15],["H0430","unto God",16,24],["H3426","If thou wilt",26,38],["H3467","save",39,43],["H3478","Israel",44,50],["H3027","by mine hand",51,63],["H1696","as thou hast said",65,82]]},"6:37":{"text":"Behold, I will put a fleece of wool in the floor; and if the dew be on the fleece only, and it be dry upon all the earth beside, then shall I know that thou wilt save Israel by mine hand, as thou hast said.","words":[["H3322","Behold, I will put",0,18],["H1492","a fleece",19,27],["H6785","of wool",28,35],["H1637","in the floor",36,48],["H2919","and if the dew",50,64],["H1492","be on the fleece",65,81],["H2721","only, and it be dry",82,101],["H0776","upon all the earth",102,120],["H3045","beside, then shall I know",121,146],["H3467","that thou wilt save",147,166],["H3478","Israel",167,173],["H3027","by mine hand",174,186],["H1696","as thou hast said",188,205]]},"6:38":{"text":"And it was so: for he rose up early on the morrow, and thrust the fleece together, and wringed the dew out of the fleece, a bowl full of water.","words":[["H7925","And it was so: for he rose up early",0,35],["H4283","on the morrow",36,49],["H2115","and thrust",51,61],["H1492","the fleece",62,72],["H2115","together",73,81],["H4680","and wringed",83,94],["H2919","the dew",95,102],["H1492","out of the fleece",103,120],["H5602","a bowl",122,128],["H4393","full",129,133],["H4325","of water",134,142]]},"6:39":{"text":"And Gideon said unto God, Let not thine anger be hot against me, and I will speak but this once: let me prove, I pray thee, but this once with the fleece; let it now be dry only upon the fleece, and upon all the ground let there be dew.","words":[["H1439","And Gideon",0,10],["H0559","said",11,15],["H0430","unto God",16,24],["H0639","Let not thine anger",26,45],["H2734","be hot",46,52],["H1696","against me, and I will speak",53,81],["H6471","but this once",82,95],["H5254","let me prove",97,109],["H6471","I pray thee, but this once",111,137],["H1492","with the fleece",138,153],["H2721","let it now be dry",155,172],["H1492","only upon the fleece",173,193],["H0776","and upon all the ground",195,218],["H2919","let there be dew",219,235]]},"6:40":{"text":"And God did so that night: for it was dry upon the fleece only, and there was dew on all the ground.","words":[["H0430","And God",0,7],["H6213","did",8,11],["H3915","so that night",12,25],["H2721","for it was dry",27,41],["H1492","upon the fleece",42,57],["H2919","only, and there was dew",58,81],["H0776","on all the ground",82,99]]},"7:1":{"text":"Then Jerubbaal, who is Gideon, and all the people that were with him, rose up early, and pitched beside the well of Harod: so that the host of the Midianites were on the north side of them, by the hill of Moreh, in the valley.","words":[["H3378","Then Jerubbaal",0,14],["H1439","who is Gideon",16,29],["H5971","and all the people",31,49],["H7925","that were with him, rose up early",50,83],["H2583","and pitched",85,96],["H5878","beside the well of Harod",97,121],["H4264","so that the host",123,139],["H4080","of the Midianites",140,157],["H6828","were on the north side",158,180],["H1389","of them, by the hill",181,201],["H4176","of Moreh",202,210],["H6010","in the valley",212,225]]},"7:2":{"text":"And the LORD said unto Gideon, The people that are with thee are too many for me to give the Midianites into their hands, lest Israel vaunt themselves against me, saying, Mine own hand hath saved me.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H1439","unto Gideon",18,29],["H5971","The people",31,41],["H7227","that are with thee are too many",42,73],["H5414","for me to give",74,88],["H4080","the Midianites",89,103],["H3027","into their hands",104,120],["H3478","lest Israel",122,133],["H6286","vaunt",134,139],["H0559","themselves against me, saying",140,169],["H3027","Mine own hand",171,184],["H3467","hath saved",185,195]]},"7:3":{"text":"Now therefore go to, proclaim in the ears of the people, saying, Whosoever is fearful and afraid, let him return and depart early from mount Gilead. And there returned of the people twenty and two thousand; and there remained ten thousand.","words":[["H4994","Now therefore go to",0,19],["H7121","proclaim",21,29],["H0241","in the ears",30,41],["H5971","of the people",42,55],["H0559","saying",57,63],["H3373","Whosoever is fearful",65,85],["H2730","and afraid",86,96],["H7725","let him return",98,112],["H6852","and depart early",113,129],["H2022","from mount",130,140],["H1568","Gilead",141,147],["H7725","And there returned",149,167],["H5971","of the people",168,181],["H6242","twenty",182,188],["H8147","and two",189,196],["H0505","thousand",197,205],["H7604","and there remained",207,225],["H6235","ten",226,229],["H0505","thousand",230,238]]},"7:4":{"text":"And the LORD said unto Gideon, The people are yet too many; bring them down unto the water, and I will try them for thee there: and it shall be, that of whom I say unto thee, This shall go with thee, the same shall go with thee; and of whomsoever I say unto thee, This shall not go with thee, the same shall not go.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H1439","unto Gideon",18,29],["H5971","The people",31,41],["H7227","are yet too many",42,58],["H3381","bring them down",60,75],["H4325","unto the water",76,90],["H6884","and I will try",92,106],["H0559","them for thee there: and it shall be, that of whom I say",107,163],["H3212","unto thee, This shall go",164,188],["H3212","with thee, the same shall go",189,217],["H0559","with thee; and of whomsoever I say",218,252],["H3212","unto thee, This shall not go",253,281],["H3212","with thee, the same shall not go",282,314]]},"7:5":{"text":"So he brought down the people unto the water: and the LORD said unto Gideon, Every one that lappeth of the water with his tongue, as a dog lappeth, him shalt thou set by himself; likewise every one that boweth down upon his knees to drink.","words":[["H3381","So he brought down",0,18],["H5971","the people",19,29],["H4325","unto the water",30,44],["H3068","and the LORD",46,58],["H0559","said",59,63],["H1439","unto Gideon",64,75],["H3952","Every one that lappeth",77,99],["H4325","of the water",100,112],["H3956","with his tongue",113,128],["H3611","as a dog",130,138],["H3952","lappeth",139,146],["H3322","him shalt thou set",148,166],["H3766","by himself; likewise every one that boweth down",167,214],["H1290","upon his knees",215,229],["H8354","to drink",230,238]]},"7:6":{"text":"And the number of them that lapped, putting their hand to their mouth, were three hundred men: but all the rest of the people bowed down upon their knees to drink water.","words":[["H4557","And the number",0,14],["H3952","of them that lapped",15,34],["H3027","putting their hand",36,54],["H6310","to their mouth",55,69],["H7969","were three",71,81],["H3967","hundred",82,89],["H0376","men",90,93],["H3499","but all the rest",95,111],["H5971","of the people",112,125],["H3766","bowed down",126,136],["H1290","upon their knees",137,153],["H8354","to drink",154,162],["H4325","water",163,168]]},"7:7":{"text":"And the LORD said unto Gideon, By the three hundred men that lapped will I save you, and deliver the Midianites into thine hand: and let all the other people go every man unto his place.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H1439","unto Gideon",18,29],["H7969","By the three",31,43],["H3967","hundred",44,51],["H0376","men",52,55],["H3952","that lapped",56,67],["H3467","will I save",68,79],["H5414","you, and deliver",80,96],["H4080","the Midianites",97,111],["H3027","into thine hand",112,127],["H5971","and let all the other people",129,157],["H3212","go",158,160],["H0376","every man",161,170],["H4725","unto his place",171,185]]},"7:8":{"text":"So the people took victuals in their hand, and their trumpets: and he sent all the rest of Israel every man unto his tent, and retained those three hundred men: and the host of Midian was beneath him in the valley.","words":[["H5971","So the people",0,13],["H3947","took",14,18],["H6720","victuals",19,27],["H3027","in their hand",28,41],["H7782","and their trumpets",43,61],["H7971","and he sent",63,74],["H0376","all",75,78],["H3478","the rest of Israel",79,97],["H0376","every man",98,107],["H0168","unto his tent",108,121],["H2388","and retained",123,135],["H7969","those three",136,147],["H3967","hundred",148,155],["H0376","men",156,159],["H4264","and the host",161,173],["H4080","of Midian",174,183],["H6010","was beneath him in the valley",184,213]]},"7:9":{"text":"And it came to pass the same night, that the LORD said unto him, Arise, get thee down unto the host; for I have delivered it into thine hand.","words":[["H3915","And it came to pass the same night",0,34],["H3068","that the LORD",36,49],["H0559","said",50,54],["H6965","unto him, Arise",55,70],["H3381","get thee down",72,85],["H4264","unto the host",86,99],["H5414","for I have delivered",101,121],["H3027","it into thine hand",122,140]]},"7:10":{"text":"But if thou fear to go down, go thou with Phurah thy servant down to the host:","words":[["H3373","But if thou fear",0,16],["H3381","to go down",17,27],["H3381","go",29,31],["H6513","thou with Phurah",32,48],["H5288","thy servant",49,60],["H3381","down",61,65],["H4264","to the host",66,77]]},"7:11":{"text":"And thou shalt hear what they say; and afterward shall thine hands be strengthened to go down unto the host. Then went he down with Phurah his servant unto the outside of the armed men that were in the host.","words":[["H8085","And thou shalt hear",0,19],["H1696","what they say",20,33],["H0310","and afterward",35,48],["H3027","shall thine hands",49,66],["H2388","be strengthened",67,82],["H3381","to go down",83,93],["H4264","unto the host",94,107],["H3381","Then went he down",109,126],["H6513","with Phurah",127,138],["H5288","his servant",139,150],["H7097","unto the outside",151,167],["H2571","of the armed men",168,184],["H4264","that were in the host",185,206]]},"7:12":{"text":"And the Midianites and the Amalekites and all the children of the east lay along in the valley like grasshoppers for multitude; and their camels were without number, as the sand by the sea side for multitude.","words":[["H4080","And the Midianites",0,18],["H6002","and the Amalekites",19,37],["H1121","and all the children",38,58],["H6924","of the east",59,70],["H5307","lay",71,74],["H6010","along in the valley",75,94],["H0697","like grasshoppers",95,112],["H7230","for multitude",113,126],["H1581","and their camels",128,144],["H4557","were without number",145,164],["H2344","as the sand",166,177],["H3220","by the sea",178,188],["H8193","side",189,193],["H7230","for multitude",194,207]]},"7:13":{"text":"And when Gideon was come, behold, there was a man that told a dream unto his fellow, and said, Behold, I dreamed a dream, and, lo, a cake of barley bread tumbled into the host of Midian, and came unto a tent, and smote it that it fell, and overturned it, that the tent lay along.","words":[["H1439","And when Gideon",0,15],["H0935","was come",16,24],["H0376","behold, there was a man",26,49],["H5608","that told",50,59],["H2472","a dream",60,67],["H7453","unto his fellow",68,83],["H0559","and said",85,93],["H2492","Behold, I dreamed",95,112],["H2472","a dream",113,120],["H6742","and, lo, a cake",122,137],["H6742","and, lo, a cake",122,137],["H8184","of barley",138,147],["H3899","bread",148,153],["H2015","tumbled",154,161],["H4264","into the host",162,175],["H4080","of Midian",176,185],["H0935","and came",187,195],["H0168","unto a tent",196,207],["H5221","and smote",209,218],["H5307","it that it fell",219,234],["H2015","and overturned",236,250],["H4605","and overturned",236,250],["H0168","it, that the tent",251,268],["H5307","lay along",269,278]]},"7:14":{"text":"And his fellow answered and said, This is nothing else save the sword of Gideon the son of Joash, a man of Israel: for into his hand hath God delivered Midian, and all the host.","words":[["H7453","And his fellow",0,14],["H6030","answered",15,23],["H0559","and said",24,32],["H2719","This is nothing else save the sword",34,69],["H1439","of Gideon",70,79],["H1121","the son",80,87],["H3101","of Joash",88,96],["H0376","a man",98,103],["H3478","of Israel",104,113],["H3027","for into his hand",115,132],["H0430","hath God",133,141],["H5414","delivered",142,151],["H4080","Midian",152,158],["H4264","and all the host",160,176]]},"7:15":{"text":"And it was so, when Gideon heard the telling of the dream, and the interpretation thereof, that he worshipped, and returned into the host of Israel, and said, Arise; for the LORD hath delivered into your hand the host of Midian.","words":[["H1439","And it was so, when Gideon",0,26],["H8085","heard",27,32],["H4557","the telling",33,44],["H2472","of the dream",45,57],["H7667","and the interpretation",59,81],["H7812","thereof, that he worshipped",82,109],["H7725","and returned",111,123],["H4264","into the host",124,137],["H3478","of Israel",138,147],["H0559","and said",149,157],["H6965","Arise",159,164],["H3068","for the LORD",166,178],["H5414","hath delivered",179,193],["H3027","into your hand",194,208],["H4264","the host",209,217],["H4080","of Midian",218,227]]},"7:16":{"text":"And he divided the three hundred men into three companies, and he put a trumpet in every man's hand, with empty pitchers, and lamps within the pitchers.","words":[["H2673","And he divided",0,14],["H7969","the three",15,24],["H3967","hundred",25,32],["H0376","men",33,36],["H7969","into three",37,47],["H7218","companies",48,57],["H5414","and he put",59,69],["H7782","a trumpet",70,79],["H3027","in every man's hand",80,99],["H7386","with empty",101,111],["H3537","pitchers",112,120],["H3940","and lamps",122,131],["H8432","within",132,138],["H3537","the pitchers",139,151]]},"7:17":{"text":"And he said unto them, Look on me, and do likewise: and, behold, when I come to the outside of the camp, it shall be that, as I do, so shall ye do.","words":[["H0559","And he said",0,11],["H7200","unto them, Look",12,27],["H6213","on me, and do",28,41],["H0935","likewise: and, behold, when I come",42,76],["H7097","to the outside",77,91],["H4264","of the camp",92,103],["H6213","it shall be that, as I do",105,130],["H6213","so shall ye do",132,146]]},"7:18":{"text":"When I blow with a trumpet, I and all that are with me, then blow ye the trumpets also on every side of all the camp, and say, The sword of the LORD, and of Gideon.","words":[["H8628","When I blow",0,11],["H7782","with a trumpet",12,26],["H8628","I and all that are with me, then blow",28,65],["H7782","ye the trumpets",66,81],["H5439","also on every side",82,100],["H4264","of all the camp",101,116],["H0559","and say",118,125],["H3068","The sword of the LORD",127,148],["H1439","and of Gideon",150,163]]},"7:19":{"text":"So Gideon, and the hundred men that were with him, came unto the outside of the camp in the beginning of the middle watch; and they had but newly set the watch: and they blew the trumpets, and brake the pitchers that were in their hands.","words":[["H1439","So Gideon",0,9],["H3967","and the hundred",11,26],["H0376","men",27,30],["H0935","that were with him, came",31,55],["H7097","unto the outside",56,72],["H4264","of the camp",73,84],["H7218","in the beginning",85,101],["H8484","of the middle",102,115],["H0821","watch",116,121],["H0389","and they had but",123,139],["H6965","newly",140,145],["H6965","set",146,149],["H8104","the watch",150,159],["H8628","and they blew",161,174],["H7782","the trumpets",175,187],["H5310","and brake",189,198],["H3537","the pitchers",199,211],["H3027","that were in their hands",212,236]]},"7:20":{"text":"And the three companies blew the trumpets, and brake the pitchers, and held the lamps in their left hands, and the trumpets in their right hands to blow withal: and they cried, The sword of the LORD, and of Gideon.","words":[["H7969","And the three",0,13],["H7218","companies",14,23],["H8628","blew",24,28],["H7782","the trumpets",29,41],["H7665","and brake",43,52],["H3537","the pitchers",53,65],["H2388","and held",67,75],["H3940","the lamps",76,85],["H8040","in their left",86,99],["H3027","hands",100,105],["H7782","and the trumpets",107,123],["H3225","in their right",124,138],["H3027","hands",139,144],["H8628","to blow",145,152],["H7121","withal: and they cried",153,175],["H2719","The sword",177,186],["H3068","of the LORD",187,198],["H1439","and of Gideon",200,213]]},"7:21":{"text":"And they stood every man in his place round about the camp: and all the host ran, and cried, and fled.","words":[["H5975","And they stood",0,14],["H0376","every man",15,24],["H5439","in his place round about",25,49],["H4264","the camp",50,58],["H4264","and all the host",60,76],["H7323","ran",77,80],["H7321","and cried",82,91],["H5127","and fled",93,101],["H5127","and fled",93,101]]},"7:22":{"text":"And the three hundred blew the trumpets, and the LORD set every man's sword against his fellow, even throughout all the host: and the host fled to Bethshittah in Zererath, and to the border of Abelmeholah, unto Tabbath.","words":[["H7969","And the three",0,13],["H3967","hundred",14,21],["H8628","blew",22,26],["H7782","the trumpets",27,39],["H3068","and the LORD",41,53],["H7760","set",54,57],["H0376","every man's",58,69],["H2719","sword",70,75],["H7453","against his fellow",76,94],["H4264","even throughout all the host",96,124],["H4264","and the host",126,138],["H5127","fled",139,143],["H1029","to Bethshittah",144,158],["H6888","in Zererath",159,170],["H8193","and to the border",172,189],["H0065","of Abelmeholah",190,204],["H2888","unto Tabbath",206,218]]},"7:23":{"text":"And the men of Israel gathered themselves together out of Naphtali, and out of Asher, and out of all Manasseh, and pursued after the Midianites.","words":[["H0376","And the men",0,11],["H3478","of Israel",12,21],["H6817","gathered themselves together",22,50],["H5321","out of Naphtali",51,66],["H0836","and out of Asher",68,84],["H4519","and out of all Manasseh",86,109],["H7291","and pursued",111,122],["H0310","after",123,128],["H4080","the Midianites",129,143]]},"7:24":{"text":"And Gideon sent messengers throughout all mount Ephraim, saying, Come down against the Midianites, and take before them the waters unto Bethbarah and Jordan. Then all the men of Ephraim gathered themselves together, and took the waters unto Bethbarah and Jordan.","words":[["H1439","And Gideon",0,10],["H7971","sent",11,15],["H4397","messengers",16,26],["H2022","throughout all mount",27,47],["H0669","Ephraim",48,55],["H0559","saying",57,63],["H3381","Come down",65,74],["H7125","against",75,82],["H4080","the Midianites",83,97],["H3920","and take",99,107],["H4325","before them the waters",108,130],["H1012","unto Bethbarah",131,145],["H3383","and Jordan",146,156],["H0376","Then all the men",158,174],["H0669","of Ephraim",175,185],["H6817","gathered themselves together",186,214],["H3920","and took",216,224],["H4325","the waters",225,235],["H1012","unto Bethbarah",236,250],["H3383","and Jordan",251,261]]},"7:25":{"text":"And they took two princes of the Midianites, Oreb and Zeeb; and they slew Oreb upon the rock Oreb, and Zeeb they slew at the winepress of Zeeb, and pursued Midian, and brought the heads of Oreb and Zeeb to Gideon on the other side Jordan.","words":[["H3920","And they took",0,13],["H8147","two",14,17],["H8269","princes",18,25],["H4080","of the Midianites",26,43],["H6159","Oreb",45,49],["H2062","and Zeeb",50,58],["H2026","and they slew",60,73],["H6159","Oreb",74,78],["H6697","upon the rock",79,92],["H6159","Oreb",93,97],["H2062","and Zeeb",99,107],["H2026","they slew",108,117],["H3342","at the winepress",118,134],["H2062","of Zeeb",135,142],["H7291","and pursued",144,155],["H4080","Midian",156,162],["H0935","and brought",164,175],["H7218","the heads",176,185],["H6159","of Oreb",186,193],["H2062","and Zeeb",194,202],["H1439","to Gideon",203,212],["H5676","on the other side",213,230],["H3383","Jordan",231,237]]},"8:1":{"text":"And the men of Ephraim said unto him, Why hast thou served us thus, that thou calledst us not, when thou wentest to fight with the Midianites? And they did chide with him sharply.","words":[["H0376","And the men",0,11],["H0669","of Ephraim",12,22],["H0559","said",23,27],["H4100","unto him, Why hast thou",28,51],["H6213","served",52,58],["H1697","us thus",59,66],["H7121","that thou calledst",68,86],["H1980","us not, when thou wentest",87,112],["H3898","to fight",113,121],["H4080","with the Midianites",122,141],["H7378","And they did chide",143,161],["H2394","with him sharply",162,178]]},"8:2":{"text":"And he said unto them, What have I done now in comparison of you? Is not the gleaning of the grapes of Ephraim better than the vintage of Abiezer?","words":[["H0559","And he said",0,11],["H6213","unto them, What have I done",12,39],["H5955","now in comparison of you? Is not the gleaning",40,85],["H0669","of the grapes of Ephraim",86,110],["H2896","better",111,117],["H1210","than the vintage",118,134],["H0044","of Abiezer",135,145]]},"8:3":{"text":"God hath delivered into your hands the princes of Midian, Oreb and Zeeb: and what was I able to do in comparison of you? Then their anger was abated toward him, when he had said that.","words":[["H0430","God",0,3],["H5414","hath delivered",4,18],["H3027","into your hands",19,34],["H8269","the princes",35,46],["H4080","of Midian",47,56],["H6159","Oreb",58,62],["H2062","and Zeeb",63,71],["H3201","and what was I able",73,92],["H6213","to do",93,98],["H7307","in comparison of you? Then their anger",99,137],["H7503","was abated",138,148],["H1697","toward him, when he had said",149,177],["H1696","that",178,182]]},"8:4":{"text":"And Gideon came to Jordan, and passed over, he, and the three hundred men that were with him, faint, yet pursuing them.","words":[["H1439","And Gideon",0,10],["H0935","came",11,15],["H3383","to Jordan",16,25],["H5674","and passed over",27,42],["H7969","he, and the three",44,61],["H3967","hundred",62,69],["H0376","men",70,73],["H5889","that were with him, faint",74,99],["H7291","yet pursuing",101,113]]},"8:5":{"text":"And he said unto the men of Succoth, Give, I pray you, loaves of bread unto the people that follow me; for they be faint, and I am pursuing after Zebah and Zalmunna, kings of Midian.","words":[["H0559","And he said",0,11],["H0582","unto the men",12,24],["H5523","of Succoth",25,35],["H5414","Give",37,41],["H3603","I pray you, loaves",43,61],["H3899","of bread",62,70],["H5971","unto the people",71,86],["H7272","that follow",87,98],["H5889","me; for they be faint",99,120],["H7291","and I am pursuing",122,139],["H0310","after",140,145],["H2078","Zebah",146,151],["H6759","and Zalmunna",152,164],["H4428","kings",166,171],["H4080","of Midian",172,181]]},"8:6":{"text":"And the princes of Succoth said, Are the hands of Zebah and Zalmunna now in thine hand, that we should give bread unto thine army?","words":[["H8269","And the princes",0,15],["H5523","of Succoth",16,26],["H0559","said",27,31],["H3709","Are the hands",33,46],["H2078","of Zebah",47,55],["H6759","and Zalmunna",56,68],["H3027","now in thine hand",69,86],["H5414","that we should give",88,107],["H3899","bread",108,113],["H6635","unto thine army",114,129]]},"8:7":{"text":"And Gideon said, Therefore when the LORD hath delivered Zebah and Zalmunna into mine hand, then I will tear your flesh with the thorns of the wilderness and with briers.","words":[["H1439","And Gideon",0,10],["H0559","said",11,15],["H3068","Therefore when the LORD",17,40],["H5414","hath delivered",41,55],["H2078","Zebah",56,61],["H6759","and Zalmunna",62,74],["H3027","into mine hand",75,89],["H1758","then I will tear",91,107],["H1320","your flesh",108,118],["H6975","with the thorns",119,134],["H4057","of the wilderness",135,152],["H1303","and with briers",153,168]]},"8:8":{"text":"And he went up thence to Penuel, and spake unto them likewise: and the men of Penuel answered him as the men of Succoth had answered him.","words":[["H5927","And he went up",0,14],["H6439","thence to Penuel",15,31],["H1696","and spake",33,42],["H2063","unto them likewise",43,61],["H0582","and the men",63,74],["H6439","of Penuel",75,84],["H6030","answered",85,93],["H0582","him as the men",94,108],["H5523","of Succoth",109,119],["H6030","had answered",120,132]]},"8:9":{"text":"And he spake also unto the men of Penuel, saying, When I come again in peace, I will break down this tower.","words":[["H0559","And he spake",0,12],["H0582","also unto the men",13,30],["H6439","of Penuel",31,40],["H0559","saying",42,48],["H7725","When I come again",50,67],["H7965","in peace",68,76],["H5422","I will break down",78,95],["H4026","this tower",96,106]]},"8:10":{"text":"Now Zebah and Zalmunna were in Karkor, and their hosts with them, about fifteen thousand men, all that were left of all the hosts of the children of the east: for there fell an hundred and twenty thousand men that drew sword.","words":[["H2078","Now Zebah",0,9],["H6759","and Zalmunna",10,22],["H7174","were in Karkor",23,37],["H4264","and their hosts",39,54],["H2568","with them, about fifteen",55,79],["H6240","with them, about fifteen",55,79],["H0505","thousand",80,88],["H3498","men, all that were left",89,112],["H4264","of all the hosts",113,129],["H1121","of the children",130,145],["H6924","of the east",146,157],["H5307","for there fell",159,173],["H3967","an hundred",174,184],["H6242","and twenty",185,195],["H0505","thousand",196,204],["H0376","men",205,208],["H8025","that drew",209,218],["H2719","sword",219,224]]},"8:11":{"text":"And Gideon went up by the way of them that dwelt in tents on the east of Nobah and Jogbehah, and smote the host: for the host was secure.","words":[["H1439","And Gideon",0,10],["H5927","went up",11,18],["H1870","by the way",19,29],["H7931","of them that dwelt",30,48],["H0168","in tents",49,57],["H6924","on the east",58,69],["H5025","of Nobah",70,78],["H3011","and Jogbehah",79,91],["H5221","and smote",93,102],["H4264","the host",103,111],["H4264","for the host",113,125],["H0983","was secure",126,136]]},"8:12":{"text":"And when Zebah and Zalmunna fled, he pursued after them, and took the two kings of Midian, Zebah and Zalmunna, and discomfited all the host.","words":[["H2078","And when Zebah",0,14],["H6759","and Zalmunna",15,27],["H5127","fled",28,32],["H7291","he pursued",34,44],["H0310","after",45,50],["H3920","them, and took",51,65],["H8147","the two",66,73],["H4428","kings",74,79],["H4080","of Midian",80,89],["H2078","Zebah",91,96],["H6759","and Zalmunna",97,109],["H2729","and discomfited",111,126],["H4264","all the host",127,139]]},"8:13":{"text":"And Gideon the son of Joash returned from battle before the sun was up,","words":[["H1439","And Gideon",0,10],["H1121","the son",11,18],["H3101","of Joash",19,27],["H7725","returned",28,36],["H4421","from battle",37,48],["H4608","before",49,55],["H2775","the sun",56,63]]},"8:14":{"text":"And caught a young man of the men of Succoth, and enquired of him: and he described unto him the princes of Succoth, and the elders thereof, even threescore and seventeen men.","words":[["H3920","And caught",0,10],["H5288","a young man",11,22],["H0582","of the men",23,33],["H5523","of Succoth",34,44],["H7592","and enquired",46,58],["H3789","of him: and he described",59,83],["H8269","unto him the princes",84,104],["H5523","of Succoth",105,115],["H2205","and the elders",117,131],["H7657","thereof, even threescore and seventeen",132,170],["H7651","thereof, even threescore and seventeen",132,170],["H0376","men",171,174]]},"8:15":{"text":"And he came unto the men of Succoth, and said, Behold Zebah and Zalmunna, with whom ye did upbraid me, saying, Are the hands of Zebah and Zalmunna now in thine hand, that we should give bread unto thy men that are weary?","words":[["H0935","And he came",0,11],["H0582","unto the men",12,24],["H5523","of Succoth",25,35],["H0559","and said",37,45],["H2078","Behold Zebah",47,59],["H6759","and Zalmunna",60,72],["H2778","with whom ye did upbraid",74,98],["H0559","me, saying",99,109],["H3709","Are the hands",111,124],["H2078","of Zebah",125,133],["H6759","and Zalmunna",134,146],["H3027","now in thine hand",147,164],["H5414","that we should give",166,185],["H3899","bread",186,191],["H0582","unto thy men",192,204],["H3287","that are weary",205,219]]},"8:16":{"text":"And he took the elders of the city, and thorns of the wilderness and briers, and with them he taught the men of Succoth.","words":[["H3947","And he took",0,11],["H2205","the elders",12,22],["H5892","of the city",23,34],["H6975","and thorns",36,46],["H4057","of the wilderness",47,64],["H1303","and briers",65,75],["H3045","and with them he taught",77,100],["H0582","the men",101,108],["H5523","of Succoth",109,119]]},"8:17":{"text":"And he beat down the tower of Penuel, and slew the men of the city.","words":[["H5422","And he beat down",0,16],["H4026","the tower",17,26],["H6439","of Penuel",27,36],["H2026","and slew",38,46],["H0582","the men",47,54],["H5892","of the city",55,66]]},"8:18":{"text":"Then said he unto Zebah and Zalmunna, What manner of men were they whom ye slew at Tabor? And they answered, As thou art, so were they; each one resembled the children of a king.","words":[["H0559","Then said",0,9],["H2078","he unto Zebah",10,23],["H6759","and Zalmunna",24,36],["H0375","What",38,42],["H0582","manner of men",43,56],["H2026","were they whom ye slew",57,79],["H8396","at Tabor",80,88],["H0559","And they answered",90,107],["H3644","As thou",109,116],["H0259","art, so were they; each one",117,144],["H8389","resembled",145,154],["H1121","the children",155,167],["H4428","of a king",168,177]]},"8:19":{"text":"And he said, They were my brethren, even the sons of my mother: as the LORD liveth, if ye had saved them alive, I would not slay you.","words":[["H0559","And he said",0,11],["H0251","They were my brethren",13,34],["H1121","even the sons",36,49],["H0517","of my mother",50,62],["H3068","as the LORD",64,75],["H2416","liveth",76,82],["H3863","if",84,86],["H2421","ye had saved them alive",87,110],["H2026","I would not slay",112,128]]},"8:20":{"text":"And he said unto Jether his firstborn, Up, and slay them. But the youth drew not his sword: for he feared, because he was yet a youth.","words":[["H0559","And he said",0,11],["H3500","unto Jether",12,23],["H1060","his firstborn",24,37],["H6965","Up",39,41],["H2026","and slay",43,51],["H5288","them. But the youth",52,71],["H8025","drew",72,76],["H2719","not his sword",77,90],["H3372","for he feared",92,105],["H5288","because he was yet a youth",107,133]]},"8:21":{"text":"Then Zebah and Zalmunna said, Rise thou, and fall upon us: for as the man is, so is his strength. And Gideon arose, and slew Zebah and Zalmunna, and took away the ornaments that were on their camels' necks.","words":[["H2078","Then Zebah",0,10],["H6759","and Zalmunna",11,23],["H0559","said",24,28],["H6965","Rise",30,34],["H6293","thou, and fall",35,49],["H0376","upon us: for as the man",50,73],["H1369","is, so is his strength",74,96],["H1439","And Gideon",98,108],["H6965","arose",109,114],["H2026","and slew",116,124],["H2078","Zebah",125,130],["H6759","and Zalmunna",131,143],["H3947","and took away",145,158],["H7720","the ornaments",159,172],["H1581","that were on their camels'",173,199],["H6677","necks",200,205]]},"8:22":{"text":"Then the men of Israel said unto Gideon, Rule thou over us, both thou, and thy son, and thy son's son also: for thou hast delivered us from the hand of Midian.","words":[["H0376","Then the men",0,12],["H3478","of Israel",13,22],["H0559","said",23,27],["H1439","unto Gideon",28,39],["H4910","Rule",41,45],["H1121","thou over us, both thou, and thy son",46,82],["H1121","and thy son's",84,97],["H1121","son",98,101],["H3467","also: for thou hast delivered",102,131],["H3027","us from the hand",132,148],["H4080","of Midian",149,158]]},"8:23":{"text":"And Gideon said unto them, I will not rule over you, neither shall my son rule over you: the LORD shall rule over you.","words":[["H1439","And Gideon",0,10],["H0559","said",11,15],["H4910","unto them, I will not rule",16,42],["H1121","over you, neither shall my son",43,73],["H4910","rule",74,78],["H3068","over you: the LORD",79,97],["H4910","shall rule",98,108]]},"8:24":{"text":"And Gideon said unto them, I would desire a request of you, that ye would give me every man the earrings of his prey. (For they had golden earrings, because they were Ishmaelites.)","words":[["H1439","And Gideon",0,10],["H0559","said",11,15],["H7592","unto them, I would desire",16,41],["H7596","a request",42,51],["H5414","of you, that ye would give",52,78],["H0376","me every man",79,91],["H5141","the earrings",92,104],["H7998","of his prey",105,116],["H2091","(For they had golden",118,138],["H5141","earrings",139,147],["H3459","because they were Ishmaelites",149,178]]},"8:25":{"text":"And they answered, We will willingly give them. And they spread a garment, and did cast therein every man the earrings of his prey.","words":[["H0559","And they answered",0,17],["H5414","We will willingly",19,36],["H5414","give",37,41],["H6566","them. And they spread",42,63],["H8071","a garment",64,73],["H7993","and did cast",75,87],["H0376","therein every man",88,105],["H5141","the earrings",106,118],["H7998","of his prey",119,130]]},"8:26":{"text":"And the weight of the golden earrings that he requested was a thousand and seven hundred shekels of gold; beside ornaments, and collars, and purple raiment that was on the kings of Midian, and beside the chains that were about their camels' necks.","words":[["H4948","And the weight",0,14],["H2091","of the golden",15,28],["H5141","earrings",29,37],["H7592","that he requested",38,55],["H0505","was a thousand",56,70],["H7651","and seven",71,80],["H3967","hundred",81,88],["H2091","shekels of gold",89,104],["H7720","beside ornaments",106,122],["H5188","and collars",124,135],["H0713","and purple",137,147],["H0899","raiment",148,155],["H4428","that was on the kings",156,177],["H4080","of Midian",178,187],["H6060","and beside the chains",189,210],["H1581","that were about their camels'",211,240],["H6677","necks",241,246]]},"8:27":{"text":"And Gideon made an ephod thereof, and put it in his city, even in Ophrah: and all Israel went thither a whoring after it: which thing became a snare unto Gideon, and to his house.","words":[["H1439","And Gideon",0,10],["H6213","made",11,15],["H0646","an ephod",16,24],["H3322","thereof, and put",25,41],["H5892","it in his city",42,56],["H6084","even in Ophrah",58,72],["H3478","and all Israel",74,88],["H2181","went thither a whoring",89,111],["H0310","after",112,117],["H4170","it: which thing became a snare",118,148],["H1439","unto Gideon",149,160],["H1004","and to his house",162,178]]},"8:28":{"text":"Thus was Midian subdued before the children of Israel, so that they lifted up their heads no more. And the country was in quietness forty years in the days of Gideon.","words":[["H4080","Thus was Midian",0,15],["H3665","subdued",16,23],["H6440","before",24,30],["H1121","the children",31,43],["H3478","of Israel",44,53],["H5375","so that they lifted up",55,77],["H7218","their heads",78,89],["H3254","no more",90,97],["H0776","And the country",99,114],["H8252","was in quietness",115,131],["H0705","forty",132,137],["H8141","years",138,143],["H3117","in the days",144,155],["H1439","of Gideon",156,165]]},"8:29":{"text":"And Jerubbaal the son of Joash went and dwelt in his own house.","words":[["H3378","And Jerubbaal",0,13],["H1121","the son",14,21],["H3101","of Joash",22,30],["H3212","went",31,35],["H3427","and dwelt",36,45],["H1004","in his own house",46,62]]},"8:30":{"text":"And Gideon had threescore and ten sons of his body begotten: for he had many wives.","words":[["H1439","And Gideon",0,10],["H7657","had threescore and ten",11,33],["H1121","sons",34,38],["H3409","of his body",39,50],["H3318","begotten",51,59],["H7227","for he had many",61,76],["H0802","wives",77,82]]},"8:31":{"text":"And his concubine that was in Shechem, she also bare him a son, whose name he called Abimelech.","words":[["H6370","And his concubine",0,17],["H7927","that was in Shechem",18,37],["H3205","she also bare",39,52],["H1121","him a son",53,62],["H8034","whose name",64,74],["H7760","he called",75,84],["H0040","Abimelech",85,94]]},"8:32":{"text":"And Gideon the son of Joash died in a good old age, and was buried in the sepulchre of Joash his father, in Ophrah of the Abiezrites.","words":[["H1439","And Gideon",0,10],["H1121","the son",11,18],["H3101","of Joash",19,27],["H4191","died",28,32],["H2896","in a good",33,42],["H7872","old age",43,50],["H6912","and was buried",52,66],["H6913","in the sepulchre",67,83],["H3101","of Joash",84,92],["H0001","his father",93,103],["H6084","in Ophrah",105,114],["H0033","of the Abiezrites",115,132]]},"8:33":{"text":"And it came to pass, as soon as Gideon was dead, that the children of Israel turned again, and went a whoring after Baalim, and made Baalberith their god.","words":[["H1439","And it came to pass, as soon as Gideon",0,38],["H4191","was dead",39,47],["H1121","that the children",49,66],["H3478","of Israel",67,76],["H7725","turned again",77,89],["H2181","and went a whoring",91,109],["H0310","after",110,115],["H1168","Baalim",116,122],["H7760","and made",124,132],["H1170","Baalberith",133,143],["H0430","their god",144,153]]},"8:34":{"text":"And the children of Israel remembered not the LORD their God, who had delivered them out of the hands of all their enemies on every side:","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H2142","remembered",27,37],["H3068","not the LORD",38,50],["H0430","their God",51,60],["H5337","who had delivered",62,79],["H3027","them out of the hands",80,101],["H0341","of all their enemies",102,122],["H5439","on every side",123,136]]},"8:35":{"text":"Neither shewed they kindness to the house of Jerubbaal, namely, Gideon, according to all the goodness which he had shewed unto Israel.","words":[["H6213","Neither shewed",0,14],["H2617","they kindness",15,28],["H1004","to the house",29,41],["H3378","of Jerubbaal",42,54],["H1439","namely, Gideon",56,70],["H2896","according to all the goodness",72,101],["H6213","which he had shewed",102,121],["H3478","unto Israel",122,133]]},"9:1":{"text":"And Abimelech the son of Jerubbaal went to Shechem unto his mother's brethren, and communed with them, and with all the family of the house of his mother's father, saying,","words":[["H0040","And Abimelech",0,13],["H1121","the son",14,21],["H3378","of Jerubbaal",22,34],["H3212","went",35,39],["H7927","to Shechem",40,50],["H0517","unto his mother's",51,68],["H0251","brethren",69,77],["H1696","and communed",79,91],["H4940","with them, and with all the family",92,126],["H1004","of the house",127,139],["H0517","of his mother's",140,155],["H0001","father",156,162],["H0559","saying",164,170]]},"9:2":{"text":"Speak, I pray you, in the ears of all the men of Shechem, Whether is better for you, either that all the sons of Jerubbaal, which are threescore and ten persons, reign over you, or that one reign over you? remember also that I am your bone and your flesh.","words":[["H1696","Speak",0,5],["H0241","I pray you, in the ears",7,30],["H1167","of all the men",31,45],["H7927","of Shechem",46,56],["H2896","Whether is better",58,75],["H1121","for you, either that all the sons",76,109],["H3378","of Jerubbaal",110,122],["H7657","which are threescore and ten",124,152],["H0376","persons",153,160],["H4910","reign",162,167],["H0259","over you, or that one",168,189],["H4910","reign",190,195],["H2142","over you? remember",196,214],["H6106","also that I am your bone",215,239],["H1320","and your flesh",240,254]]},"9:3":{"text":"And his mother's brethren spake of him in the ears of all the men of Shechem all these words: and their hearts inclined to follow Abimelech; for they said, He is our brother.","words":[["H0517","And his mother's",0,16],["H0251","brethren",17,25],["H1696","spake",26,31],["H0241","of him in the ears",32,50],["H1167","of all the men",51,65],["H7927","of Shechem",66,76],["H1697","all these words",77,92],["H3820","and their hearts",94,110],["H5186","inclined",111,119],["H0310","to follow",120,129],["H0040","Abimelech",130,139],["H0559","for they said",141,154],["H0251","He is our brother",156,173]]},"9:4":{"text":"And they gave him threescore and ten pieces of silver out of the house of Baalberith, wherewith Abimelech hired vain and light persons, which followed him.","words":[["H5414","And they gave",0,13],["H7657","him threescore and ten",14,36],["H3701","pieces of silver",37,53],["H1004","out of the house",54,70],["H1170","of Baalberith",71,84],["H0040","wherewith Abimelech",86,105],["H7936","hired",106,111],["H7386","vain",112,116],["H6348","and light",117,126],["H0582","persons",127,134],["H3212","which followed",136,150],["H0310","him",151,154]]},"9:5":{"text":"And he went unto his father's house at Ophrah, and slew his brethren the sons of Jerubbaal, being threescore and ten persons, upon one stone: notwithstanding yet Jotham the youngest son of Jerubbaal was left; for he hid himself.","words":[["H0935","And he went",0,11],["H0001","unto his father's",12,29],["H1004","house",30,35],["H6084","at Ophrah",36,45],["H2026","and slew",47,55],["H0251","his brethren",56,68],["H1121","the sons",69,77],["H3378","of Jerubbaal",78,90],["H7657","being threescore and ten",92,116],["H0376","persons",117,124],["H0259","upon one",126,134],["H0068","stone",135,140],["H3147","notwithstanding yet Jotham",142,168],["H6996","the youngest",169,181],["H1121","son",182,185],["H3378","of Jerubbaal",186,198],["H3498","was left",199,207],["H2244","for he hid",209,219]]},"9:6":{"text":"And all the men of Shechem gathered together, and all the house of Millo, and went, and made Abimelech king, by the plain of the pillar that was in Shechem.","words":[["H1167","And all the men",0,15],["H7927","of Shechem",16,26],["H0622","gathered together",27,44],["H1004","and all the house",46,63],["H4407","of Millo",64,72],["H1037","of Millo",64,72],["H3212","and went",74,82],["H4427","and made",84,92],["H0040","Abimelech",93,102],["H4428","king",103,107],["H0436","by the plain",109,121],["H5324","of the pillar",122,135],["H7927","that was in Shechem",136,155]]},"9:7":{"text":"And when they told it to Jotham, he went and stood in the top of mount Gerizim, and lifted up his voice, and cried, and said unto them, Hearken unto me, ye men of Shechem, that God may hearken unto you.","words":[["H5046","And when they told",0,18],["H3147","it to Jotham",19,31],["H3212","he went",33,40],["H5975","and stood",41,50],["H7218","in the top",51,61],["H2022","of mount",62,70],["H1630","Gerizim",71,78],["H5375","and lifted up",80,93],["H6963","his voice",94,103],["H7121","and cried",105,114],["H0559","and said",116,124],["H8085","unto them, Hearken",125,143],["H1167","unto me, ye men",144,159],["H7927","of Shechem",160,170],["H0430","that God",172,180],["H8085","may hearken",181,192]]},"9:8":{"text":"The trees went forth on a time to anoint a king over them; and they said unto the olive tree, Reign thou over us.","words":[["H6086","The trees",0,9],["H1980","went forth",10,20],["H1980","went forth",10,20],["H4886","on a time to anoint",21,40],["H4428","a king",41,47],["H0559","over them; and they said",48,72],["H2132","unto the olive tree",73,92],["H4427","Reign",94,99]]},"9:9":{"text":"But the olive tree said unto them, Should I leave my fatness, wherewith by me they honour God and man, and go to be promoted over the trees?","words":[["H2132","But the olive tree",0,18],["H0559","said",19,23],["H2308","unto them, Should I leave",24,49],["H1880","my fatness",50,60],["H3513","wherewith by me they honour",62,89],["H0430","God",90,93],["H0582","and man",94,101],["H1980","and go",103,109],["H5128","to be promoted",110,124],["H6086","over the trees",125,139]]},"9:10":{"text":"And the trees said to the fig tree, Come thou, and reign over us.","words":[["H6086","And the trees",0,13],["H0559","said",14,18],["H8384","to the fig tree",19,34],["H3212","Come",36,40],["H4427","thou, and reign",41,56]]},"9:11":{"text":"But the fig tree said unto them, Should I forsake my sweetness, and my good fruit, and go to be promoted over the trees?","words":[["H8384","But the fig tree",0,16],["H0559","said",17,21],["H2308","unto them, Should I forsake",22,49],["H4987","my sweetness",50,62],["H2896","and my good",64,75],["H8570","fruit",76,81],["H1980","and go",83,89],["H5128","to be promoted",90,104],["H6086","over the trees",105,119]]},"9:12":{"text":"Then said the trees unto the vine, Come thou, and reign over us.","words":[["H0559","Then said",0,9],["H6086","the trees",10,19],["H1612","unto the vine",20,33],["H3212","Come",35,39],["H4427","thou, and reign",40,55]]},"9:13":{"text":"And the vine said unto them, Should I leave my wine, which cheereth God and man, and go to be promoted over the trees?","words":[["H1612","And the vine",0,12],["H0559","said",13,17],["H2308","unto them, Should I leave",18,43],["H8492","my wine",44,51],["H8055","which cheereth",53,67],["H0430","God",68,71],["H0582","and man",72,79],["H1980","and go",81,87],["H5128","to be promoted",88,102],["H6086","over the trees",103,117]]},"9:14":{"text":"Then said all the trees unto the bramble, Come thou, and reign over us.","words":[["H0559","Then said",0,9],["H6086","all the trees",10,23],["H0329","unto the bramble",24,40],["H3212","Come",42,46],["H4427","thou, and reign",47,62]]},"9:15":{"text":"And the bramble said unto the trees, If in truth ye anoint me king over you, then come and put your trust in my shadow: and if not, let fire come out of the bramble, and devour the cedars of Lebanon.","words":[["H0329","And the bramble",0,15],["H0559","said",16,20],["H6086","unto the trees",21,35],["H0571","If in truth",37,48],["H4886","ye anoint",49,58],["H4428","me king",59,66],["H0935","over you, then come",67,86],["H2620","and put your trust",87,105],["H6738","in my shadow",106,118],["H0784","and if not, let fire",120,140],["H3318","come out",141,149],["H0329","of the bramble",150,164],["H0398","and devour",166,176],["H0730","the cedars",177,187],["H3844","of Lebanon",188,198]]},"9:16":{"text":"Now therefore, if ye have done truly and sincerely, in that ye have made Abimelech king, and if ye have dealt well with Jerubbaal and his house, and have done unto him according to the deserving of his hands;","words":[["H6213","Now therefore, if ye have done",0,30],["H0571","truly",31,36],["H8549","and sincerely",37,50],["H0040","in that ye have made Abimelech",52,82],["H4427","king",83,87],["H6213","and if ye have dealt",89,109],["H2896","well",110,114],["H3378","with Jerubbaal",115,129],["H1004","and his house",130,143],["H6213","and have done",145,158],["H1576","unto him according to the deserving",159,194],["H3027","of his hands",195,207]]},"9:17":{"text":"(For my father fought for you, and adventured his life far, and delivered you out of the hand of Midian:","words":[["H0001","(For my father",0,14],["H3898","fought",15,21],["H7993","for you, and adventured",22,45],["H5315","his life",46,54],["H5048","far",55,58],["H5337","and delivered",60,73],["H3027","you out of the hand",74,93],["H4080","of Midian",94,103]]},"9:18":{"text":"And ye are risen up against my father's house this day, and have slain his sons, threescore and ten persons, upon one stone, and have made Abimelech, the son of his maidservant, king over the men of Shechem, because he is your brother;)","words":[["H6965","And ye are risen up",0,19],["H0001","against my father's",20,39],["H1004","house",40,45],["H3117","this day",46,54],["H2026","and have slain",56,70],["H1121","his sons",71,79],["H7657","threescore and ten",81,99],["H0376","persons",100,107],["H0259","upon one",109,117],["H0068","stone",118,123],["H0040","and have made Abimelech",125,148],["H1121","the son",150,157],["H0519","of his maidservant",158,176],["H4427","king",178,182],["H1167","over the men",183,195],["H7927","of Shechem",196,206],["H0251","because he is your brother",208,234]]},"9:19":{"text":"If ye then have dealt truly and sincerely with Jerubbaal and with his house this day, then rejoice ye in Abimelech, and let him also rejoice in you:","words":[["H6213","If ye then have dealt",0,21],["H0571","truly",22,27],["H8549","and sincerely",28,41],["H3378","with Jerubbaal",42,56],["H1004","and with his house",57,75],["H3117","this day",76,84],["H8055","then rejoice",86,98],["H0040","ye in Abimelech",99,114],["H8055","and let him also rejoice",116,140]]},"9:20":{"text":"But if not, let fire come out from Abimelech, and devour the men of Shechem, and the house of Millo; and let fire come out from the men of Shechem, and from the house of Millo, and devour Abimelech.","words":[["H0784","But if not, let fire",0,20],["H3318","come out",21,29],["H0040","from Abimelech",30,44],["H0398","and devour",46,56],["H1167","the men",57,64],["H7927","of Shechem",65,75],["H1004","and the house",77,90],["H4407","of Millo",91,99],["H1037","of Millo",91,99],["H0784","and let fire",101,113],["H3318","come out",114,122],["H1167","from the men",123,135],["H7927","of Shechem",136,146],["H1004","and from the house",148,166],["H4407","of Millo",167,175],["H1037","of Millo",167,175],["H0398","and devour",177,187],["H0040","Abimelech",188,197]]},"9:21":{"text":"And Jotham ran away, and fled, and went to Beer, and dwelt there, for fear of Abimelech his brother.","words":[["H3147","And Jotham",0,10],["H1272","ran away",11,19],["H5127","and fled",21,29],["H3212","and went",31,39],["H0876","to Beer",40,47],["H3427","and dwelt",49,58],["H6440","there, for fear",59,74],["H0040","of Abimelech",75,87],["H0251","his brother",88,99]]},"9:22":{"text":"When Abimelech had reigned three years over Israel,","words":[["H0040","When Abimelech",0,14],["H7786","had reigned",15,26],["H7969","three",27,32],["H8141","years",33,38],["H3478","over Israel",39,50]]},"9:23":{"text":"Then God sent an evil spirit between Abimelech and the men of Shechem; and the men of Shechem dealt treacherously with Abimelech:","words":[["H0430","Then God",0,8],["H7971","sent",9,13],["H7451","an evil",14,21],["H7307","spirit",22,28],["H0040","between Abimelech",29,46],["H1167","and the men",47,58],["H7927","of Shechem",59,69],["H1167","and the men",71,82],["H7927","of Shechem",83,93],["H0898","dealt treacherously",94,113],["H0040","with Abimelech",114,128]]},"9:24":{"text":"That the cruelty done to the threescore and ten sons of Jerubbaal might come, and their blood be laid upon Abimelech their brother, which slew them; and upon the men of Shechem, which aided him in the killing of his brethren.","words":[["H2555","That the cruelty",0,16],["H7657","done to the threescore and ten",17,47],["H1121","sons",48,52],["H3378","of Jerubbaal",53,65],["H0935","might come",66,76],["H1818","and their blood",78,93],["H7760","be laid",94,101],["H0040","upon Abimelech",102,116],["H0251","their brother",117,130],["H2026","which slew",132,142],["H1167","them; and upon the men",143,165],["H7927","of Shechem",166,176],["H2388","which aided",178,189],["H3027","which aided",178,189],["H2026","him in the killing",190,208],["H0251","of his brethren",209,224]]},"9:25":{"text":"And the men of Shechem set liers in wait for him in the top of the mountains, and they robbed all that came along that way by them: and it was told Abimelech.","words":[["H1167","And the men",0,11],["H7927","of Shechem",12,22],["H7760","set",23,26],["H0693","liers in wait",27,40],["H7218","for him in the top",41,59],["H2022","of the mountains",60,76],["H1497","and they robbed",78,93],["H5674","all that came",94,107],["H1870","along that way",108,122],["H5046","by them: and it was told",123,147],["H0040","Abimelech",148,157]]},"9:26":{"text":"And Gaal the son of Ebed came with his brethren, and went over to Shechem: and the men of Shechem put their confidence in him.","words":[["H1603","And Gaal",0,8],["H1121","the son",9,16],["H5651","of Ebed",17,24],["H0935","came",25,29],["H0251","with his brethren",30,47],["H5674","and went over",49,62],["H7927","to Shechem",63,73],["H1167","and the men",75,86],["H7927","of Shechem",87,97],["H0982","put their confidence",98,118]]},"9:27":{"text":"And they went out into the fields, and gathered their vineyards, and trode the grapes, and made merry, and went into the house of their god, and did eat and drink, and cursed Abimelech.","words":[["H3318","And they went out",0,17],["H7704","into the fields",18,33],["H1219","and gathered",35,47],["H3754","their vineyards",48,63],["H1869","and trode",65,74],["H6213","the grapes, and made",75,95],["H1974","merry",96,101],["H0935","and went",103,111],["H1004","into the house",112,126],["H0430","of their god",127,139],["H0398","and did eat",141,152],["H8354","and drink",153,162],["H7043","and cursed",164,174],["H0040","Abimelech",175,184]]},"9:28":{"text":"And Gaal the son of Ebed said, Who is Abimelech, and who is Shechem, that we should serve him? is not he the son of Jerubbaal? and Zebul his officer? serve the men of Hamor the father of Shechem: for why should we serve him?","words":[["H1603","And Gaal",0,8],["H1121","the son",9,16],["H5651","of Ebed",17,24],["H0559","said",25,29],["H0040","Who is Abimelech",31,47],["H7927","and who is Shechem",49,67],["H5647","that we should serve",69,89],["H1121","him? is not he the son",90,112],["H3378","of Jerubbaal",113,125],["H2083","and Zebul",127,136],["H6496","his officer",137,148],["H5647","serve",150,155],["H0582","the men",156,163],["H2544","of Hamor",164,172],["H0001","the father",173,183],["H7927","of Shechem",184,194],["H5647","for why should we serve",196,219]]},"9:29":{"text":"And would to God this people were under my hand! then would I remove Abimelech. And he said to Abimelech, Increase thine army, and come out.","words":[["H5971","And would to God this people",0,28],["H5414","were under",29,39],["H3027","my hand",40,47],["H5493","then would I remove",49,68],["H0040","Abimelech",69,78],["H0559","And he said",80,91],["H0040","to Abimelech",92,104],["H7235","Increase",106,114],["H6635","thine army",115,125],["H3318","and come out",127,139]]},"9:30":{"text":"And when Zebul the ruler of the city heard the words of Gaal the son of Ebed, his anger was kindled.","words":[["H2083","And when Zebul",0,14],["H8269","the ruler",15,24],["H5892","of the city",25,36],["H8085","heard",37,42],["H1697","the words",43,52],["H1603","of Gaal",53,60],["H1121","the son",61,68],["H5651","of Ebed",69,76],["H0639","his anger",78,87],["H2734","was kindled",88,99]]},"9:31":{"text":"And he sent messengers unto Abimelech privily, saying, Behold, Gaal the son of Ebed and his brethren be come to Shechem; and, behold, they fortify the city against thee.","words":[["H7971","And he sent",0,11],["H4397","messengers",12,22],["H0040","unto Abimelech",23,37],["H8649","privily",38,45],["H0559","saying",47,53],["H1603","Behold, Gaal",55,67],["H1121","the son",68,75],["H5651","of Ebed",76,83],["H0251","and his brethren",84,100],["H0935","be come",101,108],["H7927","to Shechem",109,119],["H6696","and, behold, they fortify",121,146],["H5892","the city",147,155]]},"9:32":{"text":"Now therefore up by night, thou and the people that is with thee, and lie in wait in the field:","words":[["H6965","Now therefore up",0,16],["H3915","by night",17,25],["H5971","thou and the people",27,46],["H0693","that is with thee, and lie in wait",47,81],["H7704","in the field",82,94]]},"9:33":{"text":"And it shall be, that in the morning, as soon as the sun is up, thou shalt rise early, and set upon the city: and, behold, when he and the people that is with him come out against thee, then mayest thou do to them as thou shalt find occasion.","words":[["H1242","And it shall be, that in the morning",0,36],["H8121","as soon as the sun",38,56],["H2224","is up",57,62],["H7925","thou shalt rise early",64,85],["H6584","and set",87,94],["H5892","upon the city",95,108],["H5971","and, behold, when he and the people",110,145],["H3318","that is with him come out",146,171],["H6213","against thee, then mayest thou do",172,205],["H3027","to them as thou",206,221],["H4672","shalt find occasion",222,241]]},"9:34":{"text":"And Abimelech rose up, and all the people that were with him, by night, and they laid wait against Shechem in four companies.","words":[["H0040","And Abimelech",0,13],["H6965","rose up",14,21],["H5971","and all the people",23,41],["H3915","that were with him, by night",42,70],["H0693","and they laid wait",72,90],["H7927","against Shechem",91,106],["H0702","in four",107,114],["H7218","companies",115,124]]},"9:35":{"text":"And Gaal the son of Ebed went out, and stood in the entering of the gate of the city: and Abimelech rose up, and the people that were with him, from lying in wait.","words":[["H1603","And Gaal",0,8],["H1121","the son",9,16],["H5651","of Ebed",17,24],["H3318","went out",25,33],["H5975","and stood",35,44],["H6607","in the entering",45,60],["H8179","of the gate",61,72],["H5892","of the city",73,84],["H0040","and Abimelech",86,99],["H6965","rose up",100,107],["H5971","and the people",109,123],["H3993","that were with him, from lying in wait",124,162]]},"9:36":{"text":"And when Gaal saw the people, he said to Zebul, Behold, there come people down from the top of the mountains. And Zebul said unto him, Thou seest the shadow of the mountains as if they were men.","words":[["H1603","And when Gaal",0,13],["H7200","saw",14,17],["H5971","the people",18,28],["H0559","he said",30,37],["H2083","to Zebul",38,46],["H3381","Behold, there come",48,66],["H5971","people",67,73],["H3381","down",74,78],["H7218","from the top",79,91],["H2022","of the mountains",92,108],["H2083","And Zebul",110,119],["H0559","said",120,124],["H7200","unto him, Thou seest",125,145],["H6738","the shadow",146,156],["H2022","of the mountains",157,173],["H0582","as if they were men",174,193]]},"9:37":{"text":"And Gaal spake again and said, See there come people down by the middle of the land, and another company come along by the plain of Meonenim.","words":[["H1603","And Gaal",0,8],["H1696","spake",9,14],["H3254","again",15,20],["H0559","and said",21,29],["H3381","See there come",31,45],["H5971","people",46,52],["H3381","down",53,57],["H2872","by the middle",58,71],["H0776","of the land",72,83],["H0259","and another",85,96],["H7218","company",97,104],["H0935","come",105,109],["H0436","along by the plain",110,128],["H1870","of",129,131],["H6049","Meonenim",132,140]]},"9:38":{"text":"Then said Zebul unto him, Where is now thy mouth, wherewith thou saidst, Who is Abimelech, that we should serve him? is not this the people that thou hast despised? go out, I pray now, and fight with them.","words":[["H0559","Then said",0,9],["H2083","Zebul",10,15],["H0645","unto him, Where is now",16,38],["H6310","thy mouth",39,48],["H0559","wherewith thou saidst",50,71],["H0040","Who is Abimelech",73,89],["H5647","that we should serve",91,111],["H5971","him? is not this the people",112,139],["H3988","that thou hast despised",140,163],["H3318","go out",165,171],["H4994","I pray now",173,183],["H3898","and fight",185,194]]},"9:39":{"text":"And Gaal went out before the men of Shechem, and fought with Abimelech.","words":[["H1603","And Gaal",0,8],["H3318","went out",9,17],["H6440","before",18,24],["H1167","the men",25,32],["H7927","of Shechem",33,43],["H3898","and fought",45,55],["H0040","with Abimelech",56,70]]},"9:40":{"text":"And Abimelech chased him, and he fled before him, and many were overthrown and wounded, even unto the entering of the gate.","words":[["H0040","And Abimelech",0,13],["H7291","chased",14,20],["H5127","him, and he fled",21,37],["H6440","before",38,44],["H7227","him, and many",45,58],["H5307","were overthrown",59,74],["H2491","and wounded",75,86],["H6607","even unto the entering",88,110],["H8179","of the gate",111,122]]},"9:41":{"text":"And Abimelech dwelt at Arumah: and Zebul thrust out Gaal and his brethren, that they should not dwell in Shechem.","words":[["H0040","And Abimelech",0,13],["H3427","dwelt",14,19],["H0725","at Arumah",20,29],["H2083","and Zebul",31,40],["H1644","thrust out",41,51],["H1603","Gaal",52,56],["H0251","and his brethren",57,73],["H3427","that they should not dwell",75,101],["H7927","in Shechem",102,112]]},"9:42":{"text":"And it came to pass on the morrow, that the people went out into the field; and they told Abimelech.","words":[["H4283","And it came to pass on the morrow",0,33],["H5971","that the people",35,50],["H3318","went out",51,59],["H7704","into the field",60,74],["H5046","and they told",76,89],["H0040","Abimelech",90,99]]},"9:43":{"text":"And he took the people, and divided them into three companies, and laid wait in the field, and looked, and, behold, the people were come forth out of the city; and he rose up against them, and smote them.","words":[["H3947","And he took",0,11],["H5971","the people",12,22],["H2673","and divided",24,35],["H7969","them into three",36,51],["H7218","companies",52,61],["H0693","and laid wait",63,76],["H7704","in the field",77,89],["H7200","and looked",91,101],["H5971","and, behold, the people",103,126],["H3318","were come forth",127,142],["H5892","out of the city",143,158],["H6965","and he rose up",160,174],["H5221","against them, and smote",175,198]]},"9:44":{"text":"And Abimelech, and the company that was with him, rushed forward, and stood in the entering of the gate of the city: and the two other companies ran upon all the people that were in the fields, and slew them.","words":[["H0040","And Abimelech",0,13],["H7218","and the company",15,30],["H6584","that was with him, rushed forward",31,64],["H5975","and stood",66,75],["H6607","in the entering",76,91],["H8179","of the gate",92,103],["H5892","of the city",104,115],["H8147","and the two",117,128],["H7218","other companies",129,144],["H6584","ran upon",145,153],["H7704","all the people that were in the fields",154,192],["H5221","and slew",194,202]]},"9:45":{"text":"And Abimelech fought against the city all that day; and he took the city, and slew the people that was therein, and beat down the city, and sowed it with salt.","words":[["H0040","And Abimelech",0,13],["H3898","fought",14,20],["H5892","against the city",21,37],["H3117","all that day",38,50],["H3920","and he took",52,63],["H5892","the city",64,72],["H2026","and slew",74,82],["H5971","the people",83,93],["H5422","that was therein, and beat down",94,125],["H5892","the city",126,134],["H2232","and sowed",136,145],["H4417","it with salt",146,158]]},"9:46":{"text":"And when all the men of the tower of Shechem heard that, they entered into an hold of the house of the god Berith.","words":[["H1167","And when all the men",0,20],["H4026","of the tower",21,33],["H7927","of Shechem",34,44],["H8085","heard",45,50],["H0935","that, they entered",51,69],["H6877","into an hold",70,82],["H1004","of the house",83,95],["H0410","of the god",96,106],["H1286","Berith",107,113]]},"9:47":{"text":"And it was told Abimelech, that all the men of the tower of Shechem were gathered together.","words":[["H5046","And it was told",0,15],["H0040","Abimelech",16,25],["H1167","that all the men",27,43],["H4026","of the tower",44,56],["H7927","of Shechem",57,67],["H6908","were gathered together",68,90]]},"9:48":{"text":"And Abimelech gat him up to mount Zalmon, he and all the people that were with him; and Abimelech took an axe in his hand, and cut down a bough from the trees, and took it, and laid it on his shoulder, and said unto the people that were with him, What ye have seen me do, make haste, and do as I have done.","words":[["H0040","And Abimelech",0,13],["H5927","gat him up",14,24],["H2022","to mount",25,33],["H6756","Zalmon",34,40],["H5971","he and all the people",42,63],["H0040","that were with him; and Abimelech",64,97],["H3947","took",98,102],["H7134","an axe",103,109],["H3027","in his hand",110,121],["H3772","and cut down",123,135],["H7754","a bough",136,143],["H6086","from the trees",144,158],["H5375","and took",160,168],["H7760","it, and laid",169,181],["H7926","it on his shoulder",182,200],["H0559","and said",202,210],["H5971","unto the people",211,226],["H7200","that were with him, What ye have seen",227,264],["H6213","me do",265,270],["H4116","make haste",272,282],["H6213","and do",284,290],["H3644","as I",291,295]]},"9:49":{"text":"And all the people likewise cut down every man his bough, and followed Abimelech, and put them to the hold, and set the hold on fire upon them; so that all the men of the tower of Shechem died also, about a thousand men and women.","words":[["H5971","And all the people",0,18],["H3772","likewise cut down",19,36],["H0376","every man",37,46],["H7754","his bough",47,56],["H3212","and followed",58,70],["H0310","and followed",58,70],["H0040","Abimelech",71,80],["H7760","and put",82,89],["H6877","them to the hold",90,106],["H3341","and set",108,115],["H6877","the hold",116,124],["H0784","on fire",125,132],["H0582","upon them; so that all the men",133,163],["H4026","of the tower",164,176],["H7927","of Shechem",177,187],["H4191","died",188,192],["H0505","also, about a thousand",193,215],["H0376","men",216,219],["H0802","and women",220,229]]},"9:50":{"text":"Then went Abimelech to Thebez, and encamped against Thebez, and took it.","words":[["H3212","Then went",0,9],["H0040","Abimelech",10,19],["H8405","to Thebez",20,29],["H2583","and encamped",31,43],["H8405","against Thebez",44,58],["H3920","and took",60,68]]},"9:51":{"text":"But there was a strong tower within the city, and thither fled all the men and women, and all they of the city, and shut it to them, and gat them up to the top of the tower.","words":[["H5797","But there was a strong",0,22],["H4026","tower",23,28],["H8432","within",29,35],["H5892","the city",36,44],["H5127","and thither fled",46,62],["H0582","all the men",63,74],["H0802","and women",75,84],["H1167","and all they",86,98],["H5892","of the city",99,110],["H5462","and shut",112,120],["H5927","it to them, and gat them up",121,148],["H1406","to the top",149,159],["H4026","of the tower",160,172]]},"9:52":{"text":"And Abimelech came unto the tower, and fought against it, and went hard unto the door of the tower to burn it with fire.","words":[["H0040","And Abimelech",0,13],["H0935","came",14,18],["H4026","unto the tower",19,33],["H3898","and fought",35,45],["H5066","against it, and went hard",46,71],["H6607","unto the door",72,85],["H4026","of the tower",86,98],["H8313","to burn",99,106],["H0784","it with fire",107,119]]},"9:53":{"text":"And a certain woman cast a piece of a millstone upon Abimelech's head, and all to brake his skull.","words":[["H0259","And a certain",0,13],["H0802","woman",14,19],["H7993","cast",20,24],["H6400","a piece",25,32],["H7393","of a millstone",33,47],["H0040","upon Abimelech's",48,64],["H7218","head",65,69],["H7533","and all to brake",71,87],["H1538","his skull",88,97]]},"9:54":{"text":"Then he called hastily unto the young man his armourbearer, and said unto him, Draw thy sword, and slay me, that men say not of me, A woman slew him. And his young man thrust him through, and he died.","words":[["H7121","Then he called",0,14],["H4120","hastily",15,22],["H5288","unto the young man",23,41],["H5375","his armourbearer",42,58],["H3627","his armourbearer",42,58],["H0559","and said",60,68],["H8025","unto him, Draw",69,83],["H2719","thy sword",84,93],["H4191","and slay",95,103],["H0559","me, that men say",104,120],["H0802","not of me, A woman",121,139],["H2026","slew",140,144],["H5288","him. And his young man",145,167],["H1856","thrust him through",168,186],["H4191","and he died",188,199]]},"9:55":{"text":"And when the men of Israel saw that Abimelech was dead, they departed every man unto his place.","words":[["H0376","And when the men",0,16],["H3478","of Israel",17,26],["H7200","saw",27,30],["H0040","that Abimelech",31,45],["H4191","was dead",46,54],["H3212","they departed",56,69],["H0376","every man",70,79],["H4725","unto his place",80,94]]},"9:56":{"text":"Thus God rendered the wickedness of Abimelech, which he did unto his father, in slaying his seventy brethren:","words":[["H0430","Thus God",0,8],["H7725","rendered",9,17],["H7451","the wickedness",18,32],["H0040","of Abimelech",33,45],["H6213","which he did",47,59],["H0001","unto his father",60,75],["H2026","in slaying",77,87],["H7657","his seventy",88,99],["H0251","brethren",100,108]]},"9:57":{"text":"And all the evil of the men of Shechem did God render upon their heads: and upon them came the curse of Jotham the son of Jerubbaal.","words":[["H7451","And all the evil",0,16],["H0582","of the men",17,27],["H7927","of Shechem",28,38],["H0430","did God",39,46],["H7725","render",47,53],["H7218","upon their heads",54,70],["H0935","and upon them came",72,90],["H7045","the curse",91,100],["H3147","of Jotham",101,110],["H1121","the son",111,118],["H3378","of Jerubbaal",119,131]]},"10:1":{"text":"And after Abimelech there arose to defend Israel Tola the son of Puah, the son of Dodo, a man of Issachar; and he dwelt in Shamir in mount Ephraim.","words":[["H0310","And after",0,9],["H0040","Abimelech",10,19],["H6965","there arose",20,31],["H3467","to defend",32,41],["H3478","Israel",42,48],["H8439","Tola",49,53],["H1121","the son",54,61],["H6312","of Puah",62,69],["H1121","the son",71,78],["H1734","of Dodo",79,86],["H0376","a man",88,93],["H3485","of Issachar",94,105],["H3427","and he dwelt",107,119],["H8069","in Shamir",120,129],["H2022","in mount",130,138],["H0669","Ephraim",139,146]]},"10:2":{"text":"And he judged Israel twenty and three years, and died, and was buried in Shamir.","words":[["H8199","And he judged",0,13],["H3478","Israel",14,20],["H6242","twenty",21,27],["H7969","and three",28,37],["H8141","years",38,43],["H4191","and died",45,53],["H6912","and was buried",55,69],["H8069","in Shamir",70,79]]},"10:3":{"text":"And after him arose Jair, a Gileadite, and judged Israel twenty and two years.","words":[["H0310","And after",0,9],["H6965","him arose",10,19],["H2971","Jair",20,24],["H1569","a Gileadite",26,37],["H8199","and judged",39,49],["H3478","Israel",50,56],["H6242","twenty",57,63],["H8147","and two",64,71],["H8141","years",72,77]]},"10:4":{"text":"And he had thirty sons that rode on thirty ass colts, and they had thirty cities, which are called Havothjair unto this day, which are in the land of Gilead.","words":[["H7970","And he had thirty",0,17],["H1121","sons",18,22],["H7392","that rode",23,32],["H7970","on thirty",33,42],["H5895","ass colts",43,52],["H7970","and they had thirty",54,73],["H5892","cities",74,80],["H7121","which are called",82,98],["H2334","Havothjair",99,109],["H3117","unto this day",110,123],["H0776","which are in the land",125,146],["H1568","of Gilead",147,156]]},"10:5":{"text":"And Jair died, and was buried in Camon.","words":[["H2971","And Jair",0,8],["H4191","died",9,13],["H6912","and was buried",15,29],["H7056","in Camon",30,38]]},"10:6":{"text":"And the children of Israel did evil again in the sight of the LORD, and served Baalim, and Ashtaroth, and the gods of Syria, and the gods of Zidon, and the gods of Moab, and the gods of the children of Ammon, and the gods of the Philistines, and forsook the LORD, and served not him.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6213","did",27,30],["H7451","evil",31,35],["H3254","again",36,41],["H5869","in the sight",42,54],["H3068","of the LORD",55,66],["H5647","and served",68,78],["H1168","Baalim",79,85],["H6252","and Ashtaroth",87,100],["H0430","and the gods",102,114],["H0758","of Syria",115,123],["H0430","and the gods",125,137],["H6721","of Zidon",138,146],["H0430","and the gods",148,160],["H4124","of Moab",161,168],["H0430","and the gods",170,182],["H1121","of the children",183,198],["H5983","of Ammon",199,207],["H0430","and the gods",209,221],["H6430","of the Philistines",222,240],["H5800","and forsook",242,253],["H3068","the LORD",254,262],["H5647","and served",264,274]]},"10:7":{"text":"And the anger of the LORD was hot against Israel, and he sold them into the hands of the Philistines, and into the hands of the children of Ammon.","words":[["H0639","And the anger",0,13],["H3068","of the LORD",14,25],["H2734","was hot",26,33],["H3478","against Israel",34,48],["H4376","and he sold",50,61],["H3027","them into the hands",62,81],["H6430","of the Philistines",82,100],["H3027","and into the hands",102,120],["H1121","of the children",121,136],["H5983","of Ammon",137,145]]},"10:8":{"text":"And that year they vexed and oppressed the children of Israel: eighteen years, all the children of Israel that were on the other side Jordan in the land of the Amorites, which is in Gilead.","words":[["H8141","And that year",0,13],["H7492","they vexed",14,24],["H7533","and oppressed",25,38],["H1121","the children",39,51],["H3478","of Israel",52,61],["H8083","eighteen",63,71],["H6240","eighteen",63,71],["H8141","years",72,77],["H1121","all the children",79,95],["H3478","of Israel",96,105],["H5676","that were on the other side",106,133],["H3383","Jordan",134,140],["H0776","in the land",141,152],["H0567","of the Amorites",153,168],["H1568","which is in Gilead",170,188]]},"10:9":{"text":"Moreover the children of Ammon passed over Jordan to fight also against Judah, and against Benjamin, and against the house of Ephraim; so that Israel was sore distressed.","words":[["H1121","Moreover the children",0,21],["H5983","of Ammon",22,30],["H5674","passed over",31,42],["H3383","Jordan",43,49],["H3898","to fight",50,58],["H3063","also against Judah",59,77],["H1144","and against Benjamin",79,99],["H1004","and against the house",101,122],["H0669","of Ephraim",123,133],["H3478","so that Israel",135,149],["H3966","was sore",150,158],["H3334","distressed",159,169]]},"10:10":{"text":"And the children of Israel cried unto the LORD, saying, We have sinned against thee, both because we have forsaken our God, and also served Baalim.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H2199","cried",27,32],["H3068","unto the LORD",33,46],["H0559","saying",48,54],["H2398","We have sinned",56,70],["H5800","against thee, both because we have forsaken",71,114],["H0430","our God",115,122],["H5647","and also served",124,139],["H1168","Baalim",140,146]]},"10:11":{"text":"And the LORD said unto the children of Israel, Did not I deliver you from the Egyptians, and from the Amorites, from the children of Ammon, and from the Philistines?","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H1121","unto the children",18,35],["H3478","of Israel",36,45],["H4714","Did not I deliver you from the Egyptians",47,87],["H0567","and from the Amorites",89,110],["H1121","from the children",112,129],["H5983","of Ammon",130,138],["H6430","and from the Philistines",140,164]]},"10:12":{"text":"The Zidonians also, and the Amalekites, and the Maonites, did oppress you; and ye cried to me, and I delivered you out of their hand.","words":[["H6722","The Zidonians",0,13],["H6002","also, and the Amalekites",14,38],["H4584","and the Maonites",40,56],["H3905","did oppress",58,69],["H6817","you; and ye cried",70,87],["H3467","to me, and I delivered",88,110],["H3027","you out of their hand",111,132]]},"10:13":{"text":"Yet ye have forsaken me, and served other gods: wherefore I will deliver you no more.","words":[["H5800","Yet ye have forsaken",0,20],["H5647","me, and served",21,35],["H0312","other",36,41],["H0430","gods",42,46],["H3467","wherefore I will deliver",48,72],["H3254","you no more",73,84]]},"10:14":{"text":"Go and cry unto the gods which ye have chosen; let them deliver you in the time of your tribulation.","words":[["H3212","Go",0,2],["H2199","and cry",3,10],["H0430","unto the gods",11,24],["H0977","which ye have chosen",25,45],["H1992","let them",47,55],["H3467","deliver",56,63],["H6256","you in the time",64,79],["H6869","of your tribulation",80,99]]},"10:15":{"text":"And the children of Israel said unto the LORD, We have sinned: do thou unto us whatsoever seemeth good unto thee; deliver us only, we pray thee, this day.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H0559","said",27,31],["H3068","unto the LORD",32,45],["H2398","We have sinned",47,61],["H6213","do",63,65],["H5869","thou unto us whatsoever seemeth",66,97],["H2896","good",98,102],["H5337","unto thee; deliver",103,121],["H3117","us only, we pray thee, this day",122,153]]},"10:16":{"text":"And they put away the strange gods from among them, and served the LORD: and his soul was grieved for the misery of Israel.","words":[["H5493","And they put away",0,17],["H5236","the strange",18,29],["H0430","gods",30,34],["H7130","from among",35,45],["H5647","them, and served",46,62],["H3068","the LORD",63,71],["H5315","and his soul",73,85],["H7114","was grieved",86,97],["H5999","for the misery",98,112],["H3478","of Israel",113,122]]},"10:17":{"text":"Then the children of Ammon were gathered together, and encamped in Gilead. And the children of Israel assembled themselves together, and encamped in Mizpeh.","words":[["H1121","Then the children",0,17],["H5983","of Ammon",18,26],["H6817","were gathered together",27,49],["H2583","and encamped",51,63],["H1568","in Gilead",64,73],["H1121","And the children",75,91],["H3478","of Israel",92,101],["H0622","assembled themselves together",102,131],["H2583","and encamped",133,145],["H4709","in Mizpeh",146,155]]},"10:18":{"text":"And the people and princes of Gilead said one to another, What man is he that will begin to fight against the children of Ammon? he shall be head over all the inhabitants of Gilead.","words":[["H5971","And the people",0,14],["H8269","and princes",15,26],["H1568","of Gilead",27,36],["H0559","said",37,41],["H0376","one",42,45],["H7453","to another",46,56],["H0376","What man",58,66],["H2490","is he that will begin",67,88],["H3898","to fight",89,97],["H1121","against the children",98,118],["H5983","of Ammon",119,127],["H7218","he shall be head",129,145],["H3427","over all the inhabitants",146,170],["H1568","of Gilead",171,180]]},"11:1":{"text":"Now Jephthah the Gileadite was a mighty man of valour, and he was the son of an harlot: and Gilead begat Jephthah.","words":[["H3316","Now Jephthah",0,12],["H1569","the Gileadite",13,26],["H1368","was a mighty man",27,43],["H2428","of valour",44,53],["H1121","and he was the son",55,73],["H0802","of an harlot",74,86],["H2181","of an harlot",74,86],["H1568","and Gilead",88,98],["H3205","begat",99,104],["H3316","Jephthah",105,113]]},"11:2":{"text":"And Gilead's wife bare him sons; and his wife's sons grew up, and they thrust out Jephthah, and said unto him, Thou shalt not inherit in our father's house; for thou art the son of a strange woman.","words":[["H1568","And Gilead's",0,12],["H0802","wife",13,17],["H3205","bare",18,22],["H1121","him sons",23,31],["H0802","and his wife's",33,47],["H1121","sons",48,52],["H1431","grew up",53,60],["H1644","and they thrust out",62,81],["H3316","Jephthah",82,90],["H0559","and said",92,100],["H5157","unto him, Thou shalt not inherit",101,133],["H0001","in our father's",134,149],["H1004","house",150,155],["H1121","for thou art the son",157,177],["H0312","of a strange",178,190],["H0802","woman",191,196]]},"11:3":{"text":"Then Jephthah fled from his brethren, and dwelt in the land of Tob: and there were gathered vain men to Jephthah, and went out with him.","words":[["H3316","Then Jephthah",0,13],["H1272","fled",14,18],["H6440","from",19,23],["H0251","his brethren",24,36],["H3427","and dwelt",38,47],["H0776","in the land",48,59],["H2897","of Tob",60,66],["H3950","and there were gathered",68,91],["H7386","vain",92,96],["H0582","men",97,100],["H3316","to Jephthah",101,112],["H3318","and went out",114,126]]},"11:4":{"text":"And it came to pass in process of time, that the children of Ammon made war against Israel.","words":[["H3117","And it came to pass in process of time",0,38],["H1121","that the children",40,57],["H5983","of Ammon",58,66],["H3898","made war",67,75],["H3478","against Israel",76,90]]},"11:5":{"text":"And it was so, that when the children of Ammon made war against Israel, the elders of Gilead went to fetch Jephthah out of the land of Tob:","words":[["H1121","And it was so, that when the children",0,37],["H5983","of Ammon",38,46],["H3898","made war",47,55],["H3478","against Israel",56,70],["H2205","the elders",72,82],["H1568","of Gilead",83,92],["H3212","went",93,97],["H3947","to fetch",98,106],["H3316","Jephthah",107,115],["H0776","out of the land",116,131],["H2897","of Tob",132,138]]},"11:6":{"text":"And they said unto Jephthah, Come, and be our captain, that we may fight with the children of Ammon.","words":[["H0559","And they said",0,13],["H3316","unto Jephthah",14,27],["H3212","Come",29,33],["H7101","and be our captain",35,53],["H3898","that we may fight",55,72],["H1121","with the children",73,90],["H5983","of Ammon",91,99]]},"11:7":{"text":"And Jephthah said unto the elders of Gilead, Did not ye hate me, and expel me out of my father's house? and why are ye come unto me now when ye are in distress?","words":[["H3316","And Jephthah",0,12],["H0559","said",13,17],["H2205","unto the elders",18,33],["H1568","of Gilead",34,43],["H8130","Did not ye hate",45,60],["H1644","me, and expel",61,74],["H0001","me out of my father's",75,96],["H1004","house",97,102],["H0935","and why are ye come",104,123],["H6887","unto me now when ye are in distress",124,159]]},"11:8":{"text":"And the elders of Gilead said unto Jephthah, Therefore we turn again to thee now, that thou mayest go with us, and fight against the children of Ammon, and be our head over all the inhabitants of Gilead.","words":[["H2205","And the elders",0,14],["H1568","of Gilead",15,24],["H0559","said",25,29],["H3316","unto Jephthah",30,43],["H7725","Therefore we turn again",45,68],["H1980","to thee now, that thou mayest go",69,101],["H3898","with us, and fight",102,120],["H1121","against the children",121,141],["H5983","of Ammon",142,150],["H7218","and be our head",152,167],["H3427","over all the inhabitants",168,192],["H1568","of Gilead",193,202]]},"11:9":{"text":"And Jephthah said unto the elders of Gilead, If ye bring me home again to fight against the children of Ammon, and the LORD deliver them before me, shall I be your head?","words":[["H3316","And Jephthah",0,12],["H0559","said",13,17],["H2205","unto the elders",18,33],["H1568","of Gilead",34,43],["H7725","If ye bring me home again",45,70],["H3898","to fight",71,79],["H1121","against the children",80,100],["H5983","of Ammon",101,109],["H3068","and the LORD",111,123],["H5414","deliver",124,131],["H6440","them before",132,143],["H7218","me, shall I be your head",144,168]]},"11:10":{"text":"And the elders of Gilead said unto Jephthah, The LORD be witness between us, if we do not so according to thy words.","words":[["H2205","And the elders",0,14],["H1568","of Gilead",15,24],["H0559","said",25,29],["H3316","unto Jephthah",30,43],["H3068","The LORD",45,53],["H8085","be witness",54,64],["H6213","between us, if we do",65,85],["H1697","not so according to thy words",86,115]]},"11:11":{"text":"Then Jephthah went with the elders of Gilead, and the people made him head and captain over them: and Jephthah uttered all his words before the LORD in Mizpeh.","words":[["H3316","Then Jephthah",0,13],["H3212","went",14,18],["H2205","with the elders",19,34],["H1568","of Gilead",35,44],["H5971","and the people",46,60],["H7760","made",61,65],["H7218","him head",66,74],["H7101","and captain",75,86],["H3316","over them: and Jephthah",87,110],["H1696","uttered",111,118],["H1697","all his words",119,132],["H6440","before",133,139],["H3068","the LORD",140,148],["H4709","in Mizpeh",149,158]]},"11:12":{"text":"And Jephthah sent messengers unto the king of the children of Ammon, saying, What hast thou to do with me, that thou art come against me to fight in my land?","words":[["H3316","And Jephthah",0,12],["H7971","sent",13,17],["H4397","messengers",18,28],["H4428","unto the king",29,42],["H1121","of the children",43,58],["H5983","of Ammon",59,67],["H0559","saying",69,75],["H0935","What hast thou to do with me, that thou art come",77,125],["H3898","against me to fight",126,145],["H0776","in my land",146,156]]},"11:13":{"text":"And the king of the children of Ammon answered unto the messengers of Jephthah, Because Israel took away my land, when they came up out of Egypt, from Arnon even unto Jabbok, and unto Jordan: now therefore restore those lands again peaceably.","words":[["H4428","And the king",0,12],["H1121","of the children",13,28],["H5983","of Ammon",29,37],["H0559","answered",38,46],["H4397","unto the messengers",47,66],["H3316","of Jephthah",67,78],["H3478","Because Israel",80,94],["H3947","took away",95,104],["H0776","my land",105,112],["H5927","when they came up",114,131],["H4714","out of Egypt",132,144],["H0769","from Arnon",146,156],["H2999","even unto Jabbok",157,173],["H3383","and unto Jordan",175,190],["H7725","now therefore restore those lands again",192,231],["H7965","peaceably",232,241]]},"11:14":{"text":"And Jephthah sent messengers again unto the king of the children of Ammon:","words":[["H3316","And Jephthah",0,12],["H7971","sent",13,17],["H4397","messengers",18,28],["H3254","again",29,34],["H4428","unto the king",35,48],["H1121","of the children",49,64],["H5983","of Ammon",65,73]]},"11:15":{"text":"And said unto him, Thus saith Jephthah, Israel took not away the land of Moab, nor the land of the children of Ammon:","words":[["H0559","And said",0,8],["H0559","unto him, Thus saith",9,29],["H3316","Jephthah",30,38],["H3478","Israel",40,46],["H3947","took not away",47,60],["H0776","the land",61,69],["H4124","of Moab",70,77],["H0776","nor the land",79,91],["H1121","of the children",92,107],["H5983","of Ammon",108,116]]},"11:16":{"text":"But when Israel came up from Egypt, and walked through the wilderness unto the Red sea, and came to Kadesh;","words":[["H3478","But when Israel",0,15],["H5927","came up",16,23],["H4714","from Egypt",24,34],["H3212","and walked",36,46],["H4057","through the wilderness",47,69],["H5488","unto the Red",70,82],["H3220","sea",83,86],["H0935","and came",88,96],["H6946","to Kadesh",97,106]]},"11:17":{"text":"Then Israel sent messengers unto the king of Edom, saying, Let me, I pray thee, pass through thy land: but the king of Edom would not hearken thereto. And in like manner they sent unto the king of Moab: but he would not consent: and Israel abode in Kadesh.","words":[["H3478","Then Israel",0,11],["H7971","sent",12,16],["H4397","messengers",17,27],["H4428","unto the king",28,41],["H0123","of Edom",42,49],["H0559","saying",51,57],["H5674","Let me, I pray thee, pass through",59,92],["H0776","thy land",93,101],["H4428","but the king",103,115],["H0123","of Edom",116,123],["H8085","would not hearken",124,141],["H7971","thereto. And in like manner they sent",142,179],["H4428","unto the king",180,193],["H4124","of Moab",194,201],["H0014","but he would",203,215],["H3478","not consent: and Israel",216,239],["H3427","abode",240,245],["H6946","in Kadesh",246,255]]},"11:18":{"text":"Then they went along through the wilderness, and compassed the land of Edom, and the land of Moab, and came by the east side of the land of Moab, and pitched on the other side of Arnon, but came not within the border of Moab: for Arnon was the border of Moab.","words":[["H3212","Then they went along",0,20],["H4057","through the wilderness",21,43],["H5437","and compassed",45,58],["H0776","the land",59,67],["H0123","of Edom",68,75],["H0776","and the land",77,89],["H4124","of Moab",90,97],["H0935","and came",99,107],["H4217","by the east side",108,124],["H8121","by the east side",108,124],["H0776","of the land",125,136],["H4124","of Moab",137,144],["H2583","and pitched",146,157],["H5676","on the other side",158,175],["H0769","of Arnon",176,184],["H0935","but came",186,194],["H1366","not within the border",195,216],["H4124","of Moab",217,224],["H0769","for Arnon",226,235],["H1366","was the border",236,250],["H4124","of Moab",251,258]]},"11:19":{"text":"And Israel sent messengers unto Sihon king of the Amorites, the king of Heshbon; and Israel said unto him, Let us pass, we pray thee, through thy land into my place.","words":[["H3478","And Israel",0,10],["H7971","sent",11,15],["H4397","messengers",16,26],["H5511","unto Sihon",27,37],["H4428","king",38,42],["H0567","of the Amorites",43,58],["H4428","the king",60,68],["H2809","of Heshbon",69,79],["H3478","and Israel",81,91],["H0559","said",92,96],["H5674","unto him, Let us pass",97,118],["H0776","we pray thee, through thy land",120,150],["H5704","into",151,155],["H4725","my place",156,164]]},"11:20":{"text":"But Sihon trusted not Israel to pass through his coast: but Sihon gathered all his people together, and pitched in Jahaz, and fought against Israel.","words":[["H5511","But Sihon",0,9],["H0539","trusted",10,17],["H3478","not Israel",18,28],["H5674","to pass",29,36],["H1366","through his coast",37,54],["H5511","but Sihon",56,65],["H0622","gathered",66,74],["H5971","all his people",75,89],["H0622","together",90,98],["H2583","and pitched",100,111],["H3096","in Jahaz",112,120],["H3898","and fought",122,132],["H3478","against Israel",133,147]]},"11:21":{"text":"And the LORD God of Israel delivered Sihon and all his people into the hand of Israel, and they smote them: so Israel possessed all the land of the Amorites, the inhabitants of that country.","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H3478","of Israel",17,26],["H5414","delivered",27,36],["H5511","Sihon",37,42],["H5971","and all his people",43,61],["H3027","into the hand",62,75],["H3478","of Israel",76,85],["H5221","and they smote",87,101],["H3478","them: so Israel",102,117],["H3423","possessed",118,127],["H0776","all the land",128,140],["H0567","of the Amorites",141,156],["H3427","the inhabitants",158,173],["H0776","of that country",174,189]]},"11:22":{"text":"And they possessed all the coasts of the Amorites, from Arnon even unto Jabbok, and from the wilderness even unto Jordan.","words":[["H3423","And they possessed",0,18],["H1366","all the coasts",19,33],["H0567","of the Amorites",34,49],["H0769","from Arnon",51,61],["H2999","even unto Jabbok",62,78],["H4057","and from the wilderness",80,103],["H3383","even unto Jordan",104,120]]},"11:23":{"text":"So now the LORD God of Israel hath dispossessed the Amorites from before his people Israel, and shouldest thou possess it?","words":[["H3068","So now the LORD",0,15],["H0430","God",16,19],["H3478","of Israel",20,29],["H3423","hath dispossessed",30,47],["H0567","the Amorites",48,60],["H6440","from before",61,72],["H5971","his people",73,83],["H3478","Israel",84,90],["H3423","and shouldest thou possess",92,118]]},"11:24":{"text":"Wilt not thou possess that which Chemosh thy god giveth thee to possess? So whomsoever the LORD our God shall drive out from before us, them will we possess.","words":[["H3423","Wilt not thou possess",0,21],["H3645","that which Chemosh",22,40],["H0430","thy god",41,48],["H3423","giveth thee to possess",49,71],["H3068","So whomsoever the LORD",73,95],["H0430","our God",96,103],["H3423","shall drive out",104,119],["H6440","from before",120,131],["H3423","us, them will we possess",132,156]]},"11:25":{"text":"And now art thou any thing better than Balak the son of Zippor, king of Moab? did he ever strive against Israel, or did he ever fight against them,","words":[["H2896","And now art thou any thing better",0,33],["H1111","than Balak",34,44],["H1121","the son",45,52],["H6834","of Zippor",53,62],["H4428","king",64,68],["H4124","of Moab",69,76],["H7378","did he ever",78,89],["H7378","strive",90,96],["H3478","against Israel",97,111],["H3898","or did he ever",113,127],["H3898","fight",128,133]]},"11:26":{"text":"While Israel dwelt in Heshbon and her towns, and in Aroer and her towns, and in all the cities that be along by the coasts of Arnon, three hundred years? why therefore did ye not recover them within that time?","words":[["H3478","While Israel",0,12],["H3427","dwelt",13,18],["H2809","in Heshbon",19,29],["H1323","and her towns",30,43],["H6177","and in Aroer",45,57],["H1323","and her towns",58,71],["H5892","and in all the cities",73,94],["H3027","that be along by the coasts",95,122],["H0769","of Arnon",123,131],["H7969","three",133,138],["H3967","hundred",139,146],["H8141","years",147,152],["H5337","why therefore did ye not recover",154,186],["H6256","them within that time",187,208]]},"11:27":{"text":"Wherefore I have not sinned against thee, but thou doest me wrong to war against me: the LORD the Judge be judge this day between the children of Israel and the children of Ammon.","words":[["H2398","Wherefore I have not sinned",0,27],["H6213","against thee, but thou doest",28,56],["H0853","",-1,-1],["H7451","me wrong",57,65],["H3898","to war",66,72],["H3068","against me: the LORD",73,93],["H8199","the Judge",94,103],["H8199","be judge",104,112],["H3117","this day",113,121],["H1121","between the children",122,142],["H3478","of Israel",143,152],["H1121","and the children",153,169],["H5983","of Ammon",170,178]]},"11:28":{"text":"Howbeit the king of the children of Ammon hearkened not unto the words of Jephthah which he sent him.","words":[["H4428","Howbeit the king",0,16],["H1121","of the children",17,32],["H5983","of Ammon",33,41],["H8085","hearkened",42,51],["H1697","not unto the words",52,70],["H3316","of Jephthah",71,82],["H7971","which he sent",83,96]]},"11:29":{"text":"Then the Spirit of the LORD came upon Jephthah, and he passed over Gilead, and Manasseh, and passed over Mizpeh of Gilead, and from Mizpeh of Gilead he passed over unto the children of Ammon.","words":[["H7307","Then the Spirit",0,15],["H3068","of the LORD",16,27],["H3316","came upon Jephthah",28,46],["H5674","and he passed over",48,66],["H1568","Gilead",67,73],["H4519","and Manasseh",75,87],["H5674","and passed over",89,104],["H4708","Mizpeh",105,111],["H1568","of Gilead",112,121],["H4708","and from Mizpeh",123,138],["H1568","of Gilead",139,148],["H5674","he passed over",149,163],["H1121","unto the children",164,181],["H5983","of Ammon",182,190]]},"11:30":{"text":"And Jephthah vowed a vow unto the LORD, and said, If thou shalt without fail deliver the children of Ammon into mine hands,","words":[["H3316","And Jephthah",0,12],["H5087","vowed",13,18],["H5088","a vow",19,24],["H3068","unto the LORD",25,38],["H0559","and said",40,48],["H5414","If thou shalt without fail",50,76],["H5414","deliver",77,84],["H1121","the children",85,97],["H5983","of Ammon",98,106],["H3027","into mine hands",107,122]]},"11:31":{"text":"Then it shall be, that whatsoever cometh forth of the doors of my house to meet me, when I return in peace from the children of Ammon, shall surely be the LORD'S, and I will offer it up for a burnt offering.","words":[["H3318","Then it shall be, that whatsoever",0,33],["H3318","cometh forth",34,46],["H1817","of the doors",47,59],["H1004","of my house",60,71],["H7125","to meet",72,79],["H7725","me, when I return",80,97],["H7965","in peace",98,106],["H1121","from the children",107,124],["H5983","of Ammon",125,133],["H3068","shall surely be the LORD'S",135,161],["H5927","and I will offer it up",163,185],["H5930","for a burnt offering",186,206]]},"11:32":{"text":"So Jephthah passed over unto the children of Ammon to fight against them; and the LORD delivered them into his hands.","words":[["H3316","So Jephthah",0,11],["H5674","passed over",12,23],["H1121","unto the children",24,41],["H5983","of Ammon",42,50],["H3898","to fight",51,59],["H3068","against them; and the LORD",60,86],["H5414","delivered",87,96],["H3027","them into his hands",97,116]]},"11:33":{"text":"And he smote them from Aroer, even till thou come to Minnith, even twenty cities, and unto the plain of the vineyards, with a very great slaughter. Thus the children of Ammon were subdued before the children of Israel.","words":[["H5221","And he smote",0,12],["H6177","them from Aroer",13,28],["H0935","even till thou come",30,49],["H4511","to Minnith",50,60],["H6242","even twenty",62,73],["H5892","cities",74,80],["H0058","and unto the plain",82,100],["H3754","of the vineyards",101,117],["H0064","of the vineyards",101,117],["H3966","with a very",119,130],["H1419","great",131,136],["H4347","slaughter",137,146],["H1121","Thus the children",148,165],["H5983","of Ammon",166,174],["H3665","were subdued",175,187],["H6440","before",188,194],["H1121","the children",195,207],["H3478","of Israel",208,217]]},"11:34":{"text":"And Jephthah came to Mizpeh unto his house, and, behold, his daughter came out to meet him with timbrels and with dances: and she was his only child; beside her he had neither son nor daughter.","words":[["H3316","And Jephthah",0,12],["H0935","came",13,17],["H4709","to Mizpeh",18,27],["H1004","unto his house",28,42],["H1323","and, behold, his daughter",44,69],["H3318","came out",70,78],["H7125","to meet",79,86],["H8596","him with timbrels",87,104],["H4246","and with dances",105,120],["H3173","and she was his only child",122,148],["H1121","beside her he had neither son",150,179],["H0176","nor",180,183],["H1323","daughter",184,192]]},"11:35":{"text":"And it came to pass, when he saw her, that he rent his clothes, and said, Alas, my daughter! thou hast brought me very low, and thou art one of them that trouble me: for I have opened my mouth unto the LORD, and I cannot go back.","words":[["H7200","And it came to pass, when he saw",0,32],["H7167","her, that he rent",33,50],["H0899","his clothes",51,62],["H0559","and said",64,72],["H0162","Alas",74,78],["H1323","my daughter",80,91],["H3766","thou hast brought",93,110],["H3766","me very",111,118],["H3766","low",119,122],["H5916","and thou art one of them that trouble",124,161],["H6475","me: for I have opened",162,183],["H6310","my mouth",184,192],["H3068","unto the LORD",193,206],["H3201","and I cannot",208,220],["H7725","go back",221,228]]},"11:36":{"text":"And she said unto him, My father, if thou hast opened thy mouth unto the LORD, do to me according to that which hath proceeded out of thy mouth; forasmuch as the LORD hath taken vengeance for thee of thine enemies, even of the children of Ammon.","words":[["H0559","And she said",0,12],["H0001","unto him, My father",13,32],["H6475","if thou hast opened",34,53],["H6310","thy mouth",54,63],["H3068","unto the LORD",64,77],["H6213","do",79,81],["H0834","to me according to that which",82,111],["H3318","hath proceeded",112,126],["H6310","out of thy mouth",127,143],["H0310","forasmuch",145,154],["H3068","as the LORD",155,166],["H6213","hath taken",167,177],["H5360","vengeance",178,187],["H0341","for thee of thine enemies",188,213],["H1121","even of the children",215,235],["H5983","of Ammon",236,244]]},"11:37":{"text":"And she said unto her father, Let this thing be done for me: let me alone two months, that I may go up and down upon the mountains, and bewail my virginity, I and my fellows.","words":[["H0559","And she said",0,12],["H0001","unto her father",13,28],["H1697","Let this thing",30,44],["H6213","be done",45,52],["H7503","for me: let me alone",53,73],["H8147","two",74,77],["H2320","months",78,84],["H3212","that I may go up",86,102],["H3381","and down",103,111],["H2022","upon the mountains",112,130],["H1058","and bewail",132,142],["H1331","my virginity",143,155],["H7464","I and my fellows",157,173],["H7474","I and my fellows",157,173]]},"11:38":{"text":"And he said, Go. And he sent her away for two months: and she went with her companions, and bewailed her virginity upon the mountains.","words":[["H0559","And he said",0,11],["H3212","Go",13,15],["H7971","And he sent her away",17,37],["H8147","for two",38,45],["H2320","months",46,52],["H3212","and she went",54,66],["H7464","with her companions",67,86],["H1058","and bewailed",88,100],["H1331","her virginity",101,114],["H2022","upon the mountains",115,133]]},"11:39":{"text":"And it came to pass at the end of two months, that she returned unto her father, who did with her according to his vow which he had vowed: and she knew no man. And it was a custom in Israel,","words":[["H7093","And it came to pass at the end",0,30],["H8147","of two",31,37],["H2320","months",38,44],["H7725","that she returned",46,63],["H0001","unto her father",64,79],["H6213","who did",81,88],["H5088","with her according to his vow",89,118],["H5087","which he had vowed",119,137],["H3045","and she knew",139,151],["H0376","no man",152,158],["H2706","And it was a custom",160,179],["H3478","in Israel",180,189]]},"11:40":{"text":"That the daughters of Israel went yearly to lament the daughter of Jephthah the Gileadite four days in a year.","words":[["H1323","That the daughters",0,18],["H3478","of Israel",19,28],["H3212","went",29,33],["H3117","yearly",34,40],["H3117","yearly",34,40],["H8567","to lament",41,50],["H1323","the daughter",51,63],["H3316","of Jephthah",64,75],["H1569","the Gileadite",76,89],["H0702","four",90,94],["H3117","days",95,99],["H8141","in a year",100,109]]},"12:1":{"text":"And the men of Ephraim gathered themselves together, and went northward, and said unto Jephthah, Wherefore passedst thou over to fight against the children of Ammon, and didst not call us to go with thee? we will burn thine house upon thee with fire.","words":[["H0376","And the men",0,11],["H0669","of Ephraim",12,22],["H6817","gathered themselves together",23,51],["H5674","and went",53,61],["H6828","northward",62,71],["H0559","and said",73,81],["H3316","unto Jephthah",82,95],["H5674","Wherefore passedst thou over",97,125],["H3898","to fight",126,134],["H1121","against the children",135,155],["H5983","of Ammon",156,164],["H7121","and didst not call",166,184],["H3212","us to go",185,193],["H8313","with thee? we will burn",194,217],["H1004","thine house",218,229],["H0784","upon thee with fire",230,249]]},"12:2":{"text":"And Jephthah said unto them, I and my people were at great strife with the children of Ammon; and when I called you, ye delivered me not out of their hands.","words":[["H3316","And Jephthah",0,12],["H0559","said",13,17],["H5971","unto them, I and my people",18,44],["H1961","were",45,49],["H3966","at great",50,58],["H0376","strife",59,65],["H7379","strife",59,65],["H1121","with the children",66,83],["H5983","of Ammon",84,92],["H2199","and when I called",94,111],["H3467","you, ye delivered",112,129],["H3027","me not out of their hands",130,155]]},"12:3":{"text":"And when I saw that ye delivered me not, I put my life in my hands, and passed over against the children of Ammon, and the LORD delivered them into my hand: wherefore then are ye come up unto me this day, to fight against me?","words":[["H7200","And when I saw",0,14],["H3467","that ye delivered",15,32],["H7760","me not, I put",33,46],["H5315","my life",47,54],["H3709","in my hands",55,66],["H5674","and passed over",68,83],["H1121","against the children",84,104],["H5983","of Ammon",105,113],["H3068","and the LORD",115,127],["H5414","delivered",128,137],["H3027","them into my hand",138,155],["H5927","wherefore then are ye come up",157,186],["H3117","unto me this day",187,203],["H3898","to fight",205,213]]},"12:4":{"text":"Then Jephthah gathered together all the men of Gilead, and fought with Ephraim: and the men of Gilead smote Ephraim, because they said, Ye Gileadites are fugitives of Ephraim among the Ephraimites, and among the Manassites.","words":[["H3316","Then Jephthah",0,13],["H6908","gathered together",14,31],["H0582","all the men",32,43],["H1568","of Gilead",44,53],["H3898","and fought",55,65],["H0669","with Ephraim",66,78],["H0582","and the men",80,91],["H1568","of Gilead",92,101],["H5221","smote",102,107],["H0669","Ephraim",108,115],["H0559","because they said",117,134],["H1568","Ye Gileadites",136,149],["H6412","are fugitives",150,163],["H0669","of Ephraim",164,174],["H8432","among",175,180],["H0669","the Ephraimites",181,196],["H8432","and among",198,207],["H4519","the Manassites",208,222]]},"12:5":{"text":"And the Gileadites took the passages of Jordan before the Ephraimites: and it was so, that when those Ephraimites which were escaped said, Let me go over; that the men of Gilead said unto him, Art thou an Ephraimite? If he said, Nay;","words":[["H1568","And the Gileadites",0,18],["H3920","took",19,23],["H4569","the passages",24,36],["H3383","of Jordan",37,46],["H0669","before the Ephraimites",47,69],["H0669","and it was so, that when those Ephraimites",71,113],["H6412","which were escaped",114,132],["H0559","said",133,137],["H5674","Let me go over",139,153],["H0582","that the men",155,167],["H1568","of Gilead",168,177],["H0559","said",178,182],["H0673","unto him, Art thou an Ephraimite",183,215],["H0559","If he said",217,227]]},"12:6":{"text":"Then said they unto him, Say now Shibboleth: and he said Sibboleth: for he could not frame to pronounce it right. Then they took him, and slew him at the passages of Jordan: and there fell at that time of the Ephraimites forty and two thousand.","words":[["H0559","Then said",0,9],["H0559","they unto him, Say",10,28],["H7641","now Shibboleth",29,43],["H0559","and he said",45,56],["H5451","Sibboleth",57,66],["H3559","for he could not frame",68,90],["H1696","to pronounce",91,103],["H3559","it right",104,112],["H0270","Then they took",114,128],["H7819","him, and slew",129,142],["H4569","him at the passages",143,162],["H3383","of Jordan",163,172],["H5307","and there fell",174,188],["H6256","at that time",189,201],["H0669","of the Ephraimites",202,220],["H0705","forty",221,226],["H8147","and two",227,234],["H0505","thousand",235,243]]},"12:7":{"text":"And Jephthah judged Israel six years. Then died Jephthah the Gileadite, and was buried in one of the cities of Gilead.","words":[["H3316","And Jephthah",0,12],["H8199","judged",13,19],["H3478","Israel",20,26],["H8337","six",27,30],["H8141","years",31,36],["H4191","Then died",38,47],["H3316","Jephthah",48,56],["H1569","the Gileadite",57,70],["H6912","and was buried",72,86],["H5892","in one of the cities",87,107],["H1568","of Gilead",108,117]]},"12:8":{"text":"And after him Ibzan of Bethlehem judged Israel.","words":[["H0310","And after",0,9],["H0078","him Ibzan",10,19],["H1035","of Bethlehem",20,32],["H8199","judged",33,39],["H3478","Israel",40,46]]},"12:9":{"text":"And he had thirty sons, and thirty daughters, whom he sent abroad, and took in thirty daughters from abroad for his sons. And he judged Israel seven years.","words":[["H7970","And he had thirty",0,17],["H1121","sons",18,22],["H7970","and thirty",24,34],["H1323","daughters",35,44],["H7971","whom he sent",46,58],["H2351","abroad",59,65],["H0935","and took",67,75],["H7970","in thirty",76,85],["H1323","daughters",86,95],["H2351","from abroad",96,107],["H1121","for his sons",108,120],["H8199","And he judged",122,135],["H3478","Israel",136,142],["H7651","seven",143,148],["H8141","years",149,154]]},"12:10":{"text":"Then died Ibzan, and was buried at Bethlehem.","words":[["H4191","Then died",0,9],["H0078","Ibzan",10,15],["H6912","and was buried",17,31],["H1035","at Bethlehem",32,44]]},"12:11":{"text":"And after him Elon, a Zebulonite, judged Israel; and he judged Israel ten years.","words":[["H0310","And after",0,9],["H0356","him Elon",10,18],["H2075","a Zebulonite",20,32],["H8199","judged",34,40],["H3478","Israel",41,47],["H8199","and he judged",49,62],["H3478","Israel",63,69],["H6235","ten",70,73],["H8141","years",74,79]]},"12:12":{"text":"And Elon the Zebulonite died, and was buried in Aijalon in the country of Zebulun.","words":[["H0356","And Elon",0,8],["H2075","the Zebulonite",9,23],["H4191","died",24,28],["H6912","and was buried",30,44],["H0357","in Aijalon",45,55],["H0776","in the country",56,70],["H2074","of Zebulun",71,81]]},"12:13":{"text":"And after him Abdon the son of Hillel, a Pirathonite, judged Israel.","words":[["H0310","And after",0,9],["H5658","him Abdon",10,19],["H1121","the son",20,27],["H1985","of Hillel",28,37],["H6553","a Pirathonite",39,52],["H8199","judged",54,60],["H3478","Israel",61,67]]},"12:14":{"text":"And he had forty sons and thirty nephews, that rode on threescore and ten ass colts: and he judged Israel eight years.","words":[["H0705","And he had forty",0,16],["H1121","sons",17,21],["H7970","and thirty",22,32],["H1121","nephews",33,40],["H1121","nephews",33,40],["H7392","that rode",42,51],["H7657","on threescore and ten",52,73],["H5895","ass colts",74,83],["H8199","and he judged",85,98],["H3478","Israel",99,105],["H8083","eight",106,111],["H8141","years",112,117]]},"12:15":{"text":"And Abdon the son of Hillel the Pirathonite died, and was buried in Pirathon in the land of Ephraim, in the mount of the Amalekites.","words":[["H5658","And Abdon",0,9],["H1121","the son",10,17],["H1985","of Hillel",18,27],["H6553","the Pirathonite",28,43],["H4191","died",44,48],["H6912","and was buried",50,64],["H6552","in Pirathon",65,76],["H0776","in the land",77,88],["H0669","of Ephraim",89,99],["H2022","in the mount",101,113],["H6003","of the Amalekites",114,131]]},"13:1":{"text":"And the children of Israel did evil again in the sight of the LORD; and the LORD delivered them into the hand of the Philistines forty years.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6213","did",27,30],["H7451","evil",31,35],["H3254","again",36,41],["H5869","in the sight",42,54],["H3068","of the LORD",55,66],["H3068","and the LORD",68,80],["H5414","delivered",81,90],["H3027","them into the hand",91,109],["H6430","of the Philistines",110,128],["H0705","forty",129,134],["H8141","years",135,140]]},"13:2":{"text":"And there was a certain man of Zorah, of the family of the Danites, whose name was Manoah; and his wife was barren, and bare not.","words":[["H0259","And there was a certain",0,23],["H0376","man",24,27],["H6881","of Zorah",28,36],["H4940","of the family",38,51],["H1839","of the Danites",52,66],["H8034","whose name",68,78],["H4495","was Manoah",79,89],["H0802","and his wife",91,103],["H6135","was barren",104,114],["H3205","and bare",116,124]]},"13:3":{"text":"And the angel of the LORD appeared unto the woman, and said unto her, Behold now, thou art barren, and bearest not: but thou shalt conceive, and bear a son.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H7200","appeared",26,34],["H0802","unto the woman",35,49],["H0559","and said",51,59],["H6135","unto her, Behold now, thou art barren",60,97],["H3205","and bearest",99,110],["H2029","not: but thou shalt conceive",111,139],["H3205","and bear",141,149],["H1121","a son",150,155]]},"13:4":{"text":"Now therefore beware, I pray thee, and drink not wine nor strong drink, and eat not any unclean thing:","words":[["H8104","Now therefore beware",0,20],["H8354","I pray thee, and drink",22,44],["H3196","not wine",45,53],["H7941","nor strong drink",54,70],["H0398","and eat",72,79],["H2931","not any unclean",80,95]]},"13:5":{"text":"For, lo, thou shalt conceive, and bear a son; and no razor shall come on his head: for the child shall be a Nazarite unto God from the womb: and he shall begin to deliver Israel out of the hand of the Philistines.","words":[["H2030","For, lo, thou shalt conceive",0,28],["H3205","and bear",30,38],["H1121","a son",39,44],["H4177","and no razor",46,58],["H5927","shall come",59,69],["H7218","on his head",70,81],["H5288","for the child",83,96],["H5139","shall be a Nazarite",97,116],["H0430","unto God",117,125],["H0990","from the womb",126,139],["H2490","and he shall begin",141,159],["H3467","to deliver",160,170],["H3478","Israel",171,177],["H3027","out of the hand",178,193],["H6430","of the Philistines",194,212]]},"13:6":{"text":"Then the woman came and told her husband, saying, A man of God came unto me, and his countenance was like the countenance of an angel of God, very terrible: but I asked him not whence he was, neither told he me his name:","words":[["H0802","Then the woman",0,14],["H0935","came",15,19],["H0559","and told",20,28],["H0376","her husband",29,40],["H0559","saying",42,48],["H0376","A man",50,55],["H0430","of God",56,62],["H0935","came",63,67],["H4758","unto me, and his countenance",68,96],["H4758","was like the countenance",97,121],["H4397","of an angel",122,133],["H0430","of God",134,140],["H3966","very",142,146],["H3372","terrible",147,155],["H7592","but I asked",157,168],["H5046","him not whence he was, neither told",169,204],["H8034","he me his name",205,219]]},"13:7":{"text":"But he said unto me, Behold, thou shalt conceive, and bear a son; and now drink no wine nor strong drink, neither eat any unclean thing: for the child shall be a Nazarite to God from the womb to the day of his death.","words":[["H0559","But he said",0,11],["H2030","unto me, Behold, thou shalt conceive",12,48],["H3205","and bear",50,58],["H1121","a son",59,64],["H7941","and now drink",66,79],["H3196","no wine",80,87],["H8354","nor strong drink",88,104],["H0398","neither eat",106,117],["H2932","any unclean",118,129],["H5288","thing: for the child",130,150],["H5139","shall be a Nazarite",151,170],["H0430","to God",171,177],["H0990","from the womb",178,191],["H3117","to the day",192,202],["H4194","of his death",203,215]]},"13:8":{"text":"Then Manoah intreated the LORD, and said, O my Lord, let the man of God which thou didst send come again unto us, and teach us what we shall do unto the child that shall be born.","words":[["H4495","Then Manoah",0,11],["H6279","intreated",12,21],["H3068","the LORD",22,30],["H0559","and said",32,40],["H0994","O",42,43],["H0136","my Lord",44,51],["H4994","let",53,56],["H0376","the man",57,64],["H0430","of God",65,71],["H7971","which thou didst send",72,93],["H0935","come again",94,104],["H3384","unto us, and teach",105,123],["H6213","us what we shall do",124,143],["H5288","unto the child",144,158],["H3205","that shall be born",159,177]]},"13:9":{"text":"And God hearkened to the voice of Manoah; and the angel of God came again unto the woman as she sat in the field: but Manoah her husband was not with her.","words":[["H0430","And God",0,7],["H8085","hearkened",8,17],["H6963","to the voice",18,30],["H4495","of Manoah",31,40],["H4397","and the angel",42,55],["H0430","of God",56,62],["H0935","came again",63,73],["H0802","unto the woman",74,88],["H3427","as she sat",89,99],["H7704","in the field",100,112],["H4495","but Manoah",114,124],["H0376","her husband",125,136]]},"13:10":{"text":"And the woman made haste, and ran, and shewed her husband, and said unto him, Behold, the man hath appeared unto me, that came unto me the other day.","words":[["H0802","And the woman",0,13],["H4116","made haste",14,24],["H7323","and ran",26,33],["H5046","and shewed",35,45],["H0376","her husband",46,57],["H0559","and said",59,67],["H0376","unto him, Behold, the man",68,93],["H7200","hath appeared",94,107],["H0935","unto me, that came",108,126],["H3117","unto me the other day",127,148]]},"13:11":{"text":"And Manoah arose, and went after his wife, and came to the man, and said unto him, Art thou the man that spakest unto the woman? And he said, I am.","words":[["H4495","And Manoah",0,10],["H6965","arose",11,16],["H3212","and went",18,26],["H0310","after",27,32],["H0802","his wife",33,41],["H0935","and came",43,51],["H0376","to the man",52,62],["H0559","and said",64,72],["H0376","unto him, Art thou the man",73,99],["H1696","that spakest",100,112],["H0802","unto the woman",113,127],["H0559","And he said",129,140]]},"13:12":{"text":"And Manoah said, Now let thy words come to pass. How shall we order the child, and how shall we do unto him?","words":[["H4495","And Manoah",0,10],["H0559","said",11,15],["H1697","Now let thy words",17,34],["H0935","come to pass",35,47],["H4941","How shall we order",49,67],["H5288","the child",68,77],["H4639","and how shall we do",79,98]]},"13:13":{"text":"And the angel of the LORD said unto Manoah, Of all that I said unto the woman let her beware.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H0559","said",26,30],["H4495","unto Manoah",31,42],["H0559","Of all that I said",44,62],["H0802","unto the woman",63,77],["H8104","let her beware",78,92]]},"13:14":{"text":"She may not eat of any thing that cometh of the vine, neither let her drink wine or strong drink, nor eat any unclean thing: all that I commanded her let her observe.","words":[["H0398","She may not eat",0,15],["H3318","of any thing that cometh",16,40],["H1612","of the vine",41,52],["H8354","neither let her drink",54,75],["H3196","wine",76,80],["H7941","or strong drink",81,96],["H0398","nor eat",98,105],["H2932","any unclean",106,117],["H6680","thing: all that I commanded",118,145],["H8104","her let her observe",146,165]]},"13:15":{"text":"And Manoah said unto the angel of the LORD, I pray thee, let us detain thee, until we shall have made ready a kid for thee.","words":[["H4495","And Manoah",0,10],["H0559","said",11,15],["H4397","unto the angel",16,30],["H3068","of the LORD",31,42],["H6113","I pray thee, let us detain",44,70],["H6213","thee, until we shall have made ready",71,107],["H1423","a kid",108,113],["H5795","a kid",108,113],["H6440","for",114,117]]},"13:16":{"text":"And the angel of the LORD said unto Manoah, Though thou detain me, I will not eat of thy bread: and if thou wilt offer a burnt offering, thou must offer it unto the LORD. For Manoah knew not that he was an angel of the LORD.","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H0559","said",26,30],["H4495","unto Manoah",31,42],["H6113","Though thou detain",44,62],["H0398","me, I will not eat",63,81],["H3899","of thy bread",82,94],["H0518","and if",96,102],["H6213","thou wilt offer",103,118],["H5930","a burnt offering",119,135],["H5927","thou must offer",137,152],["H3068","it unto the LORD",153,169],["H4495","For Manoah",171,181],["H3045","knew",182,186],["H4397","not that he was an angel",187,211],["H3068","of the LORD",212,223]]},"13:17":{"text":"And Manoah said unto the angel of the LORD, What is thy name, that when thy sayings come to pass we may do thee honour?","words":[["H4495","And Manoah",0,10],["H0559","said",11,15],["H4397","unto the angel",16,30],["H3068","of the LORD",31,42],["H8034","What is thy name",44,60],["H1697","that when thy sayings",62,83],["H0935","come to pass",84,96],["H3513","we may do thee honour",97,118]]},"13:18":{"text":"And the angel of the LORD said unto him, Why askest thou thus after my name, seeing it is secret?","words":[["H4397","And the angel",0,13],["H3068","of the LORD",14,25],["H0559","said",26,30],["H7592","unto him, Why askest",31,51],["H8034","thou thus after my name",52,75],["H6383","seeing it is secret",77,96],["H6383","seeing it is secret",77,96]]},"13:19":{"text":"So Manoah took a kid with a meat offering, and offered it upon a rock unto the LORD: and the angel did wondrously; and Manoah and his wife looked on.","words":[["H4495","So Manoah",0,9],["H3947","took",10,14],["H1423","a kid",15,20],["H5795","a kid",15,20],["H4503","with a meat offering",21,41],["H5927","and offered",43,54],["H6697","it upon a rock",55,69],["H3068","unto the LORD",70,83],["H6213","and the angel did",85,102],["H6381","wondrously",103,113],["H4495","and Manoah",115,125],["H0802","and his wife",126,138],["H7200","looked on",139,148]]},"13:20":{"text":"For it came to pass, when the flame went up toward heaven from off the altar, that the angel of the LORD ascended in the flame of the altar. And Manoah and his wife looked on it, and fell on their faces to the ground.","words":[["H3851","For it came to pass, when the flame",0,35],["H5927","went up",36,43],["H8064","toward heaven",44,57],["H4196","from off the altar",58,76],["H4397","that the angel",78,92],["H3068","of the LORD",93,104],["H5927","ascended",105,113],["H3851","in the flame",114,126],["H4196","of the altar",127,139],["H4495","And Manoah",141,151],["H0802","and his wife",152,164],["H7200","looked on",165,174],["H5307","it, and fell on",175,190],["H6440","their faces",191,202],["H0776","to the ground",203,216]]},"13:21":{"text":"But the angel of the LORD did no more appear to Manoah and to his wife. Then Manoah knew that he was an angel of the LORD.","words":[["H4397","But the angel",0,13],["H3068","of the LORD",14,25],["H3254","did no more",26,37],["H7200","appear",38,44],["H4495","to Manoah",45,54],["H0802","and to his wife",55,70],["H4495","Then Manoah",72,83],["H3045","knew",84,88],["H4397","that he was an angel",89,109],["H3068","of the LORD",110,121]]},"13:22":{"text":"And Manoah said unto his wife, We shall surely die, because we have seen God.","words":[["H4495","And Manoah",0,10],["H0559","said",11,15],["H0802","unto his wife",16,29],["H4191","We shall surely",31,46],["H4191","die",47,50],["H7200","because we have seen",52,72],["H0430","God",73,76]]},"13:23":{"text":"But his wife said unto him, If the LORD were pleased to kill us, he would not have received a burnt offering and a meat offering at our hands, neither would he have shewed us all these things, nor would as at this time have told us such things as these.","words":[["H0802","But his wife",0,12],["H0559","said",13,17],["H3863","unto him, If",18,30],["H3068","the LORD",31,39],["H2654","were pleased",40,52],["H4191","to kill",53,60],["H3947","us, he would not have received",61,91],["H5930","a burnt offering",92,108],["H4503","and a meat offering",109,128],["H3027","at our hands",129,141],["H7200","neither would he have shewed",143,171],["H6256","us all these things, nor would as at this time",172,218],["H8085","have told",219,228],["H2063","us such things as these",229,252]]},"13:24":{"text":"And the woman bare a son, and called his name Samson: and the child grew, and the LORD blessed him.","words":[["H0802","And the woman",0,13],["H3205","bare",14,18],["H1121","a son",19,24],["H7121","and called",26,36],["H8034","his name",37,45],["H8123","Samson",46,52],["H5288","and the child",54,67],["H1431","grew",68,72],["H3068","and the LORD",74,86],["H1288","blessed",87,94]]},"13:25":{"text":"And the Spirit of the LORD began to move him at times in the camp of Dan between Zorah and Eshtaol.","words":[["H7307","And the Spirit",0,14],["H3068","of the LORD",15,26],["H2490","began",27,32],["H6470","to move him at times",33,53],["H4264","in the camp",54,65],["H1835","of Dan",66,72],["H6881","between Zorah",73,86],["H0847","and Eshtaol",87,98]]},"14:1":{"text":"And Samson went down to Timnath, and saw a woman in Timnath of the daughters of the Philistines.","words":[["H8123","And Samson",0,10],["H3381","went down",11,20],["H8553","to Timnath",21,31],["H7200","and saw",33,40],["H0802","a woman",41,48],["H8553","in Timnath",49,59],["H1323","of the daughters",60,76],["H6430","of the Philistines",77,95]]},"14:2":{"text":"And he came up, and told his father and his mother, and said, I have seen a woman in Timnath of the daughters of the Philistines: now therefore get her for me to wife.","words":[["H5927","And he came up",0,14],["H5046","and told",16,24],["H0001","his father",25,35],["H0517","and his mother",36,50],["H0559","and said",52,60],["H7200","I have seen",62,73],["H0802","a woman",74,81],["H8553","in Timnath",82,92],["H1323","of the daughters",93,109],["H6430","of the Philistines",110,128],["H3947","now therefore get",130,147],["H0802","her for me to wife",148,166]]},"14:3":{"text":"Then his father and his mother said unto him, Is there never a woman among the daughters of thy brethren, or among all my people, that thou goest to take a wife of the uncircumcised Philistines? And Samson said unto his father, Get her for me; for she pleaseth me well.","words":[["H0001","Then his father",0,15],["H0517","and his mother",16,30],["H0559","said",31,35],["H0369","unto him, Is there never",36,60],["H0802","a woman",61,68],["H1323","among the daughters",69,88],["H0251","of thy brethren",89,104],["H5971","or among all my people",106,128],["H1980","that thou goest",130,145],["H3947","to take",146,153],["H0802","a wife",154,160],["H6189","of the uncircumcised",161,181],["H6430","Philistines",182,193],["H8123","And Samson",195,205],["H0559","said",206,210],["H0001","unto his father",211,226],["H3947","Get",228,231],["H3474","her for me; for she pleaseth me well",232,268],["H5869","her for me; for she pleaseth me well",232,268]]},"14:4":{"text":"But his father and his mother knew not that it was of the LORD, that he sought an occasion against the Philistines: for at that time the Philistines had dominion over Israel.","words":[["H0001","But his father",0,14],["H0517","and his mother",15,29],["H3045","knew",30,34],["H3068","not that it was of the LORD",35,62],["H1245","that he sought",64,78],["H8385","an occasion",79,90],["H6430","against the Philistines",91,114],["H6256","for at that time",116,132],["H6430","the Philistines",133,148],["H4910","had dominion",149,161],["H3478","over Israel",162,173]]},"14:5":{"text":"Then went Samson down, and his father and his mother, to Timnath, and came to the vineyards of Timnath: and, behold, a young lion roared against him.","words":[["H3381","Then went",0,9],["H8123","Samson",10,16],["H3381","down",17,21],["H0001","and his father",23,37],["H0517","and his mother",38,52],["H8553","to Timnath",54,64],["H0935","and came",66,74],["H3754","to the vineyards",75,91],["H8553","of Timnath",92,102],["H3715","and, behold, a young",104,124],["H0738","lion",125,129],["H7580","roared",130,136],["H7125","against",137,144]]},"14:6":{"text":"And the Spirit of the LORD came mightily upon him, and he rent him as he would have rent a kid, and he had nothing in his hand: but he told not his father or his mother what he had done.","words":[["H7307","And the Spirit",0,14],["H3068","of the LORD",15,26],["H6743","came mightily",27,40],["H8156","upon him, and he rent",41,62],["H8156","him as he would have rent",63,88],["H1423","a kid",89,94],["H3972","and he had nothing",96,114],["H3027","in his hand",115,126],["H5046","but he told",128,139],["H0001","not his father",140,154],["H0517","or his mother",155,168],["H6213","what he had done",169,185]]},"14:7":{"text":"And he went down, and talked with the woman; and she pleased Samson well.","words":[["H3381","And he went down",0,16],["H1696","and talked",18,28],["H0802","with the woman",29,43],["H3474","and she pleased",45,60],["H8123","Samson",61,67],["H3474","well",68,72],["H5869","well",68,72]]},"14:8":{"text":"And after a time he returned to take her, and he turned aside to see the carcase of the lion: and, behold, there was a swarm of bees and honey in the carcase of the lion.","words":[["H3117","And after a time",0,16],["H7725","he returned",17,28],["H3947","to take",29,36],["H5493","her, and he turned aside",37,61],["H7200","to see",62,68],["H4658","the carcase",69,80],["H0738","of the lion",81,92],["H5712","and, behold, there was a swarm",94,124],["H1682","of bees",125,132],["H1706","and honey",133,142],["H1472","in the carcase",143,157],["H0738","of the lion",158,169]]},"14:9":{"text":"And he took thereof in his hands, and went on eating, and came to his father and mother, and he gave them, and they did eat: but he told not them that he had taken the honey out of the carcase of the lion.","words":[["H7287","And he took",0,11],["H3709","thereof in his hands",12,32],["H3212","and went on",34,45],["H0398","eating",46,52],["H1980","and came",54,62],["H0001","to his father",63,76],["H0517","and mother",77,87],["H5414","and he gave",89,100],["H0398","them, and they did eat",101,123],["H5046","but he told",125,136],["H7287","not them that he had taken",137,163],["H1706","the honey",164,173],["H1472","out of the carcase",174,192],["H0738","of the lion",193,204]]},"14:10":{"text":"So his father went down unto the woman: and Samson made there a feast; for so used the young men to do.","words":[["H0001","So his father",0,13],["H3381","went down",14,23],["H0802","unto the woman",24,38],["H8123","and Samson",40,50],["H6213","made",51,55],["H4960","there a feast",56,69],["H0970","for so used the young men",71,96],["H6213","to do",97,102]]},"14:11":{"text":"And it came to pass, when they saw him, that they brought thirty companions to be with him.","words":[["H7200","And it came to pass, when they saw",0,34],["H3947","him, that they brought",35,57],["H7970","thirty",58,64],["H4828","companions",65,75]]},"14:12":{"text":"And Samson said unto them, I will now put forth a riddle unto you: if ye can certainly declare it me within the seven days of the feast, and find it out, then I will give you thirty sheets and thirty change of garments:","words":[["H8123","And Samson",0,10],["H0559","said",11,15],["H2330","unto them, I will now put forth",16,47],["H2420","a riddle",48,56],["H5046","unto you: if ye can certainly",57,86],["H5046","declare",87,94],["H7651","it me within the seven",95,117],["H3117","days",118,122],["H4960","of the feast",123,135],["H4672","and find it out",137,152],["H5414","then I will give",154,170],["H7970","you thirty",171,181],["H5466","sheets",182,188],["H7970","and thirty",189,199],["H2487","change",200,206],["H0899","of garments",207,218]]},"14:13":{"text":"But if ye cannot declare it me, then shall ye give me thirty sheets and thirty change of garments. And they said unto him, Put forth thy riddle, that we may hear it.","words":[["H3201","But if ye cannot",0,16],["H5046","declare",17,24],["H5414","it me, then shall ye give",25,50],["H7970","me thirty",51,60],["H5466","sheets",61,67],["H7970","and thirty",68,78],["H2487","change",79,85],["H0899","of garments",86,97],["H0559","And they said",99,112],["H2330","unto him, Put forth",113,132],["H2420","thy riddle",133,143],["H8085","that we may hear",145,161]]},"14:14":{"text":"And he said unto them, Out of the eater came forth meat, and out of the strong came forth sweetness. And they could not in three days expound the riddle.","words":[["H0559","And he said",0,11],["H0398","unto them, Out of the eater",12,39],["H3318","came forth",40,50],["H3978","meat",51,55],["H5794","and out of the strong",57,78],["H3318","came forth",79,89],["H4966","sweetness",90,99],["H3201","And they could",101,115],["H7969","not in three",116,128],["H3117","days",129,133],["H5046","expound",134,141],["H2420","the riddle",142,152]]},"14:15":{"text":"And it came to pass on the seventh day, that they said unto Samson's wife, Entice thy husband, that he may declare unto us the riddle, lest we burn thee and thy father's house with fire: have ye called us to take that we have? is it not so?","words":[["H7637","And it came to pass on the seventh",0,34],["H3117","day",35,38],["H0559","that they said",40,54],["H8123","unto Samson's",55,68],["H0802","wife",69,73],["H6601","Entice",75,81],["H0376","thy husband",82,93],["H5046","that he may declare",95,114],["H2420","unto us the riddle",115,133],["H8313","lest we burn",135,147],["H0001","thee and thy father's",148,169],["H1004","house",170,175],["H0784","with fire",176,185],["H7121","have ye called",187,201],["H3423","us to take that we have",202,225]]},"14:16":{"text":"And Samson's wife wept before him, and said, Thou dost but hate me, and lovest me not: thou hast put forth a riddle unto the children of my people, and hast not told it me. And he said unto her, Behold, I have not told it my father nor my mother, and shall I tell it thee?","words":[["H8123","And Samson's",0,12],["H0802","wife",13,17],["H1058","wept",18,22],["H0559","before him, and said",23,43],["H8130","Thou dost but hate",45,63],["H0157","me, and lovest",64,78],["H2330","me not: thou hast put forth",79,106],["H2420","a riddle",107,115],["H1121","unto the children",116,133],["H5971","of my people",134,146],["H5046","and hast not told",148,165],["H0559","it me. And he said",166,184],["H5046","unto her, Behold, I have not told",185,218],["H0001","it my father",219,231],["H0517","nor my mother",232,245],["H5046","and shall I tell",247,263]]},"14:17":{"text":"And she wept before him the seven days, while their feast lasted: and it came to pass on the seventh day, that he told her, because she lay sore upon him: and she told the riddle to the children of her people.","words":[["H1058","And she wept",0,12],["H7651","before him the seven",13,33],["H3117","days",34,38],["H4960","while their feast",40,57],["H1961","lasted",58,64],["H7637","and it came to pass on the seventh",66,100],["H3117","day",101,104],["H5046","that he told",106,118],["H6693","her, because she lay sore",119,144],["H5046","upon him: and she told",145,167],["H2420","the riddle",168,178],["H1121","to the children",179,194],["H5971","of her people",195,208]]},"14:18":{"text":"And the men of the city said unto him on the seventh day before the sun went down, What is sweeter than honey? and what is stronger than a lion? And he said unto them, If ye had not plowed with my heifer, ye had not found out my riddle.","words":[["H0582","And the men",0,11],["H5892","of the city",12,23],["H0559","said",24,28],["H7637","unto him on the seventh",29,52],["H3117","day",53,56],["H2775","before the sun",57,71],["H0935","went down",72,81],["H4966","What is sweeter",83,98],["H1706","than honey",99,109],["H5794","and what is stronger",111,131],["H0738","than a lion",132,143],["H0559","And he said",145,156],["H3884","unto them, If",157,170],["H2790","ye had not plowed",171,188],["H5697","with my heifer",189,203],["H4672","ye had not found out",205,225],["H2420","my riddle",226,235]]},"14:19":{"text":"And the Spirit of the LORD came upon him, and he went down to Ashkelon, and slew thirty men of them, and took their spoil, and gave change of garments unto them which expounded the riddle. And his anger was kindled, and he went up to his father's house.","words":[["H7307","And the Spirit",0,14],["H3068","of the LORD",15,26],["H6743","came",27,31],["H3381","upon him, and he went down",32,58],["H0831","to Ashkelon",59,70],["H5221","and slew",72,80],["H7970","thirty",81,87],["H0376","men",88,91],["H3947","of them, and took",92,109],["H2488","their spoil",110,121],["H5414","and gave",123,131],["H2487","change",132,138],["H5046","of garments unto them which expounded",139,176],["H2420","the riddle",177,187],["H0639","And his anger",189,202],["H2734","was kindled",203,214],["H5927","and he went up",216,230],["H0001","to his father's",231,246],["H1004","house",247,252]]},"14:20":{"text":"But Samson's wife was given to his companion, whom he had used as his friend.","words":[["H8123","But Samson's",0,12],["H0802","wife",13,17],["H4828","was given to his companion",18,44],["H7462","whom he had used as his friend",46,76]]},"15:1":{"text":"But it came to pass within a while after, in the time of wheat harvest, that Samson visited his wife with a kid; and he said, I will go in to my wife into the chamber. But her father would not suffer him to go in.","words":[["H3117","But it came to pass within a while after",0,40],["H3117","in the time",42,53],["H2406","of wheat",54,62],["H7105","harvest",63,70],["H8123","that Samson",72,83],["H6485","visited",84,91],["H0802","his wife",92,100],["H1423","with a kid",101,111],["H5795","with a kid",101,111],["H0559","and he said",113,124],["H0935","I will go in",126,138],["H0802","to my wife",139,149],["H2315","into the chamber",150,166],["H0001","But her father",168,182],["H5414","would not suffer",183,199],["H0935","him to go in",200,212]]},"15:2":{"text":"And her father said, I verily thought that thou hadst utterly hated her; therefore I gave her to thy companion: is not her younger sister fairer than she? take her, I pray thee, instead of her.","words":[["H0001","And her father",0,14],["H0559","said",15,19],["H0559","I verily",21,29],["H0559","thought",30,37],["H8130","that thou hadst utterly",38,61],["H8130","hated",62,67],["H5414","her; therefore I gave",68,89],["H4828","her to thy companion",90,110],["H6996","is not her younger",112,130],["H0269","sister",131,137],["H2896","fairer",138,144]]},"15:3":{"text":"And Samson said concerning them, Now shall I be more blameless than the Philistines, though I do them a displeasure.","words":[["H8123","And Samson",0,10],["H0559","said",11,15],["H6471","concerning them, Now",16,36],["H5352","shall I be more blameless",37,62],["H6430","than the Philistines",63,83],["H6213","though I do",85,96],["H7451","them a displeasure",97,115]]},"15:4":{"text":"And Samson went and caught three hundred foxes, and took firebrands, and turned tail to tail, and put a firebrand in the midst between two tails.","words":[["H8123","And Samson",0,10],["H3212","went",11,15],["H3920","and caught",16,26],["H7969","three",27,32],["H3967","hundred",33,40],["H7776","foxes",41,46],["H3947","and took",48,56],["H3940","firebrands",57,67],["H6437","and turned",69,79],["H2180","tail",80,84],["H2180","to tail",85,92],["H7760","and put",94,101],["H0259","a",102,103],["H3940","firebrand",104,113],["H8432","in the midst",114,126],["H8147","between two",127,138],["H2180","tails",139,144]]},"15:5":{"text":"And when he had set the brands on fire, he let them go into the standing corn of the Philistines, and burnt up both the shocks, and also the standing corn, with the vineyards and olives.","words":[["H1197","And when he had set",0,19],["H3940","the brands",20,30],["H0784","on fire",31,38],["H7971","he let them go",40,54],["H7054","into the standing corn",55,77],["H6430","of the Philistines",78,96],["H1197","and burnt up",98,110],["H1430","both the shocks",111,126],["H7054","and also the standing corn",128,154],["H3754","with the vineyards",156,174],["H2132","and olives",175,185]]},"15:6":{"text":"Then the Philistines said, Who hath done this? And they answered, Samson, the son in law of the Timnite, because he had taken his wife, and given her to his companion. And the Philistines came up, and burnt her and her father with fire.","words":[["H6430","Then the Philistines",0,20],["H0559","said",21,25],["H6213","Who hath done",27,40],["H0559","this? And they answered",41,64],["H8123","Samson",66,72],["H2860","the son in law",74,88],["H8554","of the Timnite",89,103],["H3947","because he had taken",105,125],["H0802","his wife",126,134],["H5414","and given",136,145],["H4828","her to his companion",146,166],["H6430","And the Philistines",168,187],["H5927","came up",188,195],["H8313","and burnt",197,206],["H0001","her and her father",207,225],["H0784","with fire",226,235]]},"15:7":{"text":"And Samson said unto them, Though ye have done this, yet will I be avenged of you, and after that I will cease.","words":[["H8123","And Samson",0,10],["H0559","said",11,15],["H0518","unto them, Though",16,33],["H6213","ye have done",34,46],["H2063","this",47,51],["H5358","yet will I be avenged",53,74],["H0310","of you, and after",75,92],["H2308","that I will cease",93,110]]},"15:8":{"text":"And he smote them hip and thigh with a great slaughter: and he went down and dwelt in the top of the rock Etam.","words":[["H5221","And he smote",0,12],["H7785","them hip",13,21],["H5921","and",22,25],["H3409","thigh",26,31],["H1419","with a great",32,44],["H4347","slaughter",45,54],["H3381","and he went down",56,72],["H3427","and dwelt",73,82],["H5585","in the top",83,93],["H5553","of the rock",94,105],["H5862","Etam",106,110]]},"15:9":{"text":"Then the Philistines went up, and pitched in Judah, and spread themselves in Lehi.","words":[["H6430","Then the Philistines",0,20],["H5927","went up",21,28],["H2583","and pitched",30,41],["H3063","in Judah",42,50],["H5203","and spread",52,62],["H3896","themselves in Lehi",63,81]]},"15:10":{"text":"And the men of Judah said, Why are ye come up against us? And they answered, To bind Samson are we come up, to do to him as he hath done to us.","words":[["H0376","And the men",0,11],["H3063","of Judah",12,20],["H0559","said",21,25],["H5927","Why are ye come up",27,45],["H0559","against us? And they answered",46,75],["H0631","To bind",77,84],["H8123","Samson",85,91],["H5927","are we come up",92,106],["H6213","to do",108,113],["H6213","to him as he hath done",114,136]]},"15:11":{"text":"Then three thousand men of Judah went to the top of the rock Etam, and said to Samson, Knowest thou not that the Philistines are rulers over us? what is this that thou hast done unto us? And he said unto them, As they did unto me, so have I done unto them.","words":[["H7969","Then three",0,10],["H0505","thousand",11,19],["H0376","men",20,23],["H3063","of Judah",24,32],["H3381","went",33,37],["H5585","to the top",38,48],["H5553","of the rock",49,60],["H5862","Etam",61,65],["H0559","and said",67,75],["H8123","to Samson",76,85],["H3045","Knowest",87,94],["H6430","thou not that the Philistines",95,124],["H4910","are rulers",125,135],["H6213","over us? what is this that thou hast done",136,177],["H0559","unto us? And he said",178,198],["H6213","unto them, As they did",199,221],["H6213","unto me, so have I done",222,245]]},"15:12":{"text":"And they said unto him, We are come down to bind thee, that we may deliver thee into the hand of the Philistines. And Samson said unto them, Swear unto me, that ye will not fall upon me yourselves.","words":[["H0559","And they said",0,13],["H3381","unto him, We are come down",14,40],["H0631","to bind",41,48],["H5414","thee, that we may deliver",49,74],["H3027","thee into the hand",75,93],["H6430","of the Philistines",94,112],["H8123","And Samson",114,124],["H0559","said",125,129],["H7650","unto them, Swear",130,146],["H6293","unto me, that ye will not fall upon",147,182]]},"15:13":{"text":"And they spake unto him, saying, No; but we will bind thee fast, and deliver thee into their hand: but surely we will not kill thee. And they bound him with two new cords, and brought him up from the rock.","words":[["H0559","And they spake",0,14],["H0559","unto him, saying",15,31],["H0631","No; but we will bind",33,53],["H0631","thee fast",54,63],["H5414","and deliver",65,76],["H3027","thee into their hand",77,97],["H4191","but surely",99,109],["H4191","we will not kill",110,126],["H0631","thee. And they bound",127,147],["H8147","him with two",148,160],["H2319","new",161,164],["H5688","cords",165,170],["H5927","and brought him up",172,190],["H5553","from the rock",191,204]]},"15:14":{"text":"And when he came unto Lehi, the Philistines shouted against him: and the Spirit of the LORD came mightily upon him, and the cords that were upon his arms became as flax that was burnt with fire, and his bands loosed from off his hands.","words":[["H0935","And when he came",0,16],["H3896","unto Lehi",17,26],["H6430","the Philistines",28,43],["H7321","shouted",44,51],["H7125","against",52,59],["H7307","him: and the Spirit",60,79],["H3068","of the LORD",80,91],["H6743","came mightily",92,105],["H5688","upon him, and the cords",106,129],["H2220","that were upon his arms",130,153],["H6593","became as flax",154,168],["H1197","that was burnt",169,183],["H0784","with fire",184,193],["H0612","and his bands",195,208],["H4549","loosed",209,215],["H3027","from off his hands",216,234]]},"15:15":{"text":"And he found a new jawbone of an ass, and put forth his hand, and took it, and slew a thousand men therewith.","words":[["H4672","And he found",0,12],["H2961","a new",13,18],["H3895","jawbone",19,26],["H2543","of an ass",27,36],["H7971","and put forth",38,51],["H3027","his hand",52,60],["H3947","and took",62,70],["H5221","it, and slew",71,83],["H0505","a thousand",84,94],["H0376","men",95,98]]},"15:16":{"text":"And Samson said, With the jawbone of an ass, heaps upon heaps, with the jaw of an ass have I slain a thousand men.","words":[["H8123","And Samson",0,10],["H0559","said",11,15],["H3895","With the jawbone",17,33],["H2543","of an ass",34,43],["H2565","heaps",45,50],["H2565","upon heaps",51,61],["H3895","with the jaw",63,75],["H2543","of an ass",76,85],["H5221","have I slain",86,98],["H0505","a thousand",99,109],["H0376","men",110,113]]},"15:17":{"text":"And it came to pass, when he had made an end of speaking, that he cast away the jawbone out of his hand, and called that place Ramathlehi.","words":[["H3615","And it came to pass, when he had made an end",0,44],["H1696","of speaking",45,56],["H7993","that he cast away",58,75],["H3895","the jawbone",76,87],["H3027","out of his hand",88,103],["H7121","and called",105,115],["H4725","that place",116,126],["H7437","Ramathlehi",127,137]]},"15:18":{"text":"And he was sore athirst, and called on the LORD, and said, Thou hast given this great deliverance into the hand of thy servant: and now shall I die for thirst, and fall into the hand of the uncircumcised?","words":[["H3966","And he was sore",0,15],["H6770","athirst",16,23],["H7121","and called",25,35],["H3068","on the LORD",36,47],["H0559","and said",49,57],["H5414","Thou hast given",59,74],["H1419","this great",75,85],["H8668","deliverance",86,97],["H3027","into the hand",98,111],["H5650","of thy servant",112,126],["H4191","and now shall I die",128,147],["H6772","for thirst",148,158],["H5307","and fall",160,168],["H3027","into the hand",169,182],["H6189","of the uncircumcised",183,203]]},"15:19":{"text":"But God clave an hollow place that was in the jaw, and there came water thereout; and when he had drunk, his spirit came again, and he revived: wherefore he called the name thereof Enhakkore, which is in Lehi unto this day.","words":[["H0430","But God",0,7],["H1234","clave",8,13],["H4388","an hollow place",14,29],["H3895","that was in the jaw",30,49],["H3318","and there came",51,65],["H4325","water",66,71],["H8354","thereout; and when he had drunk",72,103],["H7307","his spirit",105,115],["H7725","came again",116,126],["H2421","and he revived",128,142],["H7121","wherefore he called",144,163],["H8034","the name",164,172],["H5875","thereof Enhakkore",173,190],["H3896","which is in Lehi",192,208],["H3117","unto this day",209,222]]},"15:20":{"text":"And he judged Israel in the days of the Philistines twenty years.","words":[["H8199","And he judged",0,13],["H3478","Israel",14,20],["H3117","in the days",21,32],["H6430","of the Philistines",33,51],["H6242","twenty",52,58],["H8141","years",59,64]]},"16:1":{"text":"Then went Samson to Gaza, and saw there an harlot, and went in unto her.","words":[["H3212","Then went",0,9],["H8123","Samson",10,16],["H5804","to Gaza",17,24],["H7200","and saw",26,33],["H0802","there an harlot",34,49],["H2181","there an harlot",34,49],["H0935","and went in",51,62]]},"16:2":{"text":"And it was told the Gazites, saying, Samson is come hither. And they compassed him in, and laid wait for him all night in the gate of the city, and were quiet all the night, saying, In the morning, when it is day, we shall kill him.","words":[["H5841","And it was told the Gazites",0,27],["H0559","saying",29,35],["H8123","Samson",37,43],["H0935","is come",44,51],["H5437","hither. And they compassed him in",52,85],["H0693","and laid wait",87,100],["H3915","for him all night",101,118],["H8179","in the gate",119,130],["H5892","of the city",131,142],["H2790","and were quiet",144,158],["H3915","all the night",159,172],["H0559","saying",174,180],["H1242","In the morning",182,196],["H0216","when it is day",198,212],["H2026","we shall kill",214,227]]},"16:3":{"text":"And Samson lay till midnight, and arose at midnight, and took the doors of the gate of the city, and the two posts, and went away with them, bar and all, and put them upon his shoulders, and carried them up to the top of an hill that is before Hebron.","words":[["H8123","And Samson",0,10],["H7901","lay",11,14],["H2677","till midnight",15,28],["H3915","till midnight",15,28],["H6965","and arose",30,39],["H2677","at midnight",40,51],["H3915","at midnight",40,51],["H0270","and took",53,61],["H1817","the doors",62,71],["H8179","of the gate",72,83],["H5892","of the city",84,95],["H8147","and the two",97,108],["H4201","posts",109,114],["H5265","and went away",116,129],["H1280","with them, bar",130,144],["H7760","and all, and put",145,161],["H3802","them upon his shoulders",162,185],["H5927","and carried them up",187,206],["H7218","to the top",207,217],["H2022","of an hill",218,228],["H6440","that is before",229,243],["H2275","Hebron",244,250]]},"16:4":{"text":"And it came to pass afterward, that he loved a woman in the valley of Sorek, whose name was Delilah.","words":[["H0310","And it came to pass afterward",0,29],["H0157","that he loved",31,44],["H0802","a woman",45,52],["H5158","in the valley",53,66],["H7796","of Sorek",67,75],["H8034","whose name",77,87],["H1807","was Delilah",88,99]]},"16:5":{"text":"And the lords of the Philistines came up unto her, and said unto her, Entice him, and see wherein his great strength lieth, and by what means we may prevail against him, that we may bind him to afflict him: and we will give thee every one of us eleven hundred pieces of silver.","words":[["H5633","And the lords",0,13],["H6430","of the Philistines",14,32],["H5927","came up",33,40],["H0559","unto her, and said",41,59],["H6601","unto her, Entice",60,76],["H7200","him, and see",77,89],["H1419","wherein his great",90,107],["H3581","strength",108,116],["H3201","lieth, and by what means we may prevail",117,156],["H0631","against him, that we may bind",157,186],["H6031","him to afflict",187,201],["H5414","him: and we will give",202,223],["H0376","thee every one",224,238],["H0505","of us eleven hundred",239,259],["H3967","of us eleven hundred",239,259],["H3701","pieces of silver",260,276]]},"16:6":{"text":"And Delilah said to Samson, Tell me, I pray thee, wherein thy great strength lieth, and wherewith thou mightest be bound to afflict thee.","words":[["H1807","And Delilah",0,11],["H0559","said",12,16],["H8123","to Samson",17,26],["H5046","Tell",28,32],["H1419","me, I pray thee, wherein thy great",33,67],["H3581","strength",68,76],["H0631","lieth, and wherewith thou mightest be bound",77,120],["H6031","to afflict",121,131]]},"16:7":{"text":"And Samson said unto her, If they bind me with seven green withs that were never dried, then shall I be weak, and be as another man.","words":[["H8123","And Samson",0,10],["H0559","said",11,15],["H0631","unto her, If they bind",16,38],["H7651","me with seven",39,52],["H3892","green",53,58],["H3499","withs",59,64],["H2717","that were never dried",65,86],["H2470","then shall I be weak",88,108],["H0259","and be as another",110,127],["H0120","man",128,131]]},"16:8":{"text":"Then the lords of the Philistines brought up to her seven green withs which had not been dried, and she bound him with them.","words":[["H5633","Then the lords",0,14],["H6430","of the Philistines",15,33],["H5927","brought up",34,44],["H7651","to her seven",45,57],["H3892","green",58,63],["H3499","withs",64,69],["H2717","which had not been dried",70,94],["H0631","and she bound",96,109]]},"16:9":{"text":"Now there were men lying in wait, abiding with her in the chamber. And she said unto him, The Philistines be upon thee, Samson. And he brake the withs, as a thread of tow is broken when it toucheth the fire. So his strength was not known.","words":[["H0693","Now there were men lying in wait",0,32],["H3427","abiding",34,41],["H2315","with her in the chamber",42,65],["H0559","And she said",67,79],["H6430","unto him, The Philistines",80,105],["H8123","be upon thee, Samson",106,126],["H5423","And he brake",128,140],["H3499","the withs",141,150],["H6616","as a thread",152,163],["H5296","of tow",164,170],["H5423","is broken",171,180],["H7306","when it toucheth",181,197],["H0784","the fire",198,206],["H3581","So his strength",208,223],["H3045","was not known",224,237]]},"16:10":{"text":"And Delilah said unto Samson, Behold, thou hast mocked me, and told me lies: now tell me, I pray thee, wherewith thou mightest be bound.","words":[["H1807","And Delilah",0,11],["H0559","said",12,16],["H8123","unto Samson",17,28],["H2048","Behold, thou hast mocked",30,54],["H1696","me, and told",55,67],["H3577","me lies",68,75],["H5046","now tell",77,85],["H0631","me, I pray thee, wherewith thou mightest be bound",86,135]]},"16:11":{"text":"And he said unto her, If they bind me fast with new ropes that never were occupied, then shall I be weak, and be as another man.","words":[["H0559","And he said",0,11],["H0631","unto her, If they bind",12,34],["H0631","me fast",35,42],["H2319","with new",43,51],["H5688","ropes",52,57],["H4399","that never were occupied",58,82],["H6213","that never were occupied",58,82],["H2470","then shall I be weak",84,104],["H0259","and be as another",106,123],["H0120","man",124,127]]},"16:12":{"text":"Delilah therefore took new ropes, and bound him therewith, and said unto him, The Philistines be upon thee, Samson. And there were liers in wait abiding in the chamber. And he brake them from off his arms like a thread.","words":[["H1807","Delilah",0,7],["H3947","therefore took",8,22],["H2319","new",23,26],["H5688","ropes",27,32],["H0631","and bound",34,43],["H0559","him therewith, and said",44,67],["H6430","unto him, The Philistines",68,93],["H8123","be upon thee, Samson",94,114],["H0693","And there were liers in wait",116,144],["H3427","abiding",145,152],["H2315","in the chamber",153,167],["H5423","And he brake",169,181],["H2220","them from off his arms",182,204],["H2339","like a thread",205,218]]},"16:13":{"text":"And Delilah said unto Samson, Hitherto thou hast mocked me, and told me lies: tell me wherewith thou mightest be bound. And he said unto her, If thou weavest the seven locks of my head with the web.","words":[["H1807","And Delilah",0,11],["H0559","said",12,16],["H8123","unto Samson",17,28],["H2008","Hitherto",30,38],["H2048","thou hast mocked",39,55],["H1696","me, and told",56,68],["H3577","me lies",69,76],["H5046","tell",78,82],["H0631","me wherewith thou mightest be bound",83,118],["H0559","And he said",120,131],["H0707","unto her, If thou weavest",132,157],["H7651","the seven",158,167],["H4253","locks",168,173],["H7218","of my head",174,184],["H4545","with the web",185,197]]},"16:14":{"text":"And she fastened it with the pin, and said unto him, The Philistines be upon thee, Samson. And he awaked out of his sleep, and went away with the pin of the beam, and with the web.","words":[["H8628","And she fastened",0,16],["H3489","it with the pin",17,32],["H0559","and said",34,42],["H6430","unto him, The Philistines",43,68],["H8123","be upon thee, Samson",69,89],["H3364","And he awaked",91,104],["H8142","out of his sleep",105,121],["H5265","and went away",123,136],["H3489","with the pin",137,149],["H0708","of the beam",150,161],["H4545","and with the web",163,179]]},"16:15":{"text":"And she said unto him, How canst thou say, I love thee, when thine heart is not with me? thou hast mocked me these three times, and hast not told me wherein thy great strength lieth.","words":[["H0559","And she said",0,12],["H0349","unto him, How",13,26],["H0559","canst thou say",27,41],["H0157","I love",43,49],["H3820","thee, when thine heart",50,72],["H2048","is not with me? thou hast mocked",73,105],["H7969","me these three",106,120],["H6471","times",121,126],["H5046","and hast not told",128,145],["H1419","me wherein thy great",146,166],["H3581","strength",167,175]]},"16:16":{"text":"And it came to pass, when she pressed him daily with her words, and urged him, so that his soul was vexed unto death;","words":[["H6693","And it came to pass, when she pressed",0,37],["H3117","him daily",38,47],["H1697","with her words",48,62],["H0509","and urged",64,73],["H5315","him, so that his soul",74,95],["H7114","was vexed",96,105],["H4191","unto death",106,116]]},"16:17":{"text":"That he told her all his heart, and said unto her, There hath not come a razor upon mine head; for I have been a Nazarite unto God from my mother's womb: if I be shaven, then my strength will go from me, and I shall become weak, and be like any other man.","words":[["H5046","That he told",0,12],["H3820","her all his heart",13,30],["H0559","and said",32,40],["H5927","unto her, There hath not come",41,70],["H4177","a razor",71,78],["H7218","upon mine head",79,93],["H5139","for I have been a Nazarite",95,121],["H0430","unto God",122,130],["H0517","from my mother's",131,147],["H0990","womb",148,152],["H1548","if I be shaven",154,168],["H3581","then my strength",170,186],["H5493","will go",187,194],["H2470","from me, and I shall become weak",195,227],["H0120","and be like any other man",229,254]]},"16:18":{"text":"And when Delilah saw that he had told her all his heart, she sent and called for the lords of the Philistines, saying, Come up this once, for he hath shewed me all his heart. Then the lords of the Philistines came up unto her, and brought money in their hand.","words":[["H1807","And when Delilah",0,16],["H7200","saw",17,20],["H5046","that he had told",21,37],["H3820","her all his heart",38,55],["H7971","she sent",57,65],["H7121","and called",66,76],["H5633","for the lords",77,90],["H6430","of the Philistines",91,109],["H0559","saying",111,117],["H5927","Come up",119,126],["H6471","this once",127,136],["H5046","for he hath shewed",138,156],["H3820","me all his heart",157,173],["H5633","Then the lords",175,189],["H6430","of the Philistines",190,208],["H5927","came up",209,216],["H5927","unto her, and brought",217,238],["H3701","money",239,244],["H3027","in their hand",245,258]]},"16:19":{"text":"And she made him sleep upon her knees; and she called for a man, and she caused him to shave off the seven locks of his head; and she began to afflict him, and his strength went from him.","words":[["H3462","And she made him sleep",0,22],["H1290","upon her knees",23,37],["H7121","and she called",39,53],["H0376","for a man",54,63],["H1548","and she caused him to shave off",65,96],["H7651","the seven",97,106],["H4253","locks",107,112],["H7218","of his head",113,124],["H2490","and she began",126,139],["H6031","to afflict",140,150],["H3581","him, and his strength",151,172],["H5493","went",173,177]]},"16:20":{"text":"And she said, The Philistines be upon thee, Samson. And he awoke out of his sleep, and said, I will go out as at other times before, and shake myself. And he wist not that the LORD was departed from him.","words":[["H0559","And she said",0,12],["H6430","The Philistines",14,29],["H8123","be upon thee, Samson",30,50],["H3364","And he awoke",52,64],["H8142","out of his sleep",65,81],["H0559","and said",83,91],["H3318","I will go out",93,106],["H6471","as at other times before",107,131],["H5287","and shake",133,142],["H3045","myself. And he wist",143,162],["H3068","not that the LORD",163,180],["H5493","was departed",181,193]]},"16:21":{"text":"But the Philistines took him, and put out his eyes, and brought him down to Gaza, and bound him with fetters of brass; and he did grind in the prison house.","words":[["H6430","But the Philistines",0,19],["H0270","took",20,24],["H5365","him, and put out",25,41],["H5869","his eyes",42,50],["H3381","and brought him down",52,72],["H5804","to Gaza",73,80],["H0631","and bound",82,91],["H5178","him with fetters of brass",92,117],["H2912","and he did grind",119,135],["H0631","in the prison",136,149],["H1004","house",150,155]]},"16:22":{"text":"Howbeit the hair of his head began to grow again after he was shaven.","words":[["H8181","Howbeit the hair",0,16],["H7218","of his head",17,28],["H2490","began",29,34],["H6779","to grow again",35,48],["H0834","after",49,54],["H1548","he was shaven",55,68]]},"16:23":{"text":"Then the lords of the Philistines gathered them together for to offer a great sacrifice unto Dagon their god, and to rejoice: for they said, Our god hath delivered Samson our enemy into our hand.","words":[["H5633","Then the lords",0,14],["H6430","of the Philistines",15,33],["H0622","gathered them together",34,56],["H2076","for to offer",57,69],["H1419","a great",70,77],["H2077","sacrifice",78,87],["H1712","unto Dagon",88,98],["H0430","their god",99,108],["H8057","and to rejoice",110,124],["H0559","for they said",126,139],["H0430","Our god",141,148],["H5414","hath delivered",149,163],["H8123","Samson",164,170],["H0341","our enemy",171,180],["H3027","into our hand",181,194]]},"16:24":{"text":"And when the people saw him, they praised their god: for they said, Our god hath delivered into our hands our enemy, and the destroyer of our country, which slew many of us.","words":[["H5971","And when the people",0,19],["H7200","saw",20,23],["H1984","him, they praised",24,41],["H0430","their god",42,51],["H0559","for they said",53,66],["H0430","Our god",68,75],["H5414","hath delivered",76,90],["H3027","into our hands",91,105],["H0341","our enemy",106,115],["H2717","and the destroyer",117,134],["H0776","of our country",135,149],["H2491","which slew",151,161],["H7235","many",162,166]]},"16:25":{"text":"And it came to pass, when their hearts were merry, that they said, Call for Samson, that he may make us sport. And they called for Samson out of the prison house; and he made them sport: and they set him between the pillars.","words":[["H3820","And it came to pass, when their hearts",0,38],["H2896","were merry",39,49],["H0559","that they said",51,65],["H7121","Call",67,71],["H8123","for Samson",72,82],["H7832","that he may make us sport",84,109],["H7121","And they called",111,126],["H8123","for Samson",127,137],["H0631","out of the prison",138,155],["H1004","house",156,161],["H6440","and he made them",163,179],["H6711","sport",180,185],["H5975","and they set",187,199],["H5982","him between the pillars",200,223]]},"16:26":{"text":"And Samson said unto the lad that held him by the hand, Suffer me that I may feel the pillars whereupon the house standeth, that I may lean upon them.","words":[["H8123","And Samson",0,10],["H0559","said",11,15],["H5288","unto the lad",16,28],["H2388","that held",29,38],["H3027","him by the hand",39,54],["H3240","Suffer",56,62],["H4184","me that I may feel",63,81],["H3237","me that I may feel",63,81],["H5982","the pillars",82,93],["H1004","whereupon the house",94,113],["H3559","standeth",114,122],["H8172","that I may lean",124,139]]},"16:27":{"text":"Now the house was full of men and women; and all the lords of the Philistines were there; and there were upon the roof about three thousand men and women, that beheld while Samson made sport.","words":[["H1004","Now the house",0,13],["H4390","was full",14,22],["H0582","of men",23,29],["H0802","and women",30,39],["H5633","and all the lords",41,58],["H6430","of the Philistines",59,77],["H1406","were there; and there were upon the roof",78,118],["H7969","about three",119,130],["H0505","thousand",131,139],["H0376","men",140,143],["H0802","and women",144,153],["H7200","that beheld",155,166],["H8123","while Samson",167,179],["H7832","made sport",180,190]]},"16:28":{"text":"And Samson called unto the LORD, and said, O Lord GOD, remember me, I pray thee, and strengthen me, I pray thee, only this once, O God, that I may be at once avenged of the Philistines for my two eyes.","words":[["H8123","And Samson",0,10],["H7121","called",11,17],["H3068","unto the LORD",18,31],["H0559","and said",33,41],["H0136","O Lord",43,49],["H3069","GOD",50,53],["H2142","remember",55,63],["H2388","me, I pray thee, and strengthen",64,95],["H6471","me, I pray thee, only this once",96,127],["H0430","O God",129,134],["H0259","that I may be at once",136,157],["H5358","avenged",158,165],["H5359","avenged",158,165],["H6430","of the Philistines",166,184],["H8147","for my two",185,195],["H5869","eyes",196,200]]},"16:29":{"text":"And Samson took hold of the two middle pillars upon which the house stood, and on which it was borne up, of the one with his right hand, and of the other with his left.","words":[["H8123","And Samson",0,10],["H3943","took hold",11,20],["H8147","of the two",21,31],["H8432","middle",32,38],["H5982","pillars",39,46],["H1004","upon which the house",47,67],["H3559","stood",68,73],["H5564","and on which it was borne up",75,103],["H0259","of the one",105,115],["H3225","with his right hand",116,135],["H0259","and of the other",137,153],["H8040","with his left",154,167]]},"16:30":{"text":"And Samson said, Let me die with the Philistines. And he bowed himself with all his might; and the house fell upon the lords, and upon all the people that were therein. So the dead which he slew at his death were more than they which he slew in his life.","words":[["H8123","And Samson",0,10],["H0559","said",11,15],["H4191","Let me die",17,27],["H5315","Let me die",17,27],["H6430","with the Philistines",28,48],["H5186","And he bowed",50,62],["H3581","himself with all his might",63,89],["H1004","and the house",91,104],["H5307","fell",105,109],["H5633","upon the lords",110,124],["H5971","and upon all the people",126,149],["H4191","that were therein. So the dead",150,180],["H4191","which he slew",181,194],["H4194","at his death",195,207],["H7227","were more",208,217],["H4191","than they which he slew",218,241],["H2416","in his life",242,253]]},"16:31":{"text":"Then his brethren and all the house of his father came down, and took him, and brought him up, and buried him between Zorah and Eshtaol in the buryingplace of Manoah his father. And he judged Israel twenty years.","words":[["H0251","Then his brethren",0,17],["H1004","and all the house",18,35],["H0001","of his father",36,49],["H3381","came down",50,59],["H5375","and took",61,69],["H5927","him, and brought him up",70,93],["H6912","and buried",95,105],["H6881","him between Zorah",106,123],["H0847","and Eshtaol",124,135],["H6913","in the buryingplace",136,155],["H4495","of Manoah",156,165],["H0001","his father",166,176],["H8199","And he judged",178,191],["H3478","Israel",192,198],["H6242","twenty",199,205],["H8141","years",206,211]]},"17:1":{"text":"And there was a man of mount Ephraim, whose name was Micah.","words":[["H0376","And there was a man",0,19],["H2022","of mount",20,28],["H0669","Ephraim",29,36],["H8034","whose name",38,48],["H4321","was Micah",49,58]]},"17:2":{"text":"And he said unto his mother, The eleven hundred shekels of silver that were taken from thee, about which thou cursedst, and spakest of also in mine ears, behold, the silver is with me; I took it. And his mother said, Blessed be thou of the LORD, my son.","words":[["H0559","And he said",0,11],["H0517","unto his mother",12,27],["H0505","The eleven hundred",29,47],["H3967","The eleven hundred",29,47],["H3701","shekels of silver",48,65],["H3947","that were taken",66,81],["H0422","from thee, about which thou cursedst",82,118],["H0559","and spakest",120,131],["H0241","of also in mine ears",132,152],["H3701","behold, the silver",154,172],["H3947","is with me; I took",173,191],["H0517","it. And his mother",192,210],["H0559","said",211,215],["H1288","Blessed",217,224],["H3068","be thou of the LORD",225,244],["H1121","my son",246,252]]},"17:3":{"text":"And when he had restored the eleven hundred shekels of silver to his mother, his mother said, I had wholly dedicated the silver unto the LORD from my hand for my son, to make a graven image and a molten image: now therefore I will restore it unto thee.","words":[["H7725","And when he had restored",0,24],["H0505","the eleven hundred",25,43],["H3967","the eleven hundred",25,43],["H3701","shekels of silver",44,61],["H0517","to his mother",62,75],["H0517","his mother",77,87],["H0559","said",88,92],["H6942","I had wholly",94,106],["H6942","dedicated",107,116],["H3701","the silver",117,127],["H3068","unto the LORD",128,141],["H3027","from my hand",142,154],["H1121","for my son",155,165],["H6213","to make",167,174],["H6459","a graven image",175,189],["H4541","and a molten image",190,208],["H7725","now therefore I will restore",210,238]]},"17:4":{"text":"Yet he restored the money unto his mother; and his mother took two hundred shekels of silver, and gave them to the founder, who made thereof a graven image and a molten image: and they were in the house of Micah.","words":[["H7725","Yet he restored",0,15],["H3701","the money",16,25],["H0517","unto his mother",26,41],["H0517","and his mother",43,57],["H3947","took",58,62],["H3967","two hundred",63,74],["H3701","shekels of silver",75,92],["H5414","and gave",94,102],["H6884","them to the founder",103,122],["H6213","who made",124,132],["H6459","thereof a graven image",133,155],["H4541","and a molten image",156,174],["H1004","and they were in the house",176,202],["H4321","of Micah",203,211]]},"17:5":{"text":"And the man Micah had an house of gods, and made an ephod, and teraphim, and consecrated one of his sons, who became his priest.","words":[["H0376","And the man",0,11],["H4318","Micah",12,17],["H1004","had an house",18,30],["H0430","of gods",31,38],["H6213","and made",40,48],["H0646","an ephod",49,57],["H8655","and teraphim",59,71],["H4390","and consecrated",73,88],["H3027","and consecrated",73,88],["H0259","one",89,92],["H1121","of his sons",93,104],["H3548","who became his priest",106,127]]},"17:6":{"text":"In those days there was no king in Israel, but every man did that which was right in his own eyes.","words":[["H3117","In those days",0,13],["H4428","there was no king",14,31],["H3478","in Israel",32,41],["H0376","but every man",43,56],["H6213","did",57,60],["H3477","that which was right",61,81],["H5869","in his own eyes",82,97]]},"17:7":{"text":"And there was a young man out of Bethlehemjudah of the family of Judah, who was a Levite, and he sojourned there.","words":[["H5288","And there was a young man",0,25],["H1035","out of Bethlehemjudah",26,47],["H3063","out of Bethlehemjudah",26,47],["H4940","of the family",48,61],["H3063","of Judah",62,70],["H3881","who was a Levite",72,88],["H1481","and he sojourned",90,106]]},"17:8":{"text":"And the man departed out of the city from Bethlehemjudah to sojourn where he could find a place: and he came to mount Ephraim to the house of Micah, as he journeyed.","words":[["H0376","And the man",0,11],["H3212","departed",12,20],["H5892","out of the city",21,36],["H1035","from Bethlehemjudah",37,56],["H3063","from Bethlehemjudah",37,56],["H1481","to sojourn",57,67],["H4672","where he could find",68,87],["H0935","a place: and he came",88,108],["H2022","to mount",109,117],["H0669","Ephraim",118,125],["H1004","to the house",126,138],["H4318","of Micah",139,147],["H6213","as he journeyed",149,164],["H1870","as he journeyed",149,164]]},"17:9":{"text":"And Micah said unto him, Whence comest thou? And he said unto him, I am a Levite of Bethlehemjudah, and I go to sojourn where I may find a place.","words":[["H4318","And Micah",0,9],["H0559","said",10,14],["H0370","unto him, Whence",15,31],["H0935","comest",32,38],["H0559","thou? And he said",39,56],["H3881","unto him, I am a Levite",57,80],["H1035","of Bethlehemjudah",81,98],["H3063","of Bethlehemjudah",81,98],["H1980","and I go",100,108],["H1481","to sojourn",109,119],["H4672","where I may find",120,136]]},"17:10":{"text":"And Micah said unto him, Dwell with me, and be unto me a father and a priest, and I will give thee ten shekels of silver by the year, and a suit of apparel, and thy victuals. So the Levite went in.","words":[["H4318","And Micah",0,9],["H0559","said",10,14],["H3427","unto him, Dwell",15,30],["H0001","with me, and be unto me a father",31,63],["H3548","and a priest",64,76],["H5414","and I will give",78,93],["H6235","thee ten",94,102],["H3701","shekels of silver",103,120],["H3117","by the year",121,132],["H6187","and a suit",134,144],["H0899","of apparel",145,155],["H4241","and thy victuals",157,173],["H3881","So the Levite",175,188],["H3212","went in",189,196]]},"17:11":{"text":"And the Levite was content to dwell with the man; and the young man was unto him as one of his sons.","words":[["H3881","And the Levite",0,14],["H2974","was content",15,26],["H3427","to dwell",27,35],["H0376","with the man",36,48],["H5288","and the young man",50,67],["H0259","was unto him as one",68,87],["H1121","of his sons",88,99]]},"17:12":{"text":"And Micah consecrated the Levite; and the young man became his priest, and was in the house of Micah.","words":[["H4318","And Micah",0,9],["H4390","consecrated",10,21],["H3027","consecrated",10,21],["H3881","the Levite",22,32],["H5288","and the young man",34,51],["H3548","became his priest",52,69],["H1004","and was in the house",71,91],["H4318","of Micah",92,100]]},"17:13":{"text":"Then said Micah, Now know I that the LORD will do me good, seeing I have a Levite to my priest.","words":[["H0559","Then said",0,9],["H4318","Micah",10,15],["H3045","Now know",17,25],["H3068","I that the LORD",26,41],["H3190","will do me good",42,57],["H3881","seeing I have a Levite",59,81],["H3548","to my priest",82,94]]},"18:1":{"text":"In those days there was no king in Israel: and in those days the tribe of the Danites sought them an inheritance to dwell in; for unto that day all their inheritance had not fallen unto them among the tribes of Israel.","words":[["H3117","In those days",0,13],["H4428","there was no king",14,31],["H3478","in Israel",32,41],["H3117","and in those days",43,60],["H7626","the tribe",61,70],["H1839","of the Danites",71,85],["H1245","sought",86,92],["H5159","them an inheritance",93,112],["H3427","to dwell in",113,124],["H3117","for unto that day",126,143],["H5159","all their inheritance",144,165],["H5307","had not fallen",166,180],["H8432","unto them among",181,196],["H7626","the tribes",197,207],["H3478","of Israel",208,217]]},"18:2":{"text":"And the children of Dan sent of their family five men from their coasts, men of valour, from Zorah, and from Eshtaol, to spy out the land, and to search it; and they said unto them, Go, search the land: who when they came to mount Ephraim, to the house of Micah, they lodged there.","words":[["H1121","And the children",0,16],["H1835","of Dan",17,23],["H7971","sent",24,28],["H4940","of their family",29,44],["H2568","five",45,49],["H0582","men",50,53],["H7098","from their coasts",54,71],["H1121","men",73,76],["H2428","of valour",77,86],["H6881","from Zorah",88,98],["H0847","and from Eshtaol",100,116],["H7270","to spy",118,124],["H0776","out the land",125,137],["H2713","and to search",139,152],["H0559","it; and they said",153,170],["H3212","unto them, Go",171,184],["H2713","search",186,192],["H0776","the land",193,201],["H0935","who when they came",203,221],["H2022","to mount",222,230],["H0669","Ephraim",231,238],["H1004","to the house",240,252],["H4318","of Micah",253,261],["H3885","they lodged",263,274]]},"18:3":{"text":"When they were by the house of Micah, they knew the voice of the young man the Levite: and they turned in thither, and said unto him, Who brought thee hither? and what makest thou in this place? and what hast thou here?","words":[["H1004","When they were by the house",0,27],["H4318","of Micah",28,36],["H5234","they knew",38,47],["H6963","the voice",48,57],["H5288","of the young man",58,74],["H3881","the Levite",75,85],["H5493","and they turned in",87,105],["H0559","thither, and said",106,123],["H0935","unto him, Who brought",124,145],["H1988","thee hither",146,157],["H6213","and what makest",159,174]]},"18:4":{"text":"And he said unto them, Thus and thus dealeth Micah with me, and hath hired me, and I am his priest.","words":[["H0559","And he said",0,11],["H2090","unto them, Thus",12,27],["H2090","and thus",28,36],["H6213","dealeth",37,44],["H4318","Micah",45,50],["H7936","with me, and hath hired",51,74],["H3548","me, and I am his priest",75,98]]},"18:5":{"text":"And they said unto him, Ask counsel, we pray thee, of God, that we may know whether our way which we go shall be prosperous.","words":[["H0559","And they said",0,13],["H7592","unto him, Ask counsel",14,35],["H0430","we pray thee, of God",37,57],["H3045","that we may know",59,75],["H1870","whether our way",76,91],["H1980","which we go",92,103],["H6743","shall be prosperous",104,123]]},"18:6":{"text":"And the priest said unto them, Go in peace: before the LORD is your way wherein ye go.","words":[["H3548","And the priest",0,14],["H0559","said",15,19],["H3212","unto them, Go",20,33],["H7965","in peace",34,42],["H5227","before",44,50],["H3068","the LORD",51,59],["H1870","is your way",60,71],["H3212","wherein ye go",72,85]]},"18:7":{"text":"Then the five men departed, and came to Laish, and saw the people that were therein, how they dwelt careless, after the manner of the Zidonians, quiet and secure; and there was no magistrate in the land, that might put them to shame in any thing; and they were far from the Zidonians, and had no business with any man.","words":[["H2568","Then the five",0,13],["H0582","men",14,17],["H3212","departed",18,26],["H0935","and came",28,36],["H3919","to Laish",37,45],["H7200","and saw",47,54],["H5971","the people",55,65],["H7130","that were therein",66,83],["H3427","how they dwelt",85,99],["H0983","careless",100,108],["H4941","after the manner",110,126],["H6722","of the Zidonians",127,143],["H8252","quiet",145,150],["H0982","and secure",151,161],["H3423","and there was no magistrate",163,190],["H6114","and there was no magistrate",163,190],["H0776","in the land",191,202],["H3637","that might put them to shame",204,232],["H1697","in any thing",233,245],["H7350","and they were far",247,264],["H6722","from the Zidonians",265,283],["H1697","and had no business",285,304],["H0120","with any man",305,317]]},"18:8":{"text":"And they came unto their brethren to Zorah and Eshtaol: and their brethren said unto them, What say ye?","words":[["H0935","And they came",0,13],["H0251","unto their brethren",14,33],["H6881","to Zorah",34,42],["H0847","and Eshtaol",43,54],["H0251","and their brethren",56,74],["H0559","said",75,79]]},"18:9":{"text":"And they said, Arise, that we may go up against them: for we have seen the land, and, behold, it is very good: and are ye still? be not slothful to go, and to enter to possess the land.","words":[["H0559","And they said",0,13],["H6965","Arise",15,20],["H5927","that we may go up",22,39],["H7200","against them: for we have seen",40,70],["H0776","the land",71,79],["H3966","and, behold, it is very",81,104],["H2896","good",105,109],["H2814","and are ye still",111,127],["H6101","be not slothful",129,144],["H3212","to go",145,150],["H0935","and to enter",152,164],["H3423","to possess",165,175],["H0776","the land",176,184]]},"18:10":{"text":"When ye go, ye shall come unto a people secure, and to a large land: for God hath given it into your hands; a place where there is no want of any thing that is in the earth.","words":[["H0935","When ye go",0,10],["H0935","ye shall come",12,25],["H5971","unto a people",26,39],["H0982","secure",40,46],["H7342","and to a large",48,62],["H0776","land",63,67],["H0430","for God",69,76],["H5414","hath given",77,87],["H3027","it into your hands",88,106],["H4725","a place",108,115],["H4270","where there is no want",116,138],["H1697","of any thing",139,151],["H0776","that is in the earth",152,172]]},"18:11":{"text":"And there went from thence of the family of the Danites, out of Zorah and out of Eshtaol, six hundred men appointed with weapons of war.","words":[["H5265","And there went",0,14],["H4940","from thence of the family",15,40],["H1839","of the Danites",41,55],["H6881","out of Zorah",57,69],["H0847","and out of Eshtaol",70,88],["H8337","six",90,93],["H3967","hundred",94,101],["H0376","men",102,105],["H2296","appointed",106,115],["H3627","with weapons",116,128],["H4421","of war",129,135]]},"18:12":{"text":"And they went up, and pitched in Kirjathjearim, in Judah: wherefore they called that place Mahanehdan unto this day: behold, it is behind Kirjathjearim.","words":[["H5927","And they went up",0,16],["H2583","and pitched",18,29],["H7157","in Kirjathjearim",30,46],["H3063","in Judah",48,56],["H7121","wherefore they called",58,79],["H4725","that place",80,90],["H4265","Mahanehdan",91,101],["H3117","unto this day",102,115],["H0310","behold, it is behind",117,137],["H7157","Kirjathjearim",138,151]]},"18:13":{"text":"And they passed thence unto mount Ephraim, and came unto the house of Micah.","words":[["H5674","And they passed",0,15],["H2022","thence unto mount",16,33],["H0669","Ephraim",34,41],["H0935","and came",43,51],["H1004","unto the house",52,66],["H4318","of Micah",67,75]]},"18:14":{"text":"Then answered the five men that went to spy out the country of Laish, and said unto their brethren, Do ye know that there is in these houses an ephod, and teraphim, and a graven image, and a molten image? now therefore consider what ye have to do.","words":[["H6030","Then answered",0,13],["H2568","the five",14,22],["H0582","men",23,26],["H1980","that went",27,36],["H7270","to spy out",37,47],["H0776","the country",48,59],["H3919","of Laish",60,68],["H0559","and said",70,78],["H0251","unto their brethren",79,98],["H3045","Do ye know",100,110],["H3426","that there is",111,124],["H1004","in these houses",125,140],["H0646","an ephod",141,149],["H8655","and teraphim",151,163],["H6459","and a graven image",165,183],["H4541","and a molten image",185,203],["H3045","now therefore consider",205,227],["H6213","what ye have to do",228,246]]},"18:15":{"text":"And they turned thitherward, and came to the house of the young man the Levite, even unto the house of Micah, and saluted him.","words":[["H5493","And they turned",0,15],["H0935","thitherward, and came",16,37],["H1004","to the house",38,50],["H5288","of the young man",51,67],["H3881","the Levite",68,78],["H1004","even unto the house",80,99],["H4318","of Micah",100,108],["H7592","and saluted",110,121],["H7965","and saluted",110,121]]},"18:16":{"text":"And the six hundred men appointed with their weapons of war, which were of the children of Dan, stood by the entering of the gate.","words":[["H8337","And the six",0,11],["H3967","hundred",12,19],["H0376","men",20,23],["H2296","appointed",24,33],["H3627","with their weapons",34,52],["H4421","of war",53,59],["H1121","which were of the children",61,87],["H1835","of Dan",88,94],["H5324","stood",96,101],["H6607","by the entering",102,117],["H8179","of the gate",118,129]]},"18:17":{"text":"And the five men that went to spy out the land went up, and came in thither, and took the graven image, and the ephod, and the teraphim, and the molten image: and the priest stood in the entering of the gate with the six hundred men that were appointed with weapons of war.","words":[["H2568","And the five",0,12],["H0582","men",13,16],["H1980","that went",17,26],["H7270","to spy out",27,37],["H0776","the land",38,46],["H5927","went up",47,54],["H0935","and came in",56,67],["H3947","thither, and took",68,85],["H6459","the graven image",86,102],["H0646","and the ephod",104,117],["H8655","and the teraphim",119,135],["H4541","and the molten image",137,157],["H3548","and the priest",159,173],["H5324","stood",174,179],["H6607","in the entering",180,195],["H8179","of the gate",196,207],["H8337","with the six",208,220],["H3967","hundred",221,228],["H0376","men",229,232],["H2296","that were appointed",233,252],["H3627","with weapons",253,265],["H4421","of war",266,272]]},"18:18":{"text":"And these went into Micah's house, and fetched the carved image, the ephod, and the teraphim, and the molten image. Then said the priest unto them, What do ye?","words":[["H0935","And these went",0,14],["H4318","into Micah's",15,27],["H1004","house",28,33],["H3947","and fetched",35,46],["H6459","the carved image",47,63],["H0646","the ephod",65,74],["H8655","and the teraphim",76,92],["H4541","and the molten image",94,114],["H0559","Then said",116,125],["H3548","the priest",126,136],["H6213","unto them, What do",137,155]]},"18:19":{"text":"And they said unto him, Hold thy peace, lay thine hand upon thy mouth, and go with us, and be to us a father and a priest: is it better for thee to be a priest unto the house of one man, or that thou be a priest unto a tribe and a family in Israel?","words":[["H0559","And they said",0,13],["H2790","unto him, Hold thy peace",14,38],["H7760","lay",40,43],["H3027","thine hand",44,54],["H6310","upon thy mouth",55,69],["H3212","and go",71,77],["H1961","with us, and be to us",78,99],["H0001","a father",100,108],["H3548","and a priest",109,121],["H2896","is it better",123,135],["H3548","for thee to be a priest",136,159],["H1004","unto the house",160,174],["H0259","of one",175,181],["H0376","man",182,185],["H3548","or that thou be a priest",187,211],["H7626","unto a tribe",212,224],["H4940","and a family",225,237],["H3478","in Israel",238,247]]},"18:20":{"text":"And the priest's heart was glad, and he took the ephod, and the teraphim, and the graven image, and went in the midst of the people.","words":[["H3548","And the priest's",0,16],["H3820","heart",17,22],["H3190","was glad",23,31],["H3947","and he took",33,44],["H0646","the ephod",45,54],["H8655","and the teraphim",56,72],["H6459","and the graven image",74,94],["H0935","and went in",96,107],["H7130","the midst",108,117],["H5971","of the people",118,131]]},"18:21":{"text":"So they turned and departed, and put the little ones and the cattle and the carriage before them.","words":[["H6437","So they turned",0,14],["H3212","and departed",15,27],["H7760","and put",29,36],["H2945","the little ones",37,52],["H4735","and the cattle",53,67],["H3520","and the carriage",68,84],["H6440","before",85,91]]},"18:22":{"text":"And when they were a good way from the house of Micah, the men that were in the houses near to Micah's house were gathered together, and overtook the children of Dan.","words":[["H7368","And when they were a good way",0,29],["H1004","from the house",30,44],["H4318","of Micah",45,53],["H0582","the men",55,62],["H1004","that were in the houses",63,86],["H4318","near to Micah's",87,102],["H1004","house",103,108],["H2199","were gathered together",109,131],["H1692","and overtook",133,145],["H1121","the children",146,158],["H1835","of Dan",159,165]]},"18:23":{"text":"And they cried unto the children of Dan. And they turned their faces, and said unto Micah, What aileth thee, that thou comest with such a company?","words":[["H7121","And they cried",0,14],["H1121","unto the children",15,32],["H1835","of Dan",33,39],["H5437","And they turned",41,56],["H6440","their faces",57,68],["H0559","and said",70,78],["H4318","unto Micah",79,89],["H2199","What aileth thee, that thou comest with such a company",91,145]]},"18:24":{"text":"And he said, Ye have taken away my gods which I made, and the priest, and ye are gone away: and what have I more? and what is this that ye say unto me, What aileth thee?","words":[["H0559","And he said",0,11],["H3947","Ye have taken away",13,31],["H0430","my gods",32,39],["H6213","which I made",40,52],["H3548","and the priest",54,68],["H3212","and ye are gone away",70,90],["H0559","and what have I more? and what is this that ye say",92,142]]},"18:25":{"text":"And the children of Dan said unto him, Let not thy voice be heard among us, lest angry fellows run upon thee, and thou lose thy life, with the lives of thy household.","words":[["H1121","And the children",0,16],["H1835","of Dan",17,23],["H0559","said",24,28],["H6963","unto him, Let not thy voice",29,56],["H8085","be heard",57,65],["H4751","among us, lest angry",66,86],["H5315","among us, lest angry",66,86],["H0582","fellows",87,94],["H6293","run",95,98],["H0622","upon thee, and thou lose",99,123],["H5315","thy life",124,132],["H5315","with the lives",134,148],["H1004","of thy household",149,165]]},"18:26":{"text":"And the children of Dan went their way: and when Micah saw that they were too strong for him, he turned and went back unto his house.","words":[["H1121","And the children",0,16],["H1835","of Dan",17,23],["H3212","went",24,28],["H1870","their way",29,38],["H4318","and when Micah",40,54],["H7200","saw",55,58],["H2389","that they were too strong",59,84],["H6437","for him, he turned",85,103],["H7725","and went back",104,117],["H1004","unto his house",118,132]]},"18:27":{"text":"And they took the things which Micah had made, and the priest which he had, and came unto Laish, unto a people that were at quiet and secure: and they smote them with the edge of the sword, and burnt the city with fire.","words":[["H3947","And they took",0,13],["H4318","the things which Micah",14,36],["H6213","had made",37,45],["H3548","and the priest",47,61],["H0935","which he had, and came",62,84],["H3919","unto Laish",85,95],["H5971","unto a people",97,110],["H8252","that were at quiet",111,129],["H0982","and secure",130,140],["H5221","and they smote",142,156],["H6310","them with the edge",157,175],["H2719","of the sword",176,188],["H8313","and burnt",190,199],["H5892","the city",200,208],["H0784","with fire",209,218]]},"18:28":{"text":"And there was no deliverer, because it was far from Zidon, and they had no business with any man; and it was in the valley that lieth by Bethrehob. And they built a city, and dwelt therein.","words":[["H5337","And there was no deliverer",0,26],["H7350","because it was far",28,46],["H6721","from Zidon",47,57],["H1697","and they had no business",59,83],["H0120","with any man",84,96],["H6010","and it was in the valley",98,122],["H1050","that lieth by Bethrehob",123,146],["H1129","And they built",148,162],["H5892","a city",163,169],["H3427","and dwelt",171,180]]},"18:29":{"text":"And they called the name of the city Dan, after the name of Dan their father, who was born unto Israel: howbeit the name of the city was Laish at the first.","words":[["H7121","And they called",0,15],["H8034","the name",16,24],["H5892","of the city",25,36],["H1835","Dan",37,40],["H8034","after the name",42,56],["H1835","of Dan",57,63],["H0001","their father",64,76],["H3205","who was born",78,90],["H3478","unto Israel",91,102],["H0199","howbeit",104,111],["H8034","the name",112,120],["H5892","of the city",121,132],["H3919","was Laish",133,142],["H7223","at the first",143,155]]},"18:30":{"text":"And the children of Dan set up the graven image: and Jonathan, the son of Gershom, the son of Manasseh, he and his sons were priests to the tribe of Dan until the day of the captivity of the land.","words":[["H1121","And the children",0,16],["H1835","of Dan",17,23],["H6965","set up",24,30],["H6459","the graven image",31,47],["H3083","and Jonathan",49,61],["H1121","the son",63,70],["H1647","of Gershom",71,81],["H1121","the son",83,90],["H4519","of Manasseh",91,102],["H1121","he and his sons",104,119],["H3548","were priests",120,132],["H7626","to the tribe",133,145],["H1839","of Dan",146,152],["H3117","until the day",153,166],["H1540","of the captivity",167,183],["H0776","of the land",184,195]]},"18:31":{"text":"And they set them up Micah's graven image, which he made, all the time that the house of God was in Shiloh.","words":[["H7760","And they set them up",0,20],["H4318","Micah's",21,28],["H6459","graven image",29,41],["H6213","which he made",43,56],["H3117","all the time",58,70],["H1004","that the house",71,85],["H0430","of God",86,92],["H7887","was in Shiloh",93,106]]},"19:1":{"text":"And it came to pass in those days, when there was no king in Israel, that there was a certain Levite sojourning on the side of mount Ephraim, who took to him a concubine out of Bethlehemjudah.","words":[["H3117","And it came to pass in those days",0,33],["H4428","when there was no king",35,57],["H3478","in Israel",58,67],["H0376","that there was a certain",69,93],["H3881","Levite",94,100],["H1481","sojourning",101,111],["H3411","on the side",112,123],["H2022","of mount",124,132],["H0669","Ephraim",133,140],["H3947","who took",142,150],["H0802","to him a concubine",151,169],["H6370","to him a concubine",151,169],["H1035","out of Bethlehemjudah",170,191],["H3063","out of Bethlehemjudah",170,191]]},"19:2":{"text":"And his concubine played the whore against him, and went away from him unto her father's house to Bethlehemjudah, and was there four whole months.","words":[["H6370","And his concubine",0,17],["H2181","played the whore",18,34],["H3212","against him, and went away",35,61],["H0001","from him unto her father's",62,88],["H1004","house",89,94],["H1035","to Bethlehemjudah",95,112],["H3063","to Bethlehemjudah",95,112],["H0702","and was there four",114,132],["H2320","whole months",133,145],["H3117","whole months",133,145]]},"19:3":{"text":"And her husband arose, and went after her, to speak friendly unto her, and to bring her again, having his servant with him, and a couple of asses: and she brought him into her father's house: and when the father of the damsel saw him, he rejoiced to meet him.","words":[["H0376","And her husband",0,15],["H6965","arose",16,21],["H3212","and went",23,31],["H0310","after",32,37],["H1696","her, to speak",38,51],["H3820","friendly",52,60],["H7725","unto her, and to bring her again",61,93],["H5288","having his servant",95,113],["H6776","with him, and a couple",114,136],["H2543","of asses",137,145],["H0935","and she brought",147,162],["H0001","him into her father's",163,184],["H1004","house",185,190],["H0001","and when the father",192,211],["H5291","of the damsel",212,225],["H7200","saw",226,229],["H8055","him, he rejoiced",230,246],["H7125","to meet",247,254]]},"19:4":{"text":"And his father in law, the damsel's father, retained him; and he abode with him three days: so they did eat and drink, and lodged there.","words":[["H2859","And his father in law",0,21],["H5291","the damsel's",23,35],["H0001","father",36,42],["H2388","retained",44,52],["H3427","him; and he abode",53,70],["H7969","with him three",71,85],["H3117","days",86,90],["H0398","so they did eat",92,107],["H8354","and drink",108,117],["H3885","and lodged",119,129]]},"19:5":{"text":"And it came to pass on the fourth day, when they arose early in the morning, that he rose up to depart: and the damsel's father said unto his son in law, Comfort thine heart with a morsel of bread, and afterward go your way.","words":[["H7243","And it came to pass on the fourth",0,33],["H3117","day",34,37],["H7925","when they arose early",39,60],["H1242","in the morning",61,75],["H6965","that he rose up",77,92],["H3212","to depart",93,102],["H5291","and the damsel's",104,120],["H0001","father",121,127],["H0559","said",128,132],["H2860","unto his son in law",133,152],["H5582","Comfort",154,161],["H3820","thine heart",162,173],["H6595","with a morsel",174,187],["H3899","of bread",188,196],["H0310","and afterward",198,211],["H3212","go your way",212,223]]},"19:6":{"text":"And they sat down, and did eat and drink both of them together: for the damsel's father had said unto the man, Be content, I pray thee, and tarry all night, and let thine heart be merry.","words":[["H3427","And they sat down",0,17],["H0398","and did eat",19,30],["H8354","and drink",31,40],["H8147","both",41,45],["H3162","of them together",46,62],["H5291","for the damsel's",64,80],["H0001","father",81,87],["H0559","had said",88,96],["H0376","unto the man",97,109],["H2974","Be content",111,121],["H3885","I pray thee, and tarry all night",123,155],["H3820","and let thine heart",157,176],["H3190","be merry",177,185]]},"19:7":{"text":"And when the man rose up to depart, his father in law urged him: therefore he lodged there again.","words":[["H0376","And when the man",0,16],["H6965","rose up",17,24],["H3212","to depart",25,34],["H2859","his father in law",36,53],["H6484","urged",54,59],["H3885","him: therefore he lodged",60,84],["H7725","there again",85,96]]},"19:8":{"text":"And he arose early in the morning on the fifth day to depart: and the damsel's father said, Comfort thine heart, I pray thee. And they tarried until afternoon, and they did eat both of them.","words":[["H7925","And he arose early",0,18],["H1242","in the morning",19,33],["H2549","on the fifth",34,46],["H3117","day",47,50],["H3212","to depart",51,60],["H5291","and the damsel's",62,78],["H0001","father",79,85],["H0559","said",86,90],["H5582","Comfort",92,99],["H3824","thine heart",100,111],["H4102","I pray thee. And they tarried",113,142],["H3117","until afternoon",143,158],["H5186","until afternoon",143,158],["H0398","and they did eat",160,176],["H8147","both",177,181]]},"19:9":{"text":"And when the man rose up to depart, he, and his concubine, and his servant, his father in law, the damsel's father, said unto him, Behold, now the day draweth toward evening, I pray you tarry all night: behold, the day groweth to an end, lodge here, that thine heart may be merry; and to morrow get you early on your way, that thou mayest go home.","words":[["H0376","And when the man",0,16],["H6965","rose up",17,24],["H3212","to depart",25,34],["H6370","he, and his concubine",36,57],["H5288","and his servant",59,74],["H2859","his father in law",76,93],["H5291","the damsel's",95,107],["H0001","father",108,114],["H0559","said",116,120],["H3117","unto him, Behold, now the day",121,150],["H7503","draweth",151,158],["H6150","toward evening",159,173],["H3885","I pray you tarry all night",175,201],["H3117","behold, the day",203,218],["H2583","groweth to an end",219,236],["H3885","lodge",238,243],["H3824","here, that thine heart",244,266],["H3190","may be merry",267,279],["H4279","and to morrow",281,294],["H7925","get you early",295,308],["H1870","on your way",309,320],["H1980","that thou mayest go",322,341],["H0168","home",342,346]]},"19:10":{"text":"But the man would not tarry that night, but he rose up and departed, and came over against Jebus, which is Jerusalem; and there were with him two asses saddled, his concubine also was with him.","words":[["H0376","But the man",0,11],["H0014","would",12,17],["H3885","not tarry that night",18,38],["H6965","but he rose up",40,54],["H3212","and departed",55,67],["H0935","and came",69,77],["H5227","over against",78,90],["H2982","Jebus",91,96],["H3389","which is Jerusalem",98,116],["H6776","and there were with him two",118,145],["H2543","asses",146,151],["H2280","saddled",152,159],["H6370","his concubine",161,174]]},"19:11":{"text":"And when they were by Jebus, the day was far spent; and the servant said unto his master, Come, I pray thee, and let us turn in into this city of the Jebusites, and lodge in it.","words":[["H2982","And when they were by Jebus",0,27],["H3117","the day",29,36],["H3966","was far",37,44],["H7286","spent",45,50],["H5288","and the servant",52,67],["H0559","said",68,72],["H0113","unto his master",73,88],["H3212","Come",90,94],["H5493","I pray thee, and let us turn in",96,127],["H5892","into this city",128,142],["H2983","of the Jebusites",143,159],["H3885","and lodge",161,170]]},"19:12":{"text":"And his master said unto him, We will not turn aside hither into the city of a stranger, that is not of the children of Israel; we will pass over to Gibeah.","words":[["H0113","And his master",0,14],["H0559","said",15,19],["H5493","unto him, We will not turn aside",20,52],["H5892","hither into the city",53,73],["H5237","of a stranger",74,87],["H1121","that is not of the children",89,116],["H3478","of Israel",117,126],["H5674","we will pass over",128,145],["H1390","to Gibeah",146,155]]},"19:13":{"text":"And he said unto his servant, Come, and let us draw near to one of these places to lodge all night, in Gibeah, or in Ramah.","words":[["H0559","And he said",0,11],["H5288","unto his servant",12,28],["H3212","Come",30,34],["H7126","and let us draw near",36,56],["H0259","to one",57,63],["H4725","of these places",64,79],["H3885","to lodge all night",80,98],["H1390","in Gibeah",100,109],["H7414","or in Ramah",111,122]]},"19:14":{"text":"And they passed on and went their way; and the sun went down upon them when they were by Gibeah, which belongeth to Benjamin.","words":[["H5674","And they passed on",0,18],["H3212","and went their way",19,37],["H8121","and the sun",39,50],["H0935","went down",51,60],["H0681","upon them when they were by",61,88],["H1390","Gibeah",89,95],["H1144","which belongeth to Benjamin",97,124]]},"19:15":{"text":"And they turned aside thither, to go in and to lodge in Gibeah: and when he went in, he sat him down in a street of the city: for there was no man that took them into his house to lodging.","words":[["H5493","And they turned aside",0,21],["H0935","thither, to go in",22,39],["H3885","and to lodge",40,52],["H1390","in Gibeah",53,62],["H0935","and when he went in",64,83],["H3427","he sat him down",85,100],["H7339","in a street",101,112],["H5892","of the city",113,124],["H0376","for there was no man",126,146],["H0622","that took",147,156],["H1004","them into his house",157,176],["H3885","to lodging",177,187]]},"19:16":{"text":"And, behold, there came an old man from his work out of the field at even, which was also of mount Ephraim; and he sojourned in Gibeah: but the men of the place were Benjamites.","words":[["H0935","And, behold, there came",0,23],["H2205","an old",24,30],["H0376","man",31,34],["H4639","from his work",35,48],["H7704","out of the field",49,65],["H6153","at even",66,73],["H0376","which was also",75,89],["H2022","of mount",90,98],["H0669","Ephraim",99,106],["H1481","and he sojourned",108,124],["H1390","in Gibeah",125,134],["H0582","but the men",136,147],["H4725","of the place",148,160],["H1145","were Benjamites",161,176]]},"19:17":{"text":"And when he had lifted up his eyes, he saw a wayfaring man in the street of the city: and the old man said, Whither goest thou? and whence comest thou?","words":[["H5375","And when he had lifted up",0,25],["H5869","his eyes",26,34],["H7200","he saw",36,42],["H0732","a wayfaring",43,54],["H0376","man",55,58],["H7339","in the street",59,72],["H5892","of the city",73,84],["H2205","and the old",86,97],["H0376","man",98,101],["H0559","said",102,106],["H3212","Whither goest",108,121],["H0370","thou? and whence",122,138],["H0935","comest",139,145]]},"19:18":{"text":"And he said unto him, We are passing from Bethlehemjudah toward the side of mount Ephraim; from thence am I: and I went to Bethlehemjudah, but I am now going to the house of the LORD; and there is no man that receiveth me to house.","words":[["H0559","And he said",0,11],["H5674","unto him, We are passing",12,36],["H1035","from Bethlehemjudah",37,56],["H3063","from Bethlehemjudah",37,56],["H3411","toward the side",57,72],["H2022","of mount",73,81],["H0669","Ephraim",82,89],["H3212","from thence am I: and I went",91,119],["H1035","to Bethlehemjudah",120,137],["H3063","to Bethlehemjudah",120,137],["H1980","but I am now going",139,157],["H1004","to the house",158,170],["H3068","of the LORD",171,182],["H0376","and there is no man",184,203],["H0622","that receiveth",204,218],["H1004","me to house",219,230]]},"19:19":{"text":"Yet there is both straw and provender for our asses; and there is bread and wine also for me, and for thy handmaid, and for the young man which is with thy servants: there is no want of any thing.","words":[["H3426","Yet there is",0,12],["H8401","both straw",13,23],["H4554","and provender",24,37],["H2543","for our asses",38,51],["H3899","and there is bread",53,71],["H3196","and wine",72,80],["H0519","also for me, and for thy handmaid",81,114],["H5288","and for the young man",116,137],["H5650","which is with thy servants",138,164],["H4270","there is no want",166,182],["H1697","of any thing",183,195]]},"19:20":{"text":"And the old man said, Peace be with thee; howsoever let all thy wants lie upon me; only lodge not in the street.","words":[["H2205","And the old",0,11],["H0376","man",12,15],["H0559","said",16,20],["H7965","Peace",22,27],["H7535","be with thee; howsoever",28,51],["H4270","let all thy wants",52,69],["H3885","lie upon me; only lodge",70,93],["H7339","not in the street",94,111]]},"19:21":{"text":"So he brought him into his house, and gave provender unto the asses: and they washed their feet, and did eat and drink.","words":[["H0935","So he brought",0,13],["H1004","him into his house",14,32],["H1101","and gave provender",34,52],["H2543","unto the asses",53,67],["H7364","and they washed",69,84],["H7272","their feet",85,95],["H0398","and did eat",97,108],["H8354","and drink",109,118]]},"19:22":{"text":"Now as they were making their hearts merry, behold, the men of the city, certain sons of Belial, beset the house round about, and beat at the door, and spake to the master of the house, the old man, saying, Bring forth the man that came into thine house, that we may know him.","words":[["H3820","Now as they were making their hearts",0,36],["H3190","merry",37,42],["H0582","behold, the men",44,59],["H5892","of the city",60,71],["H0582","certain",73,80],["H1121","sons",81,85],["H1100","of Belial",86,95],["H5437","beset",97,102],["H1004","the house",103,112],["H5437","round about",113,124],["H1849","and beat",126,134],["H1817","at the door",135,146],["H0559","and spake",148,157],["H1167","to the master",158,171],["H1004","of the house",172,184],["H2205","the old",186,193],["H0376","man",194,197],["H0559","saying",199,205],["H3318","Bring forth",207,218],["H0376","the man",219,226],["H0935","that came",227,236],["H1004","into thine house",237,253],["H3045","that we may know",255,271]]},"19:23":{"text":"And the man, the master of the house, went out unto them, and said unto them, Nay, my brethren, nay, I pray you, do not so wickedly; seeing that this man is come into mine house, do not this folly.","words":[["H0376","And the man",0,11],["H1167","the master",13,23],["H1004","of the house",24,36],["H3318","went out",38,46],["H0559","unto them, and said",47,66],["H0408","unto them, Nay",67,81],["H0251","my brethren",83,94],["H7489","nay, I pray you, do not so wickedly",96,131],["H0310","seeing",133,139],["H0376","that this man",140,153],["H0935","is come",154,161],["H1004","into mine house",162,177],["H6213","do",179,181],["H5039","not this folly",182,196]]},"19:24":{"text":"Behold, here is my daughter a maiden, and his concubine; them I will bring out now, and humble ye them, and do with them what seemeth good unto you: but unto this man do not so vile a thing.","words":[["H1323","Behold, here is my daughter",0,27],["H1330","a maiden",28,36],["H6370","and his concubine",38,55],["H3318","them I will bring out",57,78],["H6031","now, and humble",79,94],["H6213","ye them, and do",95,110],["H5869","with them what seemeth",111,133],["H2896","good",134,138],["H0376","unto you: but unto this man",139,166],["H6213","do",167,169],["H2063","not so",170,176],["H5039","vile",177,181],["H1697","a thing",182,189]]},"19:25":{"text":"But the men would not hearken to him: so the man took his concubine, and brought her forth unto them; and they knew her, and abused her all the night until the morning: and when the day began to spring, they let her go.","words":[["H0582","But the men",0,11],["H0014","would",12,17],["H8085","not hearken",18,29],["H0376","to him: so the man",30,48],["H2388","took",49,53],["H6370","his concubine",54,67],["H3318","and brought",69,80],["H2351","her forth",81,90],["H3045","unto them; and they knew",91,115],["H5953","her, and abused",116,131],["H3915","her all the night",132,149],["H1242","until the morning",150,167],["H7837","and when the day",169,185],["H5927","began to spring",186,201],["H7971","they let her go",203,218]]},"19:26":{"text":"Then came the woman in the dawning of the day, and fell down at the door of the man's house where her lord was, till it was light.","words":[["H0935","Then came",0,9],["H0802","the woman",10,19],["H6437","in the dawning",20,34],["H1242","of the day",35,45],["H5307","and fell down",47,60],["H6607","at the door",61,72],["H0376","of the man's",73,85],["H1004","house",86,91],["H0113","where her lord",92,106],["H0216","was, till it was light",107,129]]},"19:27":{"text":"And her lord rose up in the morning, and opened the doors of the house, and went out to go his way: and, behold, the woman his concubine was fallen down at the door of the house, and her hands were upon the threshold.","words":[["H0113","And her lord",0,12],["H6965","rose up",13,20],["H1242","in the morning",21,35],["H6605","and opened",37,47],["H1817","the doors",48,57],["H1004","of the house",58,70],["H3318","and went out",72,84],["H3212","to go",85,90],["H1870","his way",91,98],["H0802","and, behold, the woman",100,122],["H6370","his concubine",123,136],["H5307","was fallen down",137,152],["H6607","at the door",153,164],["H1004","of the house",165,177],["H3027","and her hands",179,192],["H5592","were upon the threshold",193,216]]},"19:28":{"text":"And he said unto her, Up, and let us be going. But none answered. Then the man took her up upon an ass, and the man rose up, and gat him unto his place.","words":[["H0559","And he said",0,11],["H6965","unto her, Up",12,24],["H3212","and let us be going",26,45],["H6030","But none answered",47,64],["H0376","Then the man",66,78],["H3947","took",79,83],["H2543","her up upon an ass",84,102],["H0376","and the man",104,115],["H6965","rose up",116,123],["H3212","and gat",125,132],["H4725","him unto his place",133,151]]},"19:29":{"text":"And when he was come into his house, he took a knife, and laid hold on his concubine, and divided her, together with her bones, into twelve pieces, and sent her into all the coasts of Israel.","words":[["H0935","And when he was come",0,20],["H1004","into his house",21,35],["H3947","he took",37,44],["H3979","a knife",45,52],["H2388","and laid hold",54,67],["H6370","on his concubine",68,84],["H5408","and divided",86,97],["H6106","her, together with her bones",98,126],["H8147","into twelve",128,139],["H6240","into twelve",128,139],["H5409","pieces",140,146],["H7971","and sent",148,156],["H1366","her into all the coasts",157,180],["H3478","of Israel",181,190]]},"19:30":{"text":"And it was so, that all that saw it said, There was no such deed done nor seen from the day that the children of Israel came up out of the land of Egypt unto this day: consider of it, take advice, and speak your minds.","words":[["H1961","And it was so",0,13],["H7200","that all that saw",15,32],["H0559","it said",33,40],["H2063","There was no such deed",42,64],["H7200","done nor seen",65,78],["H3117","from the day",79,91],["H1121","that the children",92,109],["H3478","of Israel",110,119],["H5927","came up",120,127],["H0776","out of the land",128,143],["H4714","of Egypt",144,152],["H3117","unto this day",153,166],["H7760","consider",168,176],["H5779","of it, take advice",177,195],["H1696","and speak",197,206]]},"20:1":{"text":"Then all the children of Israel went out, and the congregation was gathered together as one man, from Dan even to Beersheba, with the land of Gilead, unto the LORD in Mizpeh.","words":[["H1121","Then all the children",0,21],["H3478","of Israel",22,31],["H3318","went out",32,40],["H5712","and the congregation",42,62],["H6950","was gathered together",63,84],["H0259","as one",85,91],["H0376","man",92,95],["H1835","from Dan",97,105],["H0884","even to Beersheba",106,123],["H0776","with the land",125,138],["H1568","of Gilead",139,148],["H3068","unto the LORD",150,163],["H4709","in Mizpeh",164,173]]},"20:2":{"text":"And the chief of all the people, even of all the tribes of Israel, presented themselves in the assembly of the people of God, four hundred thousand footmen that drew sword.","words":[["H6438","And the chief",0,13],["H5971","of all the people",14,31],["H7626","even of all the tribes",33,55],["H3478","of Israel",56,65],["H3320","presented",67,76],["H6951","themselves in the assembly",77,103],["H5971","of the people",104,117],["H0430","of God",118,124],["H0702","four",126,130],["H3967","hundred",131,138],["H0505","thousand",139,147],["H0376","footmen",148,155],["H7273","footmen",148,155],["H8025","that drew",156,165],["H2719","sword",166,171]]},"20:3":{"text":"(Now the children of Benjamin heard that the children of Israel were gone up to Mizpeh.) Then said the children of Israel, Tell us, how was this wickedness?","words":[["H1121","(Now the children",0,17],["H1144","of Benjamin",18,29],["H8085","heard",30,35],["H1121","that the children",36,53],["H3478","of Israel",54,63],["H5927","were gone up",64,76],["H4709","to Mizpeh",77,86],["H0559",") Then said",87,98],["H1121","the children",99,111],["H3478","of Israel",112,121],["H1696","Tell",123,127],["H1961","us, how was",128,139],["H7451","this wickedness",140,155]]},"20:4":{"text":"And the Levite, the husband of the woman that was slain, answered and said, I came into Gibeah that belongeth to Benjamin, I and my concubine, to lodge.","words":[["H3881","And the Levite",0,14],["H0376","And the Levite",0,14],["H0376","the husband",16,27],["H0802","of the woman",28,40],["H7523","that was slain",41,55],["H6030","answered",57,65],["H0559","and said",66,74],["H0935","I came",76,82],["H1390","into Gibeah",83,94],["H1144","that belongeth to Benjamin",95,121],["H6370","I and my concubine",123,141],["H3885","to lodge",143,151]]},"20:5":{"text":"And the men of Gibeah rose against me, and beset the house round about upon me by night, and thought to have slain me: and my concubine have they forced, that she is dead.","words":[["H1167","And the men",0,11],["H1390","of Gibeah",12,21],["H6965","rose",22,26],["H5437","against me, and beset",27,48],["H1004","the house",49,58],["H5437","round about",59,70],["H3915","upon me by night",71,87],["H1819","and thought",89,100],["H2026","to have slain",101,114],["H6370","me: and my concubine",115,135],["H6031","have they forced",136,152],["H4191","that she is dead",154,170]]},"20:6":{"text":"And I took my concubine, and cut her in pieces, and sent her throughout all the country of the inheritance of Israel: for they have committed lewdness and folly in Israel.","words":[["H0270","And I took",0,10],["H6370","my concubine",11,23],["H5408","and cut her in pieces",25,46],["H7971","and sent",48,56],["H7704","her throughout all the country",57,87],["H5159","of the inheritance",88,106],["H3478","of Israel",107,116],["H6213","for they have committed",118,141],["H2154","lewdness",142,150],["H5039","and folly",151,160],["H3478","in Israel",161,170]]},"20:7":{"text":"Behold, ye are all children of Israel; give here your advice and counsel.","words":[["H1121","Behold, ye are all children",0,27],["H3478","of Israel",28,37],["H3051","give",39,43],["H1988","here",44,48],["H1697","your advice",49,60],["H6098","and counsel",61,72]]},"20:8":{"text":"And all the people arose as one man, saying, We will not any of us go to his tent, neither will we any of us turn into his house.","words":[["H5971","And all the people",0,18],["H6965","arose",19,24],["H0259","as one",25,31],["H0376","man",32,35],["H0559","saying",37,43],["H0376","We will not any",45,60],["H3212","of us go",61,69],["H0168","to his tent",70,81],["H0376","neither will we any",83,102],["H5493","of us turn",103,113],["H1004","into his house",114,128]]},"20:9":{"text":"But now this shall be the thing which we will do to Gibeah; we will go up by lot against it;","words":[["H1697","But now this shall be the thing",0,31],["H6213","which we will do",32,48],["H1390","to Gibeah",49,58],["H1486","we will go up by lot",60,80]]},"20:10":{"text":"And we will take ten men of an hundred throughout all the tribes of Israel, and an hundred of a thousand, and a thousand out of ten thousand, to fetch victual for the people, that they may do, when they come to Gibeah of Benjamin, according to all the folly that they have wrought in Israel.","words":[["H3947","And we will take",0,16],["H6235","ten",17,20],["H0582","men",21,24],["H3967","of an hundred",25,38],["H7626","throughout all the tribes",39,64],["H3478","of Israel",65,74],["H3967","and an hundred",76,90],["H0505","of a thousand",91,104],["H0505","and a thousand",106,120],["H7233","out of ten thousand",121,140],["H3947","to fetch",142,150],["H6720","victual",151,158],["H5971","for the people",159,173],["H6213","that they may do",175,191],["H0935","when they come",193,207],["H1387","to Gibeah",208,217],["H1144","of Benjamin",218,229],["H5039","according to all the folly",231,257],["H6213","that they have wrought",258,280],["H3478","in Israel",281,290]]},"20:11":{"text":"So all the men of Israel were gathered against the city, knit together as one man.","words":[["H0376","So all the men",0,14],["H3478","of Israel",15,24],["H0622","were gathered",25,38],["H5892","against the city",39,55],["H2270","knit together",57,70],["H0259","as one",71,77],["H0376","man",78,81]]},"20:12":{"text":"And the tribes of Israel sent men through all the tribe of Benjamin, saying, What wickedness is this that is done among you?","words":[["H7626","And the tribes",0,14],["H3478","of Israel",15,24],["H7971","sent",25,29],["H0582","men",30,33],["H7626","through all the tribe",34,55],["H1144","of Benjamin",56,67],["H0559","saying",69,75],["H7451","What wickedness",77,92],["H1961","is this that is done",93,113]]},"20:13":{"text":"Now therefore deliver us the men, the children of Belial, which are in Gibeah, that we may put them to death, and put away evil from Israel. But the children of Benjamin would not hearken to the voice of their brethren the children of Israel:","words":[["H5414","Now therefore deliver",0,21],["H0582","us the men",22,32],["H1121","the children",34,46],["H1100","of Belial",47,56],["H1390","which are in Gibeah",58,77],["H4191","that we may put them to death",79,108],["H1197","and put away",110,122],["H7451","evil",123,127],["H3478","from Israel",128,139],["H1121","But the children",141,157],["H1144","of Benjamin",158,169],["H0014","would",170,175],["H8085","not hearken",176,187],["H6963","to the voice",188,200],["H0251","of their brethren",201,218],["H1121","the children",219,231],["H3478","of Israel",232,241]]},"20:14":{"text":"But the children of Benjamin gathered themselves together out of the cities unto Gibeah, to go out to battle against the children of Israel.","words":[["H1121","But the children",0,16],["H1144","of Benjamin",17,28],["H0622","gathered themselves together",29,57],["H5892","out of the cities",58,75],["H1390","unto Gibeah",76,87],["H3318","to go out",89,98],["H4421","to battle",99,108],["H1121","against the children",109,129],["H3478","of Israel",130,139]]},"20:15":{"text":"And the children of Benjamin were numbered at that time out of the cities twenty and six thousand men that drew sword, beside the inhabitants of Gibeah, which were numbered seven hundred chosen men.","words":[["H1121","And the children",0,16],["H1144","of Benjamin",17,28],["H6485","were numbered",29,42],["H3117","at that time",43,55],["H5892","out of the cities",56,73],["H6242","twenty",74,80],["H8337","and six",81,88],["H0505","thousand",89,97],["H0376","men",98,101],["H8025","that drew",102,111],["H2719","sword",112,117],["H3427","beside the inhabitants",119,141],["H1390","of Gibeah",142,151],["H6485","which were numbered",153,172],["H7651","seven",173,178],["H3967","hundred",179,186],["H0977","chosen",187,193],["H0376","men",194,197]]},"20:16":{"text":"Among all this people there were seven hundred chosen men lefthanded; every one could sling stones at an hair breadth, and not miss.","words":[["H5971","Among all this people",0,21],["H7651","there were seven",22,38],["H3967","hundred",39,46],["H0977","chosen",47,53],["H0376","men",54,57],["H0334","lefthanded",58,68],["H3027","lefthanded",58,68],["H3225","lefthanded",58,68],["H7049","every one could sling",70,91],["H0068","stones",92,98],["H8185","at an hair",99,109],["H2398","breadth, and not miss",110,131]]},"20:17":{"text":"And the men of Israel, beside Benjamin, were numbered four hundred thousand men that drew sword: all these were men of war.","words":[["H0376","And the men",0,11],["H3478","of Israel",12,21],["H1144","beside Benjamin",23,38],["H6485","were numbered",40,53],["H0702","four",54,58],["H3967","hundred",59,66],["H0505","thousand",67,75],["H0376","men",76,79],["H8025","that drew",80,89],["H2719","sword",90,95],["H0376","all these were men",97,115],["H4421","of war",116,122]]},"20:18":{"text":"And the children of Israel arose, and went up to the house of God, and asked counsel of God, and said, Which of us shall go up first to the battle against the children of Benjamin? And the LORD said, Judah shall go up first.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6965","arose",27,32],["H5927","and went up",34,45],["H1004","to the house",46,58],["H0430","of God",59,65],["H1008","of God",59,65],["H7592","and asked",67,76],["H0430","counsel of God",77,91],["H0559","and said",93,101],["H4310","Which",103,108],["H5927","of us shall go up",109,126],["H8462","first",127,132],["H4421","to the battle",133,146],["H1121","against the children",147,167],["H1144","of Benjamin",168,179],["H3068","And the LORD",181,193],["H0559","said",194,198],["H3063","Judah",200,205],["H8462","shall go up first",206,223]]},"20:19":{"text":"And the children of Israel rose up in the morning, and encamped against Gibeah.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H6965","rose up",27,34],["H1242","in the morning",35,49],["H2583","and encamped",51,63],["H1390","against Gibeah",64,78]]},"20:20":{"text":"And the men of Israel went out to battle against Benjamin; and the men of Israel put themselves in array to fight against them at Gibeah.","words":[["H0376","And the men",0,11],["H3478","of Israel",12,21],["H3318","went out",22,30],["H4421","to battle",31,40],["H1144","against Benjamin",41,57],["H0376","and the men",59,70],["H3478","of Israel",71,80],["H6186","put themselves in array",81,104],["H4421","to fight",105,113],["H1390","against them at Gibeah",114,136]]},"20:21":{"text":"And the children of Benjamin came forth out of Gibeah, and destroyed down to the ground of the Israelites that day twenty and two thousand men.","words":[["H1121","And the children",0,16],["H1144","of Benjamin",17,28],["H3318","came forth",29,39],["H1390","out of Gibeah",40,53],["H7843","and destroyed down",55,73],["H0776","to the ground",74,87],["H3478","of the Israelites",88,105],["H3117","that day",106,114],["H6242","twenty",115,121],["H8147","and two",122,129],["H0505","thousand",130,138],["H0376","men",139,142]]},"20:22":{"text":"And the people the men of Israel encouraged themselves, and set their battle again in array in the place where they put themselves in array the first day.","words":[["H5971","And the people",0,14],["H0376","the men",15,22],["H3478","of Israel",23,32],["H2388","encouraged",33,43],["H4421","themselves, and set their battle",44,76],["H3254","again",77,82],["H6186","in array",83,91],["H4725","in the place",92,104],["H6186","where they put themselves in array",105,139],["H7223","the first",140,149],["H3117","day",150,153]]},"20:23":{"text":"(And the children of Israel went up and wept before the LORD until even, and asked counsel of the LORD, saying, Shall I go up again to battle against the children of Benjamin my brother? And the LORD said, Go up against him.)","words":[["H1121","(And the children",0,17],["H3478","of Israel",18,27],["H5927","went up",28,35],["H1058","and wept",36,44],["H6440","before",45,51],["H3068","the LORD",52,60],["H6153","until even",61,71],["H7592","and asked",73,82],["H3068","counsel of the LORD",83,102],["H0559","saying",104,110],["H5066","Shall I go up",112,125],["H3254","again",126,131],["H4421","to battle",132,141],["H1121","against the children",142,162],["H1144","of Benjamin",163,174],["H0251","my brother",175,185],["H3068","And the LORD",187,199],["H0559","said",200,204],["H5927","Go up",206,211]]},"20:24":{"text":"And the children of Israel came near against the children of Benjamin the second day.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H7126","came near",27,36],["H1121","against the children",37,57],["H1144","of Benjamin",58,69],["H8145","the second",70,80],["H3117","day",81,84]]},"20:25":{"text":"And Benjamin went forth against them out of Gibeah the second day, and destroyed down to the ground of the children of Israel again eighteen thousand men; all these drew the sword.","words":[["H1144","And Benjamin",0,12],["H3318","went forth",13,23],["H7125","against",24,31],["H1390","them out of Gibeah",32,50],["H8145","the second",51,61],["H3117","day",62,65],["H7843","and destroyed down",67,85],["H0776","to the ground",86,99],["H1121","of the children",100,115],["H3478","of Israel",116,125],["H8083","again eighteen",126,140],["H6240","again eighteen",126,140],["H0505","thousand",141,149],["H0376","men",150,153],["H8025","all these drew",155,169],["H2719","the sword",170,179]]},"20:26":{"text":"Then all the children of Israel, and all the people, went up, and came unto the house of God, and wept, and sat there before the LORD, and fasted that day until even, and offered burnt offerings and peace offerings before the LORD.","words":[["H1121","Then all the children",0,21],["H3478","of Israel",22,31],["H5971","and all the people",33,51],["H5927","went up",53,60],["H0935","and came",62,70],["H1004","unto the house",71,85],["H0430","of God",86,92],["H1008","of God",86,92],["H1058","and wept",94,102],["H3427","and sat",104,111],["H6440","there before",112,124],["H3068","the LORD",125,133],["H6684","and fasted",135,145],["H3117","that day",146,154],["H6153","until even",155,165],["H5927","and offered",167,178],["H5930","burnt offerings",179,194],["H8002","and peace offerings",195,214],["H6440","before",215,221],["H3068","the LORD",222,230]]},"20:27":{"text":"And the children of Israel enquired of the LORD, (for the ark of the covenant of God was there in those days,","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H7592","enquired",27,35],["H3068","of the LORD",36,47],["H0727","(for the ark",49,61],["H1285","of the covenant",62,77],["H0430","of God",78,84],["H3117","was there in those days",85,108]]},"20:28":{"text":"And Phinehas, the son of Eleazar, the son of Aaron, stood before it in those days,) saying, Shall I yet again go out to battle against the children of Benjamin my brother, or shall I cease? And the LORD said, Go up; for to morrow I will deliver them into thine hand.","words":[["H6372","And Phinehas",0,12],["H1121","the son",14,21],["H0499","of Eleazar",22,32],["H1121","the son",34,41],["H0175","of Aaron",42,50],["H5975","stood",52,57],["H6440","before",58,64],["H3117","it in those days",65,81],["H0559",") saying",82,90],["H3254","Shall I yet again",92,109],["H3318","go out",110,116],["H4421","to battle",117,126],["H1121","against the children",127,147],["H1144","of Benjamin",148,159],["H0251","my brother",160,170],["H2308","or shall I cease",172,188],["H3068","And the LORD",190,202],["H0559","said",203,207],["H5927","Go up",209,214],["H4279","for to morrow",216,229],["H5414","I will deliver",230,244],["H3027","them into thine hand",245,265]]},"20:29":{"text":"And Israel set liers in wait round about Gibeah.","words":[["H3478","And Israel",0,10],["H7760","set",11,14],["H0693","liers in wait",15,28],["H5439","round about",29,40],["H1390","Gibeah",41,47]]},"20:30":{"text":"And the children of Israel went up against the children of Benjamin on the third day, and put themselves in array against Gibeah, as at other times.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H5927","went up",27,34],["H1121","against the children",35,55],["H1144","of Benjamin",56,67],["H7992","on the third",68,80],["H3117","day",81,84],["H6186","and put themselves in array",86,113],["H1390","against Gibeah",114,128],["H6471","as at other times",130,147]]},"20:31":{"text":"And the children of Benjamin went out against the people, and were drawn away from the city; and they began to smite of the people, and kill, as at other times, in the highways, of which one goeth up to the house of God, and the other to Gibeah in the field, about thirty men of Israel.","words":[["H1121","And the children",0,16],["H1144","of Benjamin",17,28],["H3318","went out",29,37],["H7125","against",38,45],["H5971","the people",46,56],["H5423","and were drawn away",58,77],["H5892","from the city",78,91],["H2490","and they began",93,107],["H5221","to smite",108,116],["H5971","of the people",117,130],["H2491","and kill",132,140],["H6471","as at other times",142,159],["H4546","in the highways",161,176],["H0259","of which one",178,190],["H5927","goeth up",191,199],["H1004","to the house",200,212],["H0430","of God",213,219],["H1008","of God",213,219],["H0259","and the other",221,234],["H1390","to Gibeah",235,244],["H7704","in the field",245,257],["H7970","about thirty",259,271],["H0376","men",272,275],["H3478","of Israel",276,285]]},"20:32":{"text":"And the children of Benjamin said, They are smitten down before us, as at the first. But the children of Israel said, Let us flee, and draw them from the city unto the highways.","words":[["H1121","And the children",0,16],["H1144","of Benjamin",17,28],["H0559","said",29,33],["H5062","They are smitten down",35,56],["H6440","before",57,63],["H7223","us, as at the first",64,83],["H1121","But the children",85,101],["H3478","of Israel",102,111],["H0559","said",112,116],["H5127","Let us flee",118,129],["H5423","and draw",131,139],["H5892","them from the city",140,158],["H4546","unto the highways",159,176]]},"20:33":{"text":"And all the men of Israel rose up out of their place, and put themselves in array at Baaltamar: and the liers in wait of Israel came forth out of their places, even out of the meadows of Gibeah.","words":[["H0376","And all the men",0,15],["H3478","of Israel",16,25],["H6965","rose up",26,33],["H4725","out of their place",34,52],["H6186","and put themselves in array",54,81],["H1193","at Baaltamar",82,94],["H0693","and the liers in wait",96,117],["H3478","of Israel",118,127],["H1518","came forth",128,138],["H4725","out of their places",139,158],["H4629","even out of the meadows",160,183],["H1387","of Gibeah",184,193]]},"20:34":{"text":"And there came against Gibeah ten thousand chosen men out of all Israel, and the battle was sore: but they knew not that evil was near them.","words":[["H0935","And there came",0,14],["H5048","against",15,22],["H1390","Gibeah",23,29],["H6235","ten",30,33],["H0505","thousand",34,42],["H0977","chosen",43,49],["H0376","men",50,53],["H3478","out of all Israel",54,71],["H4421","and the battle",73,87],["H3513","was sore",88,96],["H3045","but they knew",98,111],["H7451","not that evil",112,125],["H5060","was near",126,134]]},"20:35":{"text":"And the LORD smote Benjamin before Israel: and the children of Israel destroyed of the Benjamites that day twenty and five thousand and an hundred men: all these drew the sword.","words":[["H3068","And the LORD",0,12],["H5062","smote",13,18],["H1144","Benjamin",19,27],["H6440","before",28,34],["H3478","Israel",35,41],["H1121","and the children",43,59],["H3478","of Israel",60,69],["H7843","destroyed",70,79],["H1145","of the Benjamites",80,97],["H3117","that day",98,106],["H6242","twenty",107,113],["H2568","and five",114,122],["H0505","thousand",123,131],["H3967","and an hundred",132,146],["H0376","men",147,150],["H8025","all these drew",152,166],["H2719","the sword",167,176]]},"20:36":{"text":"So the children of Benjamin saw that they were smitten: for the men of Israel gave place to the Benjamites, because they trusted unto the liers in wait which they had set beside Gibeah.","words":[["H1121","So the children",0,15],["H1144","of Benjamin",16,27],["H7200","saw",28,31],["H5062","that they were smitten",32,54],["H0376","for the men",56,67],["H3478","of Israel",68,77],["H5414","gave",78,82],["H4725","place",83,88],["H1145","to the Benjamites",89,106],["H0982","because they trusted",108,128],["H0693","unto the liers in wait",129,151],["H7760","which they had set",152,170],["H1390","beside Gibeah",171,184]]},"20:37":{"text":"And the liers in wait hasted, and rushed upon Gibeah; and the liers in wait drew themselves along, and smote all the city with the edge of the sword.","words":[["H0693","And the liers in wait",0,21],["H2363","hasted",22,28],["H6584","and rushed",30,40],["H1390","upon Gibeah",41,52],["H0693","and the liers in wait",54,75],["H4900","drew themselves along",76,97],["H5221","and smote",99,108],["H5892","all the city",109,121],["H6310","with the edge",122,135],["H2719","of the sword",136,148]]},"20:38":{"text":"Now there was an appointed sign between the men of Israel and the liers in wait, that they should make a great flame with smoke rise up out of the city.","words":[["H4150","Now there was an appointed sign",0,31],["H0376","between the men",32,47],["H3478","of Israel",48,57],["H5973","and",58,61],["H0693","the liers in wait",62,79],["H7235","that they should make a great",81,110],["H4864","flame",111,116],["H6227","with smoke",117,127],["H5927","rise up",128,135],["H5892","out of the city",136,151]]},"20:39":{"text":"And when the men of Israel retired in the battle, Benjamin began to smite and kill of the men of Israel about thirty persons: for they said, Surely they are smitten down before us, as in the first battle.","words":[["H0376","And when the men",0,16],["H3478","of Israel",17,26],["H2015","retired",27,34],["H4421","in the battle",35,48],["H1144","Benjamin",50,58],["H2490","began",59,64],["H5221","to smite",65,73],["H2491","and kill",74,82],["H0376","of the men",83,93],["H3478","of Israel",94,103],["H7970","about thirty",104,116],["H0376","persons",117,124],["H0559","for they said",126,139],["H5062","Surely",141,147],["H5062","they are smitten down",148,169],["H6440","before",170,176],["H7223","us, as in the first",177,196],["H4421","battle",197,203]]},"20:40":{"text":"But when the flame began to arise up out of the city with a pillar of smoke, the Benjamites looked behind them, and, behold, the flame of the city ascended up to heaven.","words":[["H4864","But when the flame",0,18],["H2490","began",19,24],["H5927","to arise up",25,36],["H5892","out of the city",37,52],["H5982","with a pillar",53,66],["H6227","of smoke",67,75],["H1145","the Benjamites",77,91],["H6437","looked",92,98],["H0310","behind",99,105],["H3632","them, and, behold, the flame",106,134],["H5892","of the city",135,146],["H5927","ascended up",147,158],["H8064","to heaven",159,168]]},"20:41":{"text":"And when the men of Israel turned again, the men of Benjamin were amazed: for they saw that evil was come upon them.","words":[["H0376","And when the men",0,16],["H3478","of Israel",17,26],["H2015","turned again",27,39],["H0376","the men",41,48],["H1144","of Benjamin",49,60],["H0926","were amazed",61,72],["H7200","for they saw",74,86],["H7451","that evil",87,96],["H5060","was come",97,105]]},"20:42":{"text":"Therefore they turned their backs before the men of Israel unto the way of the wilderness; but the battle overtook them; and them which came out of the cities they destroyed in the midst of them.","words":[["H6437","Therefore they turned",0,21],["H6440","their backs before",22,40],["H0376","the men",41,48],["H3478","of Israel",49,58],["H1870","unto the way",59,71],["H4057","of the wilderness",72,89],["H4421","but the battle",91,105],["H1692","overtook",106,114],["H5892","them; and them which came out of the cities",115,158],["H7843","they destroyed",159,173],["H8432","in the midst",174,186]]},"20:43":{"text":"Thus they inclosed the Benjamites round about, and chased them, and trode them down with ease over against Gibeah toward the sunrising.","words":[["H3803","Thus they inclosed",0,18],["H1145","the Benjamites",19,33],["H3803","round about",34,45],["H7291","and chased",47,57],["H1869","them, and trode them down",58,83],["H4496","with ease",84,93],["H5227","over against",94,106],["H1390","Gibeah",107,113],["H4217","toward the sunrising",114,134],["H8121","toward the sunrising",114,134]]},"20:44":{"text":"And there fell of Benjamin eighteen thousand men; all these were men of valour.","words":[["H5307","And there fell",0,14],["H1144","of Benjamin",15,26],["H8083","eighteen",27,35],["H6240","eighteen",27,35],["H0505","thousand",36,44],["H0376","men",45,48],["H0582","all these were men",50,68],["H2428","of valour",69,78]]},"20:45":{"text":"And they turned and fled toward the wilderness unto the rock of Rimmon: and they gleaned of them in the highways five thousand men; and pursued hard after them unto Gidom, and slew two thousand men of them.","words":[["H6437","And they turned",0,15],["H5127","and fled",16,24],["H4057","toward the wilderness",25,46],["H5553","unto the rock",47,60],["H7417","of Rimmon",61,70],["H5953","and they gleaned",72,88],["H4546","of them in the highways",89,112],["H2568","five",113,117],["H0505","thousand",118,126],["H0376","men",127,130],["H1692","and pursued",132,143],["H0310","hard after",144,154],["H1440","them unto Gidom",155,170],["H5221","and slew",172,180],["H0505","two thousand",181,193],["H0376","men",194,197]]},"20:46":{"text":"So that all which fell that day of Benjamin were twenty and five thousand men that drew the sword; all these were men of valour.","words":[["H5307","So that all which fell",0,22],["H3117","that day",23,31],["H1144","of Benjamin",32,43],["H6242","were twenty",44,55],["H2568","and five",56,64],["H0505","thousand",65,73],["H0376","men",74,77],["H8025","that drew",78,87],["H2719","the sword",88,97],["H0582","all these were men",99,117],["H2428","of valour",118,127]]},"20:47":{"text":"But six hundred men turned and fled to the wilderness unto the rock Rimmon, and abode in the rock Rimmon four months.","words":[["H8337","But six",0,7],["H3967","hundred",8,15],["H0376","men",16,19],["H6437","turned",20,26],["H5127","and fled",27,35],["H4057","to the wilderness",36,53],["H5553","unto the rock",54,67],["H7417","Rimmon",68,74],["H3427","and abode",76,85],["H5553","in the rock",86,97],["H7417","Rimmon",98,104],["H0702","four",105,109],["H2320","months",110,116]]},"20:48":{"text":"And the men of Israel turned again upon the children of Benjamin, and smote them with the edge of the sword, as well the men of every city, as the beast, and all that came to hand: also they set on fire all the cities that they came to.","words":[["H0376","And the men",0,11],["H3478","of Israel",12,21],["H7725","turned again",22,34],["H1121","upon the children",35,52],["H1144","of Benjamin",53,64],["H5221","and smote",66,75],["H6310","them with the edge",76,94],["H2719","of the sword",95,107],["H4974","as well the men",109,124],["H5892","of every city",125,138],["H5704","as",140,142],["H0929","the beast",143,152],["H4672","and all that came to hand",154,179],["H7971","also they set",181,194],["H0784","on fire",195,202],["H5892","all the cities",203,217],["H4672","that they came to",218,235]]},"21:1":{"text":"Now the men of Israel had sworn in Mizpeh, saying, There shall not any of us give his daughter unto Benjamin to wife.","words":[["H0376","Now the men",0,11],["H3478","of Israel",12,21],["H7650","had sworn",22,31],["H4709","in Mizpeh",32,41],["H0559","saying",43,49],["H0376","There shall not any",51,70],["H5414","of us give",71,81],["H1323","his daughter",82,94],["H1144","unto Benjamin",95,108],["H0802","to wife",109,116]]},"21:2":{"text":"And the people came to the house of God, and abode there till even before God, and lifted up their voices, and wept sore;","words":[["H5971","And the people",0,14],["H0935","came",15,19],["H1004","to the house",20,32],["H0430","of God",33,39],["H1008","of God",33,39],["H3427","and abode",41,50],["H6153","there till even",51,66],["H6440","before",67,73],["H0430","God",74,77],["H5375","and lifted up",79,92],["H6963","their voices",93,105],["H1058","and wept",107,115],["H1065","and wept",107,115],["H1419","sore",116,120]]},"21:3":{"text":"And said, O LORD God of Israel, why is this come to pass in Israel, that there should be to day one tribe lacking in Israel?","words":[["H0559","And said",0,8],["H3068","O LORD",10,16],["H0430","God",17,20],["H3478","of Israel",21,30],["H3478","why is this come to pass in Israel",32,66],["H3117","that there should be to day",68,95],["H0259","one",96,99],["H7626","tribe",100,105],["H6485","lacking",106,113],["H3478","in Israel",114,123]]},"21:4":{"text":"And it came to pass on the morrow, that the people rose early, and built there an altar, and offered burnt offerings and peace offerings.","words":[["H4283","And it came to pass on the morrow",0,33],["H5971","that the people",35,50],["H7925","rose early",51,61],["H1129","and built",63,72],["H4196","there an altar",73,87],["H5927","and offered",89,100],["H5930","burnt offerings",101,116],["H8002","and peace offerings",117,136]]},"21:5":{"text":"And the children of Israel said, Who is there among all the tribes of Israel that came not up with the congregation unto the LORD? For they had made a great oath concerning him that came not up to the LORD to Mizpeh, saying, He shall surely be put to death.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H0559","said",27,31],["H7626","Who is there among all the tribes",33,66],["H3478","of Israel",67,76],["H0834","that",77,81],["H5927","came",82,86],["H6951","not up with the congregation",87,115],["H3068","unto the LORD",116,129],["H1419","For they had made a great",131,156],["H7621","oath",157,161],["H5927","concerning him that came not up",162,193],["H3068","to the LORD",194,205],["H4709","to Mizpeh",206,215],["H0559","saying",217,223],["H4191","He shall surely",225,240],["H4191","be put to death",241,256]]},"21:6":{"text":"And the children of Israel repented them for Benjamin their brother, and said, There is one tribe cut off from Israel this day.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H5162","repented",27,35],["H1144","them for Benjamin",36,53],["H0251","their brother",54,67],["H0559","and said",69,77],["H0259","There is one",79,91],["H7626","tribe",92,97],["H1438","cut off",98,105],["H3478","from Israel",106,117],["H3117","this day",118,126]]},"21:7":{"text":"How shall we do for wives for them that remain, seeing we have sworn by the LORD that we will not give them of our daughters to wives?","words":[["H6213","How shall we do",0,15],["H0802","for wives",16,25],["H3498","for them that remain",26,46],["H7650","seeing we have sworn",48,68],["H3068","by the LORD",69,80],["H5414","that we will not give",81,102],["H1323","them of our daughters",103,124],["H0802","to wives",125,133]]},"21:8":{"text":"And they said, What one is there of the tribes of Israel that came not up to Mizpeh to the LORD? And, behold, there came none to the camp from Jabeshgilead to the assembly.","words":[["H0559","And they said",0,13],["H0259","What one",15,23],["H7626","is there of the tribes",24,46],["H3478","of Israel",47,56],["H5927","that came not up",57,73],["H4709","to Mizpeh",74,83],["H3068","to the LORD",84,95],["H0935","And, behold, there came",97,120],["H0376","none",121,125],["H4264","to the camp",126,137],["H3003","from Jabeshgilead",138,155],["H1568","from Jabeshgilead",138,155],["H6951","to the assembly",156,171]]},"21:9":{"text":"For the people were numbered, and, behold, there were none of the inhabitants of Jabeshgilead there.","words":[["H5971","For the people",0,14],["H6485","were numbered",15,28],["H0376","and, behold, there were none",30,58],["H3427","of the inhabitants",59,77],["H3003","of Jabeshgilead",78,93],["H1568","of Jabeshgilead",78,93]]},"21:10":{"text":"And the congregation sent thither twelve thousand men of the valiantest, and commanded them, saying, Go and smite the inhabitants of Jabeshgilead with the edge of the sword, with the women and the children.","words":[["H5712","And the congregation",0,20],["H7971","sent",21,25],["H8147","thither twelve",26,40],["H6240","thither twelve",26,40],["H0505","thousand",41,49],["H0376","men",50,53],["H1121","of the valiantest",54,71],["H2428","of the valiantest",54,71],["H6680","and commanded",73,86],["H0559","them, saying",87,99],["H3212","Go",101,103],["H5221","and smite",104,113],["H3427","the inhabitants",114,129],["H3003","of Jabeshgilead",130,145],["H1568","of Jabeshgilead",130,145],["H6310","with the edge",146,159],["H2719","of the sword",160,172],["H0802","with the women",174,188],["H2945","and the children",189,205]]},"21:11":{"text":"And this is the thing that ye shall do, Ye shall utterly destroy every male, and every woman that hath lain by man.","words":[["H1697","And this is the thing",0,21],["H6213","that ye shall do",22,38],["H2763","Ye shall utterly destroy",40,64],["H2145","every male",65,75],["H0802","and every woman",77,92],["H4904","that hath lain",93,107],["H3045","by man",108,114]]},"21:12":{"text":"And they found among the inhabitants of Jabeshgilead four hundred young virgins, that had known no man by lying with any male: and they brought them unto the camp to Shiloh, which is in the land of Canaan.","words":[["H4672","And they found",0,14],["H3427","among the inhabitants",15,36],["H3003","of Jabeshgilead",37,52],["H1568","of Jabeshgilead",37,52],["H0702","four",53,57],["H3967","hundred",58,65],["H5291","young",66,71],["H1330","virgins",72,79],["H3045","that had known",81,95],["H0376","no man",96,102],["H4904","by lying",103,111],["H2145","with any male",112,125],["H0935","and they brought",127,143],["H4264","them unto the camp",144,162],["H7887","to Shiloh",163,172],["H0776","which is in the land",174,194],["H3667","of Canaan",195,204]]},"21:13":{"text":"And the whole congregation sent some to speak to the children of Benjamin that were in the rock Rimmon, and to call peaceably unto them.","words":[["H5712","And the whole congregation",0,26],["H7971","sent",27,31],["H1696","some to speak",32,45],["H1121","to the children",46,61],["H1144","of Benjamin",62,73],["H5553","that were in the rock",74,95],["H7417","Rimmon",96,102],["H7121","and to call",104,115],["H7965","peaceably",116,125]]},"21:14":{"text":"And Benjamin came again at that time; and they gave them wives which they had saved alive of the women of Jabeshgilead: and yet so they sufficed them not.","words":[["H1144","And Benjamin",0,12],["H7725","came again",13,23],["H6256","at that time",24,36],["H5414","and they gave",38,51],["H0802","them wives",52,62],["H2421","which they had saved alive",63,89],["H0802","of the women",90,102],["H3003","of Jabeshgilead",103,118],["H1568","of Jabeshgilead",103,118],["H4672","and yet so they sufficed",120,144]]},"21:15":{"text":"And the people repented them for Benjamin, because that the LORD had made a breach in the tribes of Israel.","words":[["H5971","And the people",0,14],["H5162","repented",15,23],["H1144","them for Benjamin",24,41],["H3068","because that the LORD",43,64],["H6213","had made",65,73],["H6556","a breach",74,82],["H7626","in the tribes",83,96],["H3478","of Israel",97,106]]},"21:16":{"text":"Then the elders of the congregation said, How shall we do for wives for them that remain, seeing the women are destroyed out of Benjamin?","words":[["H2205","Then the elders",0,15],["H5712","of the congregation",16,35],["H0559","said",36,40],["H6213","How shall we do",42,57],["H0802","for wives",58,67],["H3498","for them that remain",68,88],["H0802","seeing the women",90,106],["H8045","are destroyed",107,120],["H1144","out of Benjamin",121,136]]},"21:17":{"text":"And they said, There must be an inheritance for them that be escaped of Benjamin, that a tribe be not destroyed out of Israel.","words":[["H0559","And they said",0,13],["H3425","There must be an inheritance",15,43],["H6413","for them that be escaped",44,68],["H1144","of Benjamin",69,80],["H7626","that a tribe",82,94],["H4229","be not destroyed",95,111],["H3478","out of Israel",112,125]]},"21:18":{"text":"Howbeit we may not give them wives of our daughters: for the children of Israel have sworn, saying, Cursed be he that giveth a wife to Benjamin.","words":[["H3201","Howbeit we may",0,14],["H5414","not give",15,23],["H0802","them wives",24,34],["H1323","of our daughters",35,51],["H1121","for the children",53,69],["H3478","of Israel",70,79],["H7650","have sworn",80,90],["H0559","saying",92,98],["H0779","Cursed",100,106],["H5414","be he that giveth",107,124],["H0802","a wife",125,131],["H1144","to Benjamin",132,143]]},"21:19":{"text":"Then they said, Behold, there is a feast of the LORD in Shiloh yearly in a place which is on the north side of Bethel, on the east side of the highway that goeth up from Bethel to Shechem, and on the south of Lebonah.","words":[["H0559","Then they said",0,14],["H2282","Behold, there is a feast",16,40],["H3068","of the LORD",41,52],["H7887","in Shiloh",53,62],["H3117","yearly",63,69],["H3117","yearly",63,69],["H6828","in a place which is on the north side",70,107],["H1008","of Bethel",108,117],["H4217","on the east side",119,135],["H8121","on the east side",119,135],["H4546","of the highway",136,150],["H5927","that goeth up",151,164],["H1008","from Bethel",165,176],["H7927","to Shechem",177,187],["H5045","and on the south",189,205],["H3829","of Lebonah",206,216]]},"21:20":{"text":"Therefore they commanded the children of Benjamin, saying, Go and lie in wait in the vineyards;","words":[["H6680","Therefore they commanded",0,24],["H1121","the children",25,37],["H1144","of Benjamin",38,49],["H0559","saying",51,57],["H3212","Go",59,61],["H0693","and lie in wait",62,77],["H3754","in the vineyards",78,94]]},"21:21":{"text":"And see, and, behold, if the daughters of Shiloh come out to dance in dances, then come ye out of the vineyards, and catch you every man his wife of the daughters of Shiloh, and go to the land of Benjamin.","words":[["H7200","And see",0,7],["H1323","and, behold, if the daughters",9,38],["H7887","of Shiloh",39,48],["H3318","come out",49,57],["H2342","to dance",58,66],["H4246","in dances",67,76],["H3318","then come ye out",78,94],["H3754","of the vineyards",95,111],["H2414","and catch",113,122],["H0376","you every man",123,136],["H0802","his wife",137,145],["H1323","of the daughters",146,162],["H7887","of Shiloh",163,172],["H1980","and go",174,180],["H0776","to the land",181,192],["H1144","of Benjamin",193,204]]},"21:22":{"text":"And it shall be, when their fathers or their brethren come unto us to complain, that we will say unto them, Be favourable unto them for our sakes: because we reserved not to each man his wife in the war: for ye did not give unto them at this time, that ye should be guilty.","words":[["H0001","And it shall be, when their fathers",0,35],["H0251","or their brethren",36,53],["H0935","come",54,58],["H7378","unto us to complain",59,78],["H0559","that we will say",80,96],["H2603","unto them, Be favourable",97,121],["H3947","unto them for our sakes: because we reserved",122,166],["H0376","not to each man",167,182],["H0802","his wife",183,191],["H4421","in the war",192,202],["H5414","for ye did not give",204,223],["H6256","unto them at this time",224,246],["H0816","that ye should be guilty",248,272]]},"21:23":{"text":"And the children of Benjamin did so, and took them wives, according to their number, of them that danced, whom they caught: and they went and returned unto their inheritance, and repaired the cities, and dwelt in them.","words":[["H1121","And the children",0,16],["H1144","of Benjamin",17,28],["H6213","did so",29,35],["H5375","and took",37,45],["H0802","them wives",46,56],["H4557","according to their number",58,83],["H2342","of them that danced",85,104],["H1497","whom they caught",106,122],["H3212","and they went",124,137],["H7725","and returned",138,150],["H5159","unto their inheritance",151,173],["H1129","and repaired",175,187],["H5892","the cities",188,198],["H3427","and dwelt",200,209]]},"21:24":{"text":"And the children of Israel departed thence at that time, every man to his tribe and to his family, and they went out from thence every man to his inheritance.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H1980","departed",27,35],["H6256","thence at that time",36,55],["H0376","every man",57,66],["H7626","to his tribe",67,79],["H4940","and to his family",80,97],["H3318","and they went out",99,116],["H0376","from thence every man",117,138],["H5159","to his inheritance",139,157]]},"21:25":{"text":"In those days there was no king in Israel: every man did that which was right in his own eyes.","words":[["H3117","In those days",0,13],["H4428","there was no king",14,31],["H3478","in Israel",32,41],["H0376","every man",43,52],["H6213","did",53,56],["H3477","that which was right",57,77],["H5869","in his own eyes",78,93]]}}};
